import { useEffect, useState } from 'react';
import { BrowserRouter, Routes, Route, Navigate, useNavigate, useLocation } from 'react-router-dom';
import { QueryClientProvider } from '@tanstack/react-query';
import { Toaster } from 'react-hot-toast';
import { queryClient } from './lib/queryClient';
import { useAuthStore } from './stores/authStore';
import { useRealtime } from './hooks/useRealtime';
import { useOnlineStatus } from './hooks/useOnlineStatus';
import { ErrorBoundary } from './components/ErrorBoundary';
import { SplashScreen } from './components/SplashScreen';
import { Login } from './views/Login';
import { AppShell } from './components/AppShell';

// Views
import { DashboardPage } from './views/DashboardPage';
import { DevicesPage } from './views/DevicesPage';
import { AlertsPage } from './views/AlertsPage';
import { AIAssistantPage } from './views/AIAssistantPage';
import { MapView } from './views/MapView';
import { Topology } from './views/Topology';
import { Groups } from './views/Groups';
import { Automation } from './views/Automation';
import { Templates } from './views/Templates';
import { Policies } from './views/Policies';
import { RemoteControl } from './views/RemoteControl';
import { Terminal } from './views/Terminal';
import { FileManager } from './views/FileManager';
import { TaskManager } from './views/TaskManager';
import { Jobs } from './views/Jobs';
import { JobsPage } from './views/JobsPage';
import { Schedules } from './views/Schedules';
import { Monitoring } from './views/Monitoring';
import { Logs } from './views/Logs';
import { Reports } from './views/Reports';
import { AIInsights } from './views/AIInsights';
import { Tenants } from './views/Tenants';
import { Users } from './views/Users';
import { RolesPermissions } from './views/RolesPermissions';
import { AuditLogs } from './views/AuditLogs';
import { AuditLogsPage } from './views/AuditLogsPage';
import { AdminPanel } from './views/AdminPanel';
import { Settings } from './views/Settings';

function ProtectedRoutes() {
  const { isAuthenticated, checkAuth } = useAuthStore();
  const { connected } = useRealtime();
  useOnlineStatus();
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => { checkAuth(); }, [checkAuth]);

  useEffect(() => {
    if (!isAuthenticated && location.pathname !== '/login') {
      navigate('/login');
    }
  }, [isAuthenticated, location.pathname, navigate]);

  if (!isAuthenticated) return <Navigate to="/login" />;

  return (
    <AppShell>
      <Routes>
        <Route path="/" element={<DashboardPage />} />
        <Route path="/dashboard" element={<DashboardPage />} />
        <Route path="/devices" element={<DevicesPage />} />
        <Route path="/map-view" element={<MapView />} />
        <Route path="/topology" element={<Topology />} />
        <Route path="/groups" element={<Groups />} />
        <Route path="/automation" element={<Automation />} />
        <Route path="/templates" element={<Templates />} />
        <Route path="/policies" element={<Policies />} />
        <Route path="/remote-control" element={<RemoteControl />} />
        <Route path="/terminal" element={<Terminal />} />
        <Route path="/file-manager" element={<FileManager />} />
        <Route path="/task-manager" element={<TaskManager />} />
        <Route path="/jobs" element={<JobsPage />} />
        <Route path="/schedules" element={<Schedules />} />
        <Route path="/monitoring" element={<Monitoring />} />
        <Route path="/logs" element={<Logs />} />
        <Route path="/alerts" element={<AlertsPage />} />
        <Route path="/reports" element={<Reports />} />
        <Route path="/ai-insights" element={<AIAssistantPage />} />
        <Route path="/tenants" element={<Tenants />} />
        <Route path="/users" element={<Users />} />
        <Route path="/roles" element={<RolesPermissions />} />
        <Route path="/audit-logs" element={<AuditLogsPage />} />
        <Route path="/admin" element={<AdminPanel />} />
        <Route path="/settings" element={<Settings />} />
        <Route path="*" element={<Navigate to="/dashboard" />} />
      </Routes>
    </AppShell>
  );
}

export function App() {
  const [showSplash, setShowSplash] = useState(true);

  if (showSplash) {
    return <SplashScreen onFinish={() => setShowSplash(false)} />;
  }

  return (
    <ErrorBoundary>
      <QueryClientProvider client={queryClient}>
        <BrowserRouter>
          <Toaster position="top-right" toastOptions={{ duration: 3000 }} />
          <Routes>
            <Route path="/login" element={<Login />} />
            <Route path="/*" element={<ProtectedRoutes />} />
          </Routes>
        </BrowserRouter>
      </QueryClientProvider>
    </ErrorBoundary>
  );
}

import { notify } from './toast';

const API_BASE = '/api/v1';

class ApiClient {
  private token: string | null = null;
  private refreshPromise: Promise<string | null> | null = null;
  private requestCount = 0;

  setToken(token: string | null) {
    this.token = token;
    if (token) {
      localStorage.setItem('auth_token', token);
    } else {
      localStorage.removeItem('auth_token');
    }
  }

  getToken(): string | null {
    if (!this.token) {
      this.token = localStorage.getItem('auth_token');
    }
    return this.token;
  }

  private async request<T>(endpoint: string, options: RequestInit = {}): Promise<T> {
    const token = this.getToken();
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...((options.headers as Record<string, string>) || {}),
    };
    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    this.requestCount++;

    try {
      const response = await fetch(`${API_BASE}${endpoint}`, {
        ...options,
        headers,
      });

      // Handle 401 - try refresh token
      if (response.status === 401) {
        const refreshed = await this.tryRefreshToken();
        if (refreshed) {
          // Retry with new token
          headers['Authorization'] = `Bearer ${refreshed}`;
          const retryResponse = await fetch(`${API_BASE}${endpoint}`, { ...options, headers });
          if (retryResponse.ok) return retryResponse.json();
        }
        // Refresh failed - logout
        this.setToken(null);
        window.dispatchEvent(new CustomEvent('auth:logout'));
        throw new Error('Session expired. Please login again.');
      }

      // Handle 429 - rate limited
      if (response.status === 429) {
        notify.error('Too many requests. Please slow down.');
        throw new Error('Rate limited');
      }

      // Handle 500+ - server error
      if (response.status >= 500) {
        notify.error('Server error. Please try again later.');
        throw new Error(`Server error: ${response.status}`);
      }

      if (!response.ok) {
        const error = await response.json().catch(() => ({ message: 'Request failed' }));
        throw new Error(error.message || `HTTP ${response.status}`);
      }

      return response.json();
    } catch (err: any) {
      // Network error (offline)
      if (err.name === 'TypeError' && err.message.includes('fetch')) {
        throw new Error('Network error. Check your connection.');
      }
      throw err;
    }
  }

  private async tryRefreshToken(): Promise<string | null> {
    // Deduplicate concurrent refresh attempts
    if (this.refreshPromise) return this.refreshPromise;

    this.refreshPromise = (async () => {
      try {
        const response = await fetch(`${API_BASE}/auth/refresh`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ token: this.getToken() }),
        });
        if (response.ok) {
          const data = await response.json();
          this.setToken(data.access_token);
          return data.access_token;
        }
        return null;
      } catch {
        return null;
      } finally {
        this.refreshPromise = null;
      }
    })();

    return this.refreshPromise;
  }

  // ─── Auth ───────────────────────────────────────────────────────────────────

  async login(email: string, password: string) {
    return this.request<{ access_token: string; user: any }>('/auth/login', {
      method: 'POST',
      body: JSON.stringify({ email, password }),
    });
  }

  async register(data: { email: string; username: string; password: string; displayName: string }) {
    return this.request<{ access_token: string; user: any }>('/auth/register', {
      method: 'POST',
      body: JSON.stringify(data),
    });
  }

  async getProfile() {
    return this.request<any>('/auth/me');
  }

  // ─── Dashboard ──────────────────────────────────────────────────────────────

  async getDashboardStats() {
    return this.request<any>('/dashboard/stats');
  }

  // ─── Devices ────────────────────────────────────────────────────────────────

  async getDevices(params?: { status?: string; type?: string; search?: string; page?: number; limit?: number }) {
    const query = new URLSearchParams();
    if (params?.status && params.status !== 'all') query.set('status', params.status);
    if (params?.type && params.type !== 'all') query.set('type', params.type);
    if (params?.search) query.set('search', params.search);
    if (params?.page) query.set('page', params.page.toString());
    if (params?.limit) query.set('limit', params.limit.toString());
    const qs = query.toString();
    return this.request<any>(`/devices${qs ? `?${qs}` : ''}`);
  }

  async getDeviceStats() {
    return this.request<any>('/devices/stats');
  }

  async getDevice(id: string) {
    return this.request<any>(`/devices/${id}`);
  }

  async createDevice(data: any) {
    return this.request<any>('/devices', { method: 'POST', body: JSON.stringify(data) });
  }

  async updateDevice(id: string, data: any) {
    return this.request<any>(`/devices/${id}`, { method: 'PUT', body: JSON.stringify(data) });
  }

  async deleteDevice(id: string) {
    return this.request<any>(`/devices/${id}`, { method: 'DELETE' });
  }

  async bulkDeleteDevices(ids: string[]) {
    return Promise.all(ids.map(id => this.deleteDevice(id)));
  }

  async bulkUpdateDevices(ids: string[], data: any) {
    return Promise.all(ids.map(id => this.updateDevice(id, data)));
  }

  // ─── Alerts ─────────────────────────────────────────────────────────────────

  async getAlerts() {
    return this.request<any[]>('/alerts');
  }

  async getAlertStats() {
    return this.request<any>('/alerts/stats');
  }

  async acknowledgeAlert(id: string) {
    return this.request<any>(`/alerts/${id}/acknowledge`, { method: 'PUT' });
  }

  async resolveAlert(id: string) {
    return this.request<any>(`/alerts/${id}/resolve`, { method: 'PUT' });
  }

  async bulkAcknowledgeAlerts(ids: string[]) {
    return Promise.all(ids.map(id => this.acknowledgeAlert(id)));
  }

  async bulkResolveAlerts(ids: string[]) {
    return Promise.all(ids.map(id => this.resolveAlert(id)));
  }

  // ─── Jobs ───────────────────────────────────────────────────────────────────

  async getJobs() {
    return this.request<any[]>('/jobs');
  }

  async getJobStats() {
    return this.request<any>('/jobs/stats');
  }

  // ─── Users ──────────────────────────────────────────────────────────────────

  async getUsers() {
    return this.request<any[]>('/users');
  }

  async getUserStats() {
    return this.request<any>('/users/stats');
  }

  // ─── Tenants ────────────────────────────────────────────────────────────────

  async getTenants() {
    return this.request<any[]>('/tenants');
  }

  async getTenantStats() {
    return this.request<any>('/tenants/stats');
  }

  // ─── Audit Logs ─────────────────────────────────────────────────────────────

  async getAuditLogs() {
    return this.request<any[]>('/audit-logs');
  }

  async getAuditLogStats() {
    return this.request<any>('/audit-logs/stats');
  }

  // ─── Groups ─────────────────────────────────────────────────────────────────

  async getGroups() {
    return this.request<any[]>('/groups');
  }

  // ─── Health ─────────────────────────────────────────────────────────────────

  async getHealth() {
    return this.request<any>('/health');
  }

  // ─── Telemetry ──────────────────────────────────────────────────────────────

  async getTelemetryLatest() {
    return this.request<any[]>('/telemetry/latest');
  }

  async getTelemetryAggregated() {
    return this.request<any>('/telemetry/aggregated');
  }

  async getTelemetryTimeSeries(minutes = 60) {
    return this.request<any[]>(`/telemetry/timeseries?minutes=${minutes}`);
  }

  async getDeviceTelemetry(deviceId: string, limit = 50) {
    return this.request<any[]>(`/telemetry/device/${deviceId}?limit=${limit}`);
  }

  // ─── AI ─────────────────────────────────────────────────────────────────────

  async aiQuery(query: string) {
    return this.request<any>('/ai/query', { method: 'POST', body: JSON.stringify({ query }) });
  }

  async aiRecommendations() {
    return this.request<any>('/ai/recommendations');
  }

  async aiAnomalies() {
    return this.request<any>('/ai/anomalies');
  }

  async aiPredictions() {
    return this.request<any>('/ai/predictions');
  }

  // ─── Admin Panel ────────────────────────────────────────────────────────────

  async adminOverview() {
    return this.request<any>('/admin/overview');
  }

  async adminGetUsers(params?: { search?: string; role?: string; status?: string; page?: number }) {
    const query = new URLSearchParams();
    if (params?.search) query.set('search', params.search);
    if (params?.role) query.set('role', params.role);
    if (params?.status) query.set('status', params.status);
    if (params?.page) query.set('page', params.page.toString());
    return this.request<any>(`/admin/users?${query}`);
  }

  async adminCreateUser(data: { email: string; username: string; password: string; displayName: string; role: string }) {
    return this.request<any>('/admin/users', { method: 'POST', body: JSON.stringify(data) });
  }

  async adminUpdateUser(id: string, data: { displayName?: string; role?: string; status?: string }) {
    return this.request<any>(`/admin/users/${id}`, { method: 'PUT', body: JSON.stringify(data) });
  }

  async adminDeleteUser(id: string) {
    return this.request<any>(`/admin/users/${id}`, { method: 'DELETE' });
  }

  async adminGetTenants(params?: { page?: number }) {
    const query = params?.page ? `?page=${params.page}` : '';
    return this.request<any>(`/admin/tenants${query}`);
  }

  async adminCreateTenant(data: { name: string; domain: string; plan: string }) {
    return this.request<any>('/admin/tenants', { method: 'POST', body: JSON.stringify(data) });
  }

  async adminUpdateTenant(id: string, data: { name?: string; plan?: string; status?: string }) {
    return this.request<any>(`/admin/tenants/${id}`, { method: 'PUT', body: JSON.stringify(data) });
  }

  async adminGetRoles() {
    return this.request<any[]>('/admin/roles');
  }

  async adminCreateRole(data: { name: string; description?: string; permissions: string[] }) {
    return this.request<any>('/admin/roles', { method: 'POST', body: JSON.stringify(data) });
  }

  async adminDeleteRole(id: string) {
    return this.request<any>(`/admin/roles/${id}`, { method: 'DELETE' });
  }

  async adminGetSettings() {
    return this.request<any[]>('/admin/settings');
  }

  async adminUpdateSettings(settings: { key: string; value: string }[]) {
    return this.request<any>('/admin/settings', { method: 'PUT', body: JSON.stringify({ settings }) });
  }

  async adminGetAuditLogs(params?: { eventType?: string; page?: number }) {
    const query = new URLSearchParams();
    if (params?.eventType) query.set('eventType', params.eventType);
    if (params?.page) query.set('page', params.page.toString());
    return this.request<any>(`/admin/audit-logs?${query}`);
  }

  // ─── Webhooks ───────────────────────────────────────────────────────────────

  async getWebhooks() {
    return this.request<any[]>('/webhooks');
  }

  async createWebhook(data: { name: string; url: string; events: string[] }) {
    return this.request<any>('/webhooks', { method: 'POST', body: JSON.stringify(data) });
  }

  async deleteWebhook(id: string) {
    return this.request<any>(`/webhooks/${id}`, { method: 'DELETE' });
  }

  // ─── API Keys ───────────────────────────────────────────────────────────────

  async getApiKeys() {
    return this.request<any[]>('/api-keys');
  }

  async createApiKey(data: { name: string; permissions: string[] }) {
    return this.request<any>('/api-keys', { method: 'POST', body: JSON.stringify(data) });
  }

  async revokeApiKey(id: string) {
    return this.request<any>(`/api-keys/${id}/revoke`, { method: 'PUT' });
  }

  async deleteApiKey(id: string) {
    return this.request<any>(`/api-keys/${id}`, { method: 'DELETE' });
  }

  // ─── Files ──────────────────────────────────────────────────────────────────

  async getFiles(deviceId?: string) {
    const query = deviceId ? `?deviceId=${deviceId}` : '';
    return this.request<any[]>(`/files${query}`);
  }

  async deleteStoredFile(id: string) {
    return this.request<any>(`/files/${id}`, { method: 'DELETE' });
  }

  // ─── Backups ────────────────────────────────────────────────────────────────

  async getBackups() {
    return this.request<any[]>('/backups');
  }

  async createBackup(data: { name: string; type: string }) {
    return this.request<any>('/backups', { method: 'POST', body: JSON.stringify(data) });
  }

  async deleteBackup(id: string) {
    return this.request<any>(`/backups/${id}`, { method: 'DELETE' });
  }
}

export const api = new ApiClient();

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../lib/api';
import { notify } from '../lib/toast';

// ─── Dashboard ──────────────────────────────────────────────────────────────────

export function useDashboardStats() {
  return useQuery({
    queryKey: ['dashboard', 'stats'],
    queryFn: () => api.getDashboardStats(),
    refetchInterval: 30000, // auto-refresh every 30s
  });
}

// ─── Devices ────────────────────────────────────────────────────────────────────

export function useDevices(params?: { search?: string; status?: string; type?: string; page?: number; limit?: number }) {
  return useQuery({
    queryKey: ['devices', params],
    queryFn: () => api.getDevices(params),
    placeholderData: (prev: any) => prev, // keep previous data while loading next page
  });
}

export function useDeviceStats() {
  return useQuery({
    queryKey: ['devices', 'stats'],
    queryFn: () => api.getDeviceStats(),
    refetchInterval: 15000,
  });
}

export function useCreateDevice() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (data: any) => api.createDevice(data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['devices'] });
      notify.success('Device created successfully');
    },
    onError: (err: any) => notify.error(err.message || 'Failed to create device'),
  });
}

export function useDeleteDevice() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.deleteDevice(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['devices'] });
      notify.success('Device deleted');
    },
    onError: (err: any) => notify.error(err.message || 'Failed to delete device'),
  });
}

export function useUpdateDevice() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: ({ id, data }: { id: string; data: any }) => api.updateDevice(id, data),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['devices'] });
      notify.success('Device updated');
    },
    onError: (err: any) => notify.error(err.message || 'Failed to update device'),
  });
}

// ─── Alerts ─────────────────────────────────────────────────────────────────────

export function useAlerts() {
  return useQuery({
    queryKey: ['alerts'],
    queryFn: () => api.getAlerts(),
    refetchInterval: 10000,
  });
}

export function useAlertStats() {
  return useQuery({
    queryKey: ['alerts', 'stats'],
    queryFn: () => api.getAlertStats(),
    refetchInterval: 10000,
  });
}

export function useAcknowledgeAlert() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.acknowledgeAlert(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['alerts'] });
      notify.success('Alert acknowledged');
    },
    onError: (err: any) => notify.error(err.message),
  });
}

export function useResolveAlert() {
  const qc = useQueryClient();
  return useMutation({
    mutationFn: (id: string) => api.resolveAlert(id),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['alerts'] });
      notify.success('Alert resolved');
    },
    onError: (err: any) => notify.error(err.message),
  });
}

// ─── Jobs ───────────────────────────────────────────────────────────────────────

export function useJobs() {
  return useQuery({
    queryKey: ['jobs'],
    queryFn: () => api.getJobs(),
  });
}

export function useJobStats() {
  return useQuery({
    queryKey: ['jobs', 'stats'],
    queryFn: () => api.getJobStats(),
    refetchInterval: 15000,
  });
}

// ─── Users ──────────────────────────────────────────────────────────────────────

export function useUsers() {
  return useQuery({
    queryKey: ['users'],
    queryFn: () => api.getUsers(),
  });
}

export function useUserStats() {
  return useQuery({
    queryKey: ['users', 'stats'],
    queryFn: () => api.getUserStats(),
  });
}

// ─── Tenants ────────────────────────────────────────────────────────────────────

export function useTenants() {
  return useQuery({
    queryKey: ['tenants'],
    queryFn: () => api.getTenants(),
  });
}

export function useTenantStats() {
  return useQuery({
    queryKey: ['tenants', 'stats'],
    queryFn: () => api.getTenantStats(),
  });
}

// ─── Audit Logs ─────────────────────────────────────────────────────────────────

export function useAuditLogs() {
  return useQuery({
    queryKey: ['audit-logs'],
    queryFn: () => api.getAuditLogs(),
  });
}

export function useAuditLogStats() {
  return useQuery({
    queryKey: ['audit-logs', 'stats'],
    queryFn: () => api.getAuditLogStats(),
  });
}

// ─── Groups ─────────────────────────────────────────────────────────────────────

export function useGroups() {
  return useQuery({
    queryKey: ['groups'],
    queryFn: () => api.getGroups(),
  });
}

// ─── Telemetry ──────────────────────────────────────────────────────────────────

export function useTelemetryLatest() {
  return useQuery({
    queryKey: ['telemetry', 'latest'],
    queryFn: () => api.getTelemetryLatest(),
    refetchInterval: 5000,
  });
}

export function useTelemetryAggregated() {
  return useQuery({
    queryKey: ['telemetry', 'aggregated'],
    queryFn: () => api.getTelemetryAggregated(),
    refetchInterval: 5000,
  });
}

export function useTelemetryTimeSeries(minutes = 60) {
  return useQuery({
    queryKey: ['telemetry', 'timeseries', minutes],
    queryFn: () => api.getTelemetryTimeSeries(minutes),
    refetchInterval: 10000,
  });
}

export function useDeviceTelemetry(deviceId: string | null) {
  return useQuery({
    queryKey: ['telemetry', 'device', deviceId],
    queryFn: () => api.getDeviceTelemetry(deviceId!, 50),
    enabled: !!deviceId,
    refetchInterval: 5000,
  });
}

import Fastify from 'fastify';
import { deviceRoutes } from './routes/device.routes';
import { heartbeatRoutes } from './routes/heartbeat.routes';
import { logger } from './lib/logger';

const app = Fastify({ logger: true });

// Register routes
app.register(deviceRoutes, { prefix: '/api/v1/devices' });
app.register(heartbeatRoutes, { prefix: '/api/v1/heartbeat' });

// Health check
app.get('/health', async () => ({
  status: 'ok',
  service: 'device-service',
  timestamp: new Date().toISOString(),
  uptime: process.uptime(),
}));

// Start server
const start = async () => {
  try {
    const port = parseInt(process.env.DEVICE_SERVICE_PORT || '4010');
    await app.listen({ port, host: '0.0.0.0' });
    logger.info(`Device Service running on port ${port}`);
  } catch (err) {
    logger.error(err);
    process.exit(1);
  }
};

start();

export { app };

import { FastifyInstance } from 'fastify';

export async function deviceRoutes(app: FastifyInstance) {
  // List devices
  app.get('/', async (request, reply) => {
    const { page = 1, pageSize = 20, status, type } = request.query as any;
    // TODO: Query from PostgreSQL
    return {
      success: true,
      data: [],
      total: 0,
      page: Number(page),
      pageSize: Number(pageSize),
    };
  });

  // Get device by ID
  app.get('/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    // TODO: Query from PostgreSQL
    return { success: true, data: { id } };
  });

  // Register device
  app.post('/', async (request, reply) => {
    const body = request.body as any;
    // TODO: Insert into PostgreSQL, publish to Kafka
    const deviceId = `dev-${Date.now()}`;
    return {
      success: true,
      data: {
        id: deviceId,
        ...body,
        status: 'online',
        createdAt: new Date().toISOString(),
      },
    };
  });

  // Update device
  app.put('/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const body = request.body as any;
    // TODO: Update in PostgreSQL
    return {
      success: true,
      data: { id, ...body, updatedAt: new Date().toISOString() },
    };
  });

  // Delete (decommission) device
  app.delete('/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    // TODO: Soft delete in PostgreSQL
    return { success: true, message: `Device ${id} decommissioned` };
  });

  // Execute command on device
  app.post('/:id/command', async (request, reply) => {
    const { id } = request.params as { id: string };
    const body = request.body as any;
    // TODO: Publish command to MQTT/Kafka
    return {
      success: true,
      data: {
        commandId: `cmd-${Date.now()}`,
        deviceId: id,
        type: body.type,
        status: 'queued',
      },
    };
  });

  // Get device shadow state
  app.get('/:id/shadow', async (request, reply) => {
    const { id } = request.params as { id: string };
    // TODO: Get from Redis/PostgreSQL
    return {
      success: true,
      data: {
        deviceId: id,
        desired: {},
        reported: {},
        delta: {},
        version: 1,
        lastSync: new Date().toISOString(),
      },
    };
  });

  // Update device shadow
  app.put('/:id/shadow', async (request, reply) => {
    const { id } = request.params as { id: string };
    const body = request.body as any;
    // TODO: Update shadow state, compute delta, publish to device
    return {
      success: true,
      data: {
        deviceId: id,
        desired: body.desired || {},
        version: 2,
        updatedAt: new Date().toISOString(),
      },
    };
  });
}

