  ONLINE = 'online',
  OFFLINE = 'offline',
  IDLE = 'idle',
  BUSY = 'busy',
  ERROR = 'error',
  MAINTENANCE = 'maintenance',
  UPDATING = 'updating',
  PROVISIONING = 'provisioning',
  DECOMMISSIONED = 'decommissioned',
}

export enum DeviceHealthStatus {
  HEALTHY = 'healthy',
  WARNING = 'warning',
  CRITICAL = 'critical',
  UNKNOWN = 'unknown',
}

export interface DeviceSpecs {
  cpu: {
    model: string;
    cores: number;
    frequency: number; // MHz
    architecture: string;
  };
  memory: {
    total: number; // bytes
    type?: string;
  };
  storage: {
    total: number; // bytes
    type?: string;
  };
  gpu?: {
    model: string;
    memory: number; // bytes
    driver?: string;
  };
  network: {
    interfaces: NetworkInterface[];
  };
  os: {
    name: string;
    version: string;
    kernel?: string;
  };
  screen?: {
    width: number;
    height: number;
    density?: number;
  };
}

export interface NetworkInterface {
  name: string;
  type: 'wifi' | 'ethernet' | 'cellular' | 'bluetooth' | 'other';
  macAddress?: string;
  ipv4?: string;
  ipv6?: string;
  speed?: number; // Mbps
}

export interface Device extends BaseEntity {
  tenantId: UUID;
  name: string;
  alias?: string;
  type: DeviceType;
  status: DeviceStatus;
  healthStatus: DeviceHealthStatus;
  specs: DeviceSpecs;
  location?: GeoLocation;
  tags: string[];
  groups: UUID[];
  metadata: Record<string, unknown>;
  lastSeen: string;
  lastHeartbeat: string;
  agentVersion: string;
  firmwareVersion?: string;
  serialNumber?: string;
  fingerprint: string;
  shadowState: DeviceShadowState;
  ownerId: UUID;
}

export interface DeviceShadowState {
  desired: Record<string, unknown>;
  reported: Record<string, unknown>;
  delta?: Record<string, unknown>;
  lastSync: string;
  version: number;
}

export interface DeviceGroup extends BaseEntity {
  tenantId: UUID;
  name: string;
  description?: string;
  parentId?: UUID;
  deviceCount: number;
  tags: string[];
  policies: UUID[];
}

export interface DeviceCommand {
  id: UUID;
  deviceId: UUID;
  type: DeviceCommandType;
  payload: Record<string, unknown>;
  status: CommandStatus;
  priority: number;
  timeout: number; // seconds
  createdAt: string;
  executedAt?: string;
  completedAt?: string;
  result?: CommandResult;
}

export enum DeviceCommandType {
  SHELL_EXECUTE = 'shell_execute',
  FILE_TRANSFER = 'file_transfer',
  APP_INSTALL = 'app_install',
  APP_UNINSTALL = 'app_uninstall',
  REBOOT = 'reboot',
  SHUTDOWN = 'shutdown',
  UPDATE_CONFIG = 'update_config',
  SCREENSHOT = 'screenshot',
  SCREEN_RECORD = 'screen_record',
  REMOTE_CONTROL = 'remote_control',
  OTA_UPDATE = 'ota_update',
  DIAGNOSTICS = 'diagnostics',
  CUSTOM = 'custom',
}

export enum CommandStatus {
  PENDING = 'pending',
  QUEUED = 'queued',
  EXECUTING = 'executing',
  COMPLETED = 'completed',
  FAILED = 'failed',
  TIMEOUT = 'timeout',
  CANCELLED = 'cancelled',
}

export interface CommandResult {
  exitCode?: number;
  stdout?: string;
  stderr?: string;
  data?: Record<string, unknown>;
  error?: string;
  duration: number; // ms
}

export interface DeviceRegistrationRequest {
  name: string;
  type: DeviceType;
  specs: DeviceSpecs;
  fingerprint: string;
  agentVersion: string;
  metadata?: Record<string, unknown>;
  tags?: string[];
}

export interface DeviceHeartbeat {
  deviceId: UUID;
  timestamp: string;
  status: DeviceStatus;
  metrics: DeviceMetricsSnapshot;
  agentVersion: string;
}

export interface DeviceMetricsSnapshot {
  cpu: {
    usage: number; // percentage
    temperature?: number; // celsius
  };
  memory: {
    used: number; // bytes
    available: number; // bytes
    percentage: number;
  };
  storage: {
    used: number; // bytes
    available: number; // bytes
    percentage: number;
  };
  network: {
    bytesIn: number;
    bytesOut: number;
    latency?: number; // ms
  };
  battery?: {
    level: number; // percentage
    charging: boolean;
    temperature?: number;
  };
  gpu?: {
    usage: number; // percentage
    memory: number; // percentage
    temperature?: number;
  };
  uptime: number; // seconds
  processCount: number;
}

import { BaseEntity, UUID } from './common';
import { UserRole } from './tenant';

// ============================================
// Authentication & Authorization Types
// ============================================

export interface User extends BaseEntity {
  email: string;
  username: string;
  displayName: string;
  avatar?: string;
  emailVerified: boolean;
  mfaEnabled: boolean;
  passkeysEnabled: boolean;
  lastLogin?: string;
  status: UserStatus;
  preferences: UserPreferences;
}

export enum UserStatus {
  ACTIVE = 'active',
  INACTIVE = 'inactive',
  SUSPENDED = 'suspended',
  PENDING_VERIFICATION = 'pending_verification',
}

export interface UserPreferences {
  theme: 'light' | 'dark' | 'system';
  language: string;
  timezone: string;
  notifications: NotificationPreferences;
}

export interface NotificationPreferences {
  email: boolean;
  push: boolean;
  sms: boolean;
  slack: boolean;
  telegram: boolean;
  discord: boolean;
}

export interface AuthTokens {
  accessToken: string;
  refreshToken: string;
  expiresIn: number;
  tokenType: 'Bearer';
}

export interface LoginRequest {
  email: string;
  password: string;
  mfaCode?: string;
  deviceFingerprint?: string;
}

export interface RegisterRequest {
  email: string;
  username: string;
  password: string;
  displayName: string;
  tenantName?: string;
}

export interface Session extends BaseEntity {
  userId: UUID;
  tenantId: UUID;
  token: string;
  deviceInfo: SessionDeviceInfo;
  ipAddress: string;
  expiresAt: string;
  lastActivity: string;
}

export interface SessionDeviceInfo {
  userAgent: string;
  browser?: string;
  os?: string;
  device?: string;
  fingerprint: string;
}

export interface ApiKey extends BaseEntity {
  tenantId: UUID;
  userId: UUID;
  name: string;
  keyPrefix: string; // first 8 chars for identification
  permissions: string[];
  rateLimit: number; // requests per minute
  expiresAt?: string;
  lastUsed?: string;
  usageCount: number;
}

export interface Permission {
  resource: string;
  actions: PermissionAction[];
}

export enum PermissionAction {
  CREATE = 'create',
  READ = 'read',
  UPDATE = 'update',
  DELETE = 'delete',
  EXECUTE = 'execute',
  MANAGE = 'manage',
}

export interface RolePermissions {
  role: UserRole;
  permissions: Permission[];
}

export interface OAuthProvider {
  provider: 'google' | 'github' | 'microsoft' | 'apple';
  clientId: string;
  enabled: boolean;
}

export interface MFASetup {
  secret: string;
  qrCode: string;
  backupCodes: string[];
}

export interface PasskeyCredential {
  id: string;
  publicKey: string;
  counter: number;
  deviceType: string;
  createdAt: string;
  lastUsed?: string;
}

import { UUID, Timestamp, EventPriority } from './common';

// ============================================
// Telemetry & Monitoring Types
// ============================================

export interface TelemetryEvent {
  id: UUID;
  deviceId: UUID;
  tenantId: UUID;
  type: TelemetryEventType;
  timestamp: Timestamp;
  data: Record<string, unknown>;
  tags: string[];
  priority: EventPriority;
}

export enum TelemetryEventType {
  METRIC = 'metric',
  LOG = 'log',
  ERROR = 'error',
  ALERT = 'alert',
  HEARTBEAT = 'heartbeat',
  STATE_CHANGE = 'state_change',
  COMMAND_RESULT = 'command_result',
  PERFORMANCE = 'performance',
  SECURITY = 'security',
  CUSTOM = 'custom',
}

export interface MetricDataPoint {
  name: string;
  value: number;
  unit: string;
  timestamp: Timestamp;
  tags: Record<string, string>;
  deviceId: UUID;
  tenantId: UUID;
}

export interface Alert {
  id: UUID;
  tenantId: UUID;
  deviceId?: UUID;
  type: AlertType;
  severity: AlertSeverity;
  title: string;
  message: string;
  source: string;
  timestamp: Timestamp;
  acknowledged: boolean;
  acknowledgedBy?: UUID;
  resolvedAt?: Timestamp;
  metadata: Record<string, unknown>;
}

export enum AlertType {
  DEVICE_OFFLINE = 'device_offline',
  HIGH_CPU = 'high_cpu',
  HIGH_MEMORY = 'high_memory',
  LOW_STORAGE = 'low_storage',
  LOW_BATTERY = 'low_battery',
  NETWORK_ERROR = 'network_error',
  SECURITY_THREAT = 'security_threat',
  UPDATE_AVAILABLE = 'update_available',
  COMMAND_FAILED = 'command_failed',
  ANOMALY_DETECTED = 'anomaly_detected',
  CUSTOM = 'custom',
}

export enum AlertSeverity {
  INFO = 'info',
  WARNING = 'warning',
  ERROR = 'error',
  CRITICAL = 'critical',
}

export interface TelemetryQuery {
  deviceIds?: UUID[];
  tenantId: UUID;
  metrics: string[];
  startTime: Timestamp;
  endTime: Timestamp;
  interval?: string; // e.g., '1m', '5m', '1h'
  aggregation?: 'avg' | 'sum' | 'min' | 'max' | 'count';
  groupBy?: string[];
}

export interface TelemetryResult {
  metric: string;
  dataPoints: {
    timestamp: Timestamp;
    value: number;
  }[];
  aggregation?: string;
  deviceId?: UUID;
}

export interface DashboardWidget {
  id: UUID;
  type: WidgetType;
  title: string;
  config: WidgetConfig;
  position: { x: number; y: number; w: number; h: number };
}

export enum WidgetType {
  LINE_CHART = 'line_chart',
  BAR_CHART = 'bar_chart',
  GAUGE = 'gauge',
  STAT = 'stat',
  TABLE = 'table',
  MAP = 'map',
  HEATMAP = 'heatmap',
  TOPOLOGY = 'topology',
  LOG_STREAM = 'log_stream',
  ALERT_LIST = 'alert_list',
}

export interface WidgetConfig {
  query: TelemetryQuery;
  refreshInterval: number; // seconds
  thresholds?: { value: number; color: string; label: string }[];
  visualization?: Record<string, unknown>;
}

import { BaseEntity, UUID } from './common';

// ============================================
// Multi-Tenant Types
// ============================================

export enum TenantPlan {
  FREE = 'free',
  PRO = 'pro',
  ENTERPRISE = 'enterprise',
}

export enum TenantStatus {
  ACTIVE = 'active',
  SUSPENDED = 'suspended',
  TRIAL = 'trial',
  CANCELLED = 'cancelled',
}

export interface Tenant extends BaseEntity {
  name: string;
  slug: string;
  plan: TenantPlan;
  status: TenantStatus;
  ownerId: UUID;
  settings: TenantSettings;
  limits: TenantLimits;
  billing: TenantBilling;
  metadata: Record<string, unknown>;
}

export interface TenantSettings {
  timezone: string;
  locale: string;
  theme?: string;
  features: string[];
  integrations: TenantIntegration[];
  security: TenantSecuritySettings;
}

export interface TenantSecuritySettings {
  mfaRequired: boolean;
  ipWhitelist: string[];
  sessionTimeout: number; // minutes
  passwordPolicy: {
    minLength: number;
    requireUppercase: boolean;
    requireNumbers: boolean;
    requireSpecialChars: boolean;
    maxAge: number; // days
  };
}

export interface TenantIntegration {
  type: string;
  enabled: boolean;
  config: Record<string, unknown>;
}

export interface TenantLimits {
  maxDevices: number;
  maxUsers: number;
  maxWorkflows: number;
  maxStorage: number; // bytes
  maxApiCalls: number; // per month
  maxConcurrentSessions: number;
}

export interface TenantBilling {
  customerId?: string; // Stripe customer ID
  subscriptionId?: string;
  currentPeriodEnd?: string;
  paymentMethod?: string;
}

export enum UserRole {
  SUPER_ADMIN = 'super_admin',
  TENANT_OWNER = 'tenant_owner',
  ADMIN = 'admin',
  OPERATOR = 'operator',
  VIEWER = 'viewer',
  AI_OPERATOR = 'ai_operator',
  BILLING_ADMIN = 'billing_admin',
}

export interface TenantMember extends BaseEntity {
  tenantId: UUID;
  userId: UUID;
  role: UserRole;
  permissions: string[];
  invitedBy?: UUID;
  joinedAt: string;
}

export interface Workspace extends BaseEntity {
  tenantId: UUID;
  name: string;
  description?: string;
  settings: Record<string, unknown>;
  members: UUID[];
}

// Common types used across the platform

export type UUID = string;
export type Timestamp = string; // ISO 8601
export type GeoLocation = {
  latitude: number;
  longitude: number;
  altitude?: number;
  accuracy?: number;
};

export interface PaginatedResponse<T> {
  data: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
  hasNext: boolean;
  hasPrevious: boolean;
}

export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: ApiError;
  metadata?: Record<string, unknown>;
  timestamp: Timestamp;
  requestId: string;
}

export interface ApiError {
  code: string;
  message: string;
  details?: Record<string, unknown>;
  stack?: string;
}

export type SortOrder = 'asc' | 'desc';

export interface SortOptions {
  field: string;
  order: SortOrder;
}

export interface FilterOptions {
  field: string;
  operator: 'eq' | 'neq' | 'gt' | 'gte' | 'lt' | 'lte' | 'in' | 'nin' | 'contains' | 'regex';
  value: unknown;
}

export interface QueryOptions {
  page?: number;
  pageSize?: number;
  sort?: SortOptions[];
  filters?: FilterOptions[];
  search?: string;
}

export enum EventPriority {
  LOW = 'low',
  MEDIUM = 'medium',
  HIGH = 'high',
  CRITICAL = 'critical',
}

export interface BaseEntity {
  id: UUID;
  createdAt: Timestamp;
  updatedAt: Timestamp;
  deletedAt?: Timestamp;
}

