import { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../lib/api';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';

export function Settings() {
  const [activeTab, setActiveTab] = useState<'general' | 'security' | 'notifications' | 'integrations' | 'devices' | 'system'>('general');
  const queryClient = useQueryClient();

  // Fetch settings from API
  const { data: settingsData, isLoading } = useQuery({
    queryKey: ['admin', 'settings'],
    queryFn: () => api.adminGetSettings(),
  });

  // Fetch system overview
  const { data: overview } = useQuery({
    queryKey: ['admin', 'overview'],
    queryFn: () => api.adminOverview(),
  });

  // Local form state
  const [formValues, setFormValues] = useState<Record<string, string>>({});

  useEffect(() => {
    if (Array.isArray(settingsData)) {
      const values: Record<string, string> = {};
      for (const s of settingsData) {
        values[s.key] = s.value;
      }
      setFormValues(values);
    }
  }, [settingsData]);

  // Save settings mutation
  const saveMutation = useMutation({
    mutationFn: (settings: { key: string; value: string }[]) => api.adminUpdateSettings(settings),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin', 'settings'] });
      notify.success('Settings saved successfully');
    },
    onError: (err: any) => notify.error(err.message || 'Failed to save settings'),
  });

  const handleSave = () => {
    const settings = Object.entries(formValues).map(([key, value]) => ({ key, value }));
    saveMutation.mutate(settings);
  };

  const updateValue = (key: string, value: string) => {
    setFormValues(prev => ({ ...prev, [key]: value }));
  };

  const tabs = [
    { id: 'general' as const, icon: '⚙️', label: 'General' },
    { id: 'security' as const, icon: '🔒', label: 'Security' },
    { id: 'notifications' as const, icon: '🔔', label: 'Notifications' },
    { id: 'integrations' as const, icon: '🔗', label: 'Integrations' },
    { id: 'devices' as const, icon: '📱', label: 'Devices' },
    { id: 'system' as const, icon: '🖥️', label: 'System' },
  ];

  return (
    <PageLayout title="Settings" description="Configure system preferences and platform settings.">
      {/* Tabs */}
      <div className="flex items-center gap-2 px-4 py-2 border-b border-[#1e293b]/50 bg-[#0d1117]/50 flex-shrink-0">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border transition-colors ${
              activeTab === tab.id
                ? 'bg-[#1e293b] border-[#334155] text-white'
                : 'border-transparent text-slate-400 hover:text-white hover:bg-[#1e293b]/50'
            }`}
          >
            <span className="text-xs">{tab.icon}</span>
            <span className="text-[9px] font-medium">{tab.label}</span>
          </button>
        ))}
      </div>

      {/* Main content */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {activeTab === 'general' && (
          <div className="grid grid-cols-12 gap-4">
            {/* General Settings Form */}
            <div className="col-span-7 rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
              <h3 className="text-[11px] font-semibold text-white mb-4">General Settings</h3>
              {isLoading ? (
                <div className="space-y-3">
                  {Array.from({ length: 5 }).map((_, i) => (
                    <div key={i} className="h-8 bg-[#1e293b]/50 rounded animate-pulse" />
                  ))}
                </div>
              ) : (
                <div className="space-y-4">
                  <SettingRow label="Telemetry Interval" description="How often devices report metrics (seconds)">
                    <select
                      value={formValues['telemetry_interval'] || '30'}
                      onChange={(e) => updateValue('telemetry_interval', e.target.value)}
                      className="w-48 h-7 px-2.5 rounded border border-[#1e293b] bg-[#111827] text-[9px] text-white outline-none focus:border-cyan-500/30"
                    >
                      <option value="10">10 seconds</option>
                      <option value="30">30 seconds</option>
                      <option value="60">60 seconds</option>
                      <option value="300">5 minutes</option>
                    </select>
                  </SettingRow>

                  <SettingRow label="Session Timeout" description="Auto-logout after inactivity (seconds)">
                    <select
                      value={formValues['session_timeout'] || '3600'}
                      onChange={(e) => updateValue('session_timeout', e.target.value)}
                      className="w-48 h-7 px-2.5 rounded border border-[#1e293b] bg-[#111827] text-[9px] text-white outline-none focus:border-cyan-500/30"
                    >
                      <option value="1800">30 minutes</option>
                      <option value="3600">1 hour</option>
                      <option value="7200">2 hours</option>
                      <option value="28800">8 hours</option>
                    </select>
                  </SettingRow>

                  <SettingRow label="Max Login Attempts" description="Lock account after failed attempts">
                    <select
                      value={formValues['max_login_attempts'] || '5'}
                      onChange={(e) => updateValue('max_login_attempts', e.target.value)}
                      className="w-48 h-7 px-2.5 rounded border border-[#1e293b] bg-[#111827] text-[9px] text-white outline-none focus:border-cyan-500/30"
                    >
                      <option value="3">3 attempts</option>
                      <option value="5">5 attempts</option>
                      <option value="10">10 attempts</option>
                    </select>
                  </SettingRow>

                  <SettingRow label="Backup Retention" description="How long to keep backups (days)">
                    <select
                      value={formValues['backup_retention_days'] || '30'}
                      onChange={(e) => updateValue('backup_retention_days', e.target.value)}
                      className="w-48 h-7 px-2.5 rounded border border-[#1e293b] bg-[#111827] text-[9px] text-white outline-none focus:border-cyan-500/30"
                    >
                      <option value="7">7 days</option>
                      <option value="14">14 days</option>
                      <option value="30">30 days</option>
                      <option value="90">90 days</option>
                    </select>
                  </SettingRow>

                  <SettingRow label="Email Alerts" description="Send alert notifications via email">
                    <ToggleSwitch
                      enabled={formValues['alert_email_enabled'] === 'true'}
                      onChange={(v) => updateValue('alert_email_enabled', v ? 'true' : 'false')}
                    />
                  </SettingRow>

                  <SettingRow label="Slack Webhook" description="Slack webhook URL for notifications">
                    <input
                      type="text"
                      value={formValues['alert_slack_webhook'] || ''}
                      onChange={(e) => updateValue('alert_slack_webhook', e.target.value)}
                      placeholder="https://hooks.slack.com/..."
                      className="w-48 h-7 px-2.5 rounded border border-[#1e293b] bg-[#111827] text-[9px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600"
                    />
                  </SettingRow>

                  <button
                    onClick={handleSave}
                    disabled={saveMutation.isPending}
                    className="px-4 py-2 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20 transition-colors disabled:opacity-50"
                  >
                    {saveMutation.isPending ? '⏳ Saving...' : '💾 Save Changes'}
                  </button>
                </div>
              )}
            </div>

            {/* System Information */}
            <div className="col-span-5 space-y-4">
              <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
                <h3 className="text-[11px] font-semibold text-white mb-3">System Information</h3>
                <div className="space-y-2">
                  {[
                    { label: 'Platform Version', value: overview?.version || 'v2.1.0' },
                    { label: 'System Health', value: overview?.systemHealth || 'unknown', color: overview?.systemHealth === 'healthy' ? 'text-emerald-400' : 'text-yellow-400' },
                    { label: 'Uptime', value: overview?.uptime || '—' },
                    { label: 'Total Users', value: String(overview?.users || 0) },
                    { label: 'Total Devices', value: String(overview?.devices || 0) },
                    { label: 'Total Tenants', value: String(overview?.tenants || 0) },
                  ].map((row) => (
                    <div key={row.label} className="flex items-center justify-between">
                      <span className="text-[9px] text-slate-500">{row.label}</span>
                      <span className={`text-[9px] font-medium ${row.color || 'text-white'}`}>{row.value}</span>
                    </div>
                  ))}
                </div>
              </div>

              <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
                <h3 className="text-[11px] font-semibold text-white mb-3">Current Settings</h3>
                <div className="space-y-1.5">
                  {Array.isArray(settingsData) && settingsData.map((s: any) => (
                    <div key={s.id} className="flex items-center justify-between">
                      <span className="text-[8px] text-slate-500">{s.key}</span>
                      <span className="text-[8px] text-slate-300 font-mono">{s.value || '(empty)'}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'security' && (
          <div className="grid grid-cols-2 gap-4">
            <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
              <h3 className="text-[11px] font-semibold text-white mb-4">Authentication</h3>
              <div className="space-y-4">
                <SettingRow label="Session Timeout" description="Auto-logout inactive users">
                  <select
                    value={formValues['session_timeout'] || '3600'}
                    onChange={(e) => updateValue('session_timeout', e.target.value)}
                    className="w-40 h-7 px-2.5 rounded border border-[#1e293b] bg-[#111827] text-[9px] text-white outline-none"
                  >
                    <option value="1800">30 minutes</option>
                    <option value="3600">1 hour</option>
                    <option value="7200">2 hours</option>
                  </select>
                </SettingRow>
                <SettingRow label="Max Login Attempts" description="Lock after failed attempts">
                  <select
