}

// Helper components
function SettingRow({ label, description, children }: { label: string; description: string; children: React.ReactNode }) {
  return (
    <div className="flex items-center justify-between">
      <div>
        <p className="text-[10px] font-medium text-white">{label}</p>
        <p className="text-[8px] text-slate-500">{description}</p>
      </div>
      {children}
    </div>
  );
}

function ToggleSwitch({ enabled, onChange }: { enabled: boolean; onChange: (v: boolean) => void }) {
  return (
    <button
      onClick={() => onChange(!enabled)}
      className={`w-8 h-4 rounded-full relative transition-colors ${enabled ? 'bg-cyan-500/30 border-cyan-500/50' : 'bg-[#1e293b] border-[#334155]'} border`}
    >
      <div className={`absolute top-0.5 w-3 h-3 rounded-full transition-all ${enabled ? 'right-0.5 bg-cyan-400' : 'left-0.5 bg-slate-500'}`} />
    </button>
  );
}

import { useState } from 'react';
import { useGroups, useDeviceStats } from '../hooks/useApi';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../lib/api';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { Modal } from '../components/ui/Modal';
import { ConfirmDialog } from '../components/ui/ConfirmDialog';
import { TableSkeleton } from '../components/ui/LoadingState';
import { EmptyState } from '../components/ui/EmptyState';

export function Groups() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedGroup, setSelectedGroup] = useState<any>(null);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<any>(null);
  const [newGroup, setNewGroup] = useState({ name: '', description: '', color: '#06b6d4' });

  const queryClient = useQueryClient();
  const { data: groupsData, isLoading } = useGroups();
  const { data: deviceStats } = useDeviceStats();

  const groups = Array.isArray(groupsData) ? groupsData : [];

  // Create group mutation
  const createGroup = useMutation({
    mutationFn: (data: any) => api.createWebhook ? fetch('/api/v1/groups', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${localStorage.getItem('auth_token')}` },
      body: JSON.stringify(data),
    }).then(r => r.json()) : Promise.resolve({}),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['groups'] });
      notify.success('Group created');
      setShowCreateModal(false);
      setNewGroup({ name: '', description: '', color: '#06b6d4' });
    },
    onError: (err: any) => notify.error(err.message || 'Failed to create group'),
  });

  // Delete group mutation
  const deleteGroup = useMutation({
    mutationFn: (id: string) => fetch(`/api/v1/groups/${id}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${localStorage.getItem('auth_token')}` },
    }).then(r => r.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['groups'] });
      notify.success('Group deleted');
      setDeleteTarget(null);
      if (selectedGroup?.id === deleteTarget?.id) setSelectedGroup(null);
    },
    onError: (err: any) => notify.error(err.message || 'Failed to delete group'),
  });

  // Filter groups
  const filtered = groups.filter((g: any) =>
    !searchQuery || g.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const stats = [
    { label: 'Total Groups', value: String(groups.length) },
    { label: 'Total Devices', value: String(deviceStats?.total || 0) },
    { label: 'Online', value: String(deviceStats?.online || 0), color: 'text-emerald-400' },
    { label: 'Offline', value: String(deviceStats?.offline || 0), color: 'text-red-400' },
  ];

  const handleCreate = () => {
    if (!newGroup.name.trim()) {
      notify.error('Group name is required');
      return;
    }
    createGroup.mutate(newGroup);
  };

  return (
    <PageLayout
      title="Groups"
      description="Organize and manage your devices with group controls."
      stats={stats}
      actions={
        <button
          onClick={() => setShowCreateModal(true)}
          className="px-3 py-1.5 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20 transition-colors"
        >
          + Create Group
        </button>
      }
    >
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search groups...' }}
        info={`${filtered.length} groups`}
      />

      {/* Main content */}
      <div className="flex-1 flex overflow-hidden">
        {/* Groups list */}
        <div className="flex-1 overflow-y-auto">
          {isLoading ? (
            <TableSkeleton rows={6} />
          ) : filtered.length === 0 ? (
            <EmptyState
              icon="📁"
              title="No groups found"
              description={searchQuery ? 'Try a different search term' : 'Create your first device group to organize devices'}
            />
          ) : (
            <div className="px-4 py-2">
              {/* Table header */}
              <div className="flex items-center gap-2 px-2 py-1.5 text-[9px] text-slate-500 font-medium border-b border-[#1e293b]/50">
                <span className="flex-1 min-w-[180px]">Group Name</span>
                <span className="w-20 text-center">Devices</span>
                <span className="w-20 text-center">Color</span>
                <span className="w-32 text-right">Created</span>
                <span className="w-16 text-center">Actions</span>
              </div>

              {/* Table rows */}
              {filtered.map((group: any) => (
                <div
                  key={group.id}
                  onClick={() => setSelectedGroup(group)}
                  className={`flex items-center gap-2 px-2 py-2.5 rounded-md cursor-pointer transition-colors border ${
                    selectedGroup?.id === group.id
                      ? 'bg-cyan-500/5 border-cyan-500/20'
                      : 'border-transparent hover:bg-[#1e293b]/30'
                  }`}
                >
                  <div className="flex-1 min-w-[180px] flex items-center gap-2">
                    <span className="w-3 h-3 rounded" style={{ backgroundColor: group.color || '#06b6d4' }} />
                    <div>
                      <p className="text-[10px] font-medium text-white">{group.name}</p>
                      {group.description && <p className="text-[8px] text-slate-500">{group.description}</p>}
                    </div>
                  </div>
                  <span className="w-20 text-center text-[10px] text-white font-medium">
                    {group.deviceCount || 0}
                  </span>
                  <span className="w-20 flex justify-center">
                    <span className="w-4 h-4 rounded-full border border-[#1e293b]" style={{ backgroundColor: group.color || '#06b6d4' }} />
                  </span>
                  <span className="w-32 text-right text-[9px] text-slate-500">
                    {group.createdAt ? new Date(group.createdAt).toLocaleDateString() : '—'}
                  </span>
                  <span className="w-16 flex justify-center gap-1">
                    <button
                      onClick={(e) => { e.stopPropagation(); setDeleteTarget(group); }}
                      className="text-slate-500 hover:text-red-400 text-[9px] px-1"
                      title="Delete"
                    >
                      🗑️
                    </button>
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Right panel: Selected group detail */}
        {selectedGroup && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] flex flex-col overflow-hidden flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between mb-1">
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 rounded" style={{ backgroundColor: selectedGroup.color || '#06b6d4' }} />
                  <span className="text-[11px] font-semibold text-white">{selectedGroup.name}</span>
                </div>
                <button onClick={() => setSelectedGroup(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
              {selectedGroup.description && (
                <p className="text-[9px] text-slate-500 mt-1">{selectedGroup.description}</p>
              )}
            </div>

            <div className="px-4 py-3 border-b border-[#1e293b]">
              <h4 className="text-[10px] font-semibold text-slate-500 uppercase mb-2">Group Details</h4>
              <div className="space-y-2">
                <DetailRow label="Group ID" value={selectedGroup.id.slice(0, 8) + '...'} />
                <DetailRow label="Devices" value={String(selectedGroup.deviceCount || 0)} />
                <DetailRow label="Color" value={selectedGroup.color || '#06b6d4'} />
                <DetailRow label="Created" value={selectedGroup.createdAt ? new Date(selectedGroup.createdAt).toLocaleString() : '—'} />
                <DetailRow label="Updated" value={selectedGroup.updatedAt ? new Date(selectedGroup.updatedAt).toLocaleString() : '—'} />
              </div>
            </div>

            <div className="px-4 py-3">
              <button
                onClick={() => setDeleteTarget(selectedGroup)}
                className="w-full py-2 rounded-md text-[9px] font-medium bg-red-500/10 border border-red-500/20 text-red-400 hover:bg-red-500/20 transition-colors"
              >
                🗑️ Delete Group
              </button>
            </div>
          </aside>
        )}
      </div>

      {/* Create Modal */}
      <Modal open={showCreateModal} onClose={() => setShowCreateModal(false)} title="Create Group">
        <div className="space-y-4 p-4">
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Group Name *</label>
            <input
              type="text"
              value={newGroup.name}
              onChange={(e) => setNewGroup(prev => ({ ...prev, name: e.target.value }))}
              placeholder="e.g. Production Servers"
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600"
            />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Description</label>
            <input
              type="text"
              value={newGroup.description}
              onChange={(e) => setNewGroup(prev => ({ ...prev, description: e.target.value }))}
              placeholder="Optional description"
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600"
            />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Color</label>
            <div className="flex items-center gap-2">
              <input
                type="color"
                value={newGroup.color}
                onChange={(e) => setNewGroup(prev => ({ ...prev, color: e.target.value }))}
                className="w-8 h-8 rounded border border-[#1e293b] bg-transparent cursor-pointer"
              />
              <span className="text-[9px] text-slate-400">{newGroup.color}</span>
            </div>
          </div>
          <div className="flex items-center gap-2 pt-2">
            <button
              onClick={handleCreate}
              disabled={createGroup.isPending}
              className="flex-1 py-2 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20 disabled:opacity-50"
            >
              {createGroup.isPending ? 'Creating...' : 'Create Group'}
            </button>
            <button
              onClick={() => setShowCreateModal(false)}
              className="flex-1 py-2 rounded-md text-[10px] font-medium bg-[#1e293b]/50 border border-[#1e293b] text-slate-300 hover:bg-[#1e293b]"
            >
              Cancel
            </button>
          </div>
        </div>
      </Modal>

      {/* Delete Confirmation */}
      <ConfirmDialog
        open={!!deleteTarget}
        onClose={() => setDeleteTarget(null)}
        onConfirm={() => deleteTarget && deleteGroup.mutate(deleteTarget.id)}
        title="Delete Group"
        message={`Are you sure you want to delete "${deleteTarget?.name}"? This action cannot be undone.`}
        confirmLabel="Delete"
        loading={deleteGroup.isPending}
      />
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white font-mono">{value}</span>
    </div>
  );
}

import { useState } from 'react';
import { useAuditLogs, useAuditLogStats } from '../hooks/useApi';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { DataTable, Column } from '../components/ui/DataTable';

interface AuditLog {
  id: string;
  userId: string;
  action: string;
  resource: string;
  resourceId?: string;
  details: any;
  ipAddress?: string;
  createdAt: string;
}

export function Logs() {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterAction, setFilterAction] = useState('all');
  const [filterResource, setFilterResource] = useState('all');
  const [selectedLog, setSelectedLog] = useState<AuditLog | null>(null);

  const { data: logsData, isLoading } = useAuditLogs();
  const { data: logStats } = useAuditLogStats();

  const logs: AuditLog[] = Array.isArray(logsData) ? logsData : [];

  // Filter logs
  const filtered = logs.filter((log) => {
    if (filterAction !== 'all' && log.action !== filterAction) return false;
    if (filterResource !== 'all' && log.resource !== filterResource) return false;
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      return (
        log.action.toLowerCase().includes(q) ||
        log.resource.toLowerCase().includes(q) ||
        (log.ipAddress || '').includes(q) ||
        JSON.stringify(log.details || {}).toLowerCase().includes(q)
      );
    }
    return true;
  });

  // Get unique actions and resources for filters
  const actions = [...new Set(logs.map(l => l.action))];
  const resources = [...new Set(logs.map(l => l.resource))];

  const stats = [
    { label: 'Total Logs', value: String(logStats?.total || logs.length) },
    { label: 'Login Events', value: String(logStats?.login || 0) },
    { label: 'Create Events', value: String(logStats?.create || 0) },
    { label: 'Update Events', value: String(logStats?.update || 0) },
  ];

  const columns: Column<AuditLog>[] = [
    {
      key: 'createdAt',
      label: 'Timestamp',
      width: 'w-36',
      render: (log) => (
        <span className="text-slate-400 font-mono text-[9px]">
          {new Date(log.createdAt).toLocaleString()}
        </span>
      ),
    },
    {
      key: 'action',
      label: 'Action',
      width: 'w-28',
      render: (log) => (
        <span className={`text-[8px] px-1.5 py-0.5 rounded font-medium ${getActionColor(log.action)}`}>
          {log.action}
        </span>
      ),
    },
    {
      key: 'resource',
      label: 'Resource',
      width: 'w-24',
      render: (log) => <span className="text-slate-300">{log.resource}</span>,
    },
    {
      key: 'resourceId',
      label: 'Resource ID',
      width: 'w-24',
      render: (log) => (
        <span className="text-slate-500 font-mono text-[8px]">
          {log.resourceId ? log.resourceId.slice(0, 8) + '...' : '—'}
        </span>
      ),
    },
    {
      key: 'details',
      label: 'Details',
      render: (log) => (
        <span className="text-slate-400 truncate text-[9px]">
          {log.details ? JSON.stringify(log.details).slice(0, 50) : '—'}
        </span>
      ),
    },
    {
      key: 'ipAddress',
      label: 'IP',
      width: 'w-24',
      render: (log) => <span className="text-slate-500 font-mono">{log.ipAddress || '—'}</span>,
    },
  ];

  return (
    <PageLayout
      title="Logs"
      description="System audit logs and activity history."
      stats={stats}
    >
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search logs...' }}
        filters={[
          {
            key: 'action',
            value: filterAction,
            onChange: setFilterAction,
            options: [{ value: 'all', label: 'All Actions' }, ...actions.map(a => ({ value: a, label: a }))],
          },
          {
            key: 'resource',
            value: filterResource,
            onChange: setFilterResource,
            options: [{ value: 'all', label: 'All Resources' }, ...resources.map(r => ({ value: r, label: r }))],
          },
        ]}
        info={`${filtered.length} entries`}
      />

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1">
          <DataTable
            columns={columns}
            data={filtered}
            loading={isLoading}
            emptyIcon="📋"
            emptyTitle="No logs found"
            emptyDescription="Audit logs will appear here as actions are performed."
            onRowClick={setSelectedLog}
            selectedId={selectedLog?.id}
          />
        </div>

        {/* Detail panel */}
        {selectedLog && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] flex flex-col overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">Log Detail</span>
                <button onClick={() => setSelectedLog(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
            </div>
            <div className="px-4 py-3 space-y-3">
              <DetailRow label="Timestamp" value={new Date(selectedLog.createdAt).toLocaleString()} />
              <DetailRow label="Action" value={selectedLog.action} />
              <DetailRow label="Resource" value={selectedLog.resource} />
              <DetailRow label="Resource ID" value={selectedLog.resourceId || '—'} />
              <DetailRow label="User ID" value={selectedLog.userId?.slice(0, 8) + '...' || '—'} />
              <DetailRow label="IP Address" value={selectedLog.ipAddress || '—'} />
              <div>
                <p className="text-[9px] text-slate-500 mb-1">Details</p>
                <pre className="text-[8px] text-slate-300 bg-[#0a0e1a] rounded p-2 overflow-x-auto border border-[#1e293b]/50">
                  {JSON.stringify(selectedLog.details, null, 2)}
                </pre>
              </div>
            </div>
          </aside>
        )}
      </div>
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <p className="text-[8px] text-slate-500">{label}</p>
      <p className="text-[9px] text-white font-mono">{value}</p>
    </div>
  );
}

function getActionColor(action: string): string {
  switch (action) {
    case 'login': return 'text-blue-400 bg-blue-500/10';
    case 'create': return 'text-emerald-400 bg-emerald-500/10';
    case 'update': return 'text-yellow-400 bg-yellow-500/10';
    case 'delete': return 'text-red-400 bg-red-500/10';
    case 'execute_command': return 'text-purple-400 bg-purple-500/10';
    case 'acknowledge': return 'text-cyan-400 bg-cyan-500/10';
    default: return 'text-slate-400 bg-slate-500/10';
  }
}

import { useState } from 'react';
import { useJobs, useJobStats } from '../hooks/useApi';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../lib/api';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { DataTable, Column } from '../components/ui/DataTable';
import { Modal } from '../components/ui/Modal';

export function Schedules() {
  const [searchQuery, setSearchQuery] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [newSchedule, setNewSchedule] = useState({ name: '', type: 'maintenance', scheduledAt: '' });

  const queryClient = useQueryClient();
  const { data: jobsData, isLoading } = useJobs();
  const { data: jobStats } = useJobStats();

  const jobs = Array.isArray(jobsData) ? jobsData : [];
  // Show scheduled/pending jobs as "schedules"
  const schedules = jobs.filter((j: any) => j.scheduledAt || j.status === 'pending');

  const filtered = schedules.filter((s: any) =>
    !searchQuery || s.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const createSchedule = useMutation({
    mutationFn: (data: any) => fetch('/api/v1/jobs', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${localStorage.getItem('auth_token')}` },
      body: JSON.stringify(data),
    }).then(r => r.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['jobs'] });
      notify.success('Schedule created');
      setShowCreateModal(false);
      setNewSchedule({ name: '', type: 'maintenance', scheduledAt: '' });
    },
    onError: (err: any) => notify.error(err.message || 'Failed to create schedule'),
  });

  const stats = [
    { label: 'Total Schedules', value: String(schedules.length) },
    { label: 'Pending', value: String(jobStats?.pending || 0) },
    { label: 'Running', value: String(jobStats?.running || 0), color: 'text-cyan-400' },
    { label: 'Completed', value: String(jobStats?.completed || 0), color: 'text-emerald-400' },
  ];

  const columns: Column<any>[] = [
    {
      key: 'name',
      label: 'Schedule Name',
      render: (item) => <span className="text-white font-medium">{item.name}</span>,
    },
    {
      key: 'type',
      label: 'Type',
      width: 'w-28',
      render: (item) => (
        <span className="text-[8px] px-1.5 py-0.5 rounded text-slate-300 bg-[#1e293b]">{item.type}</span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      width: 'w-24',
      align: 'center',
      render: (item) => (
        <span className={`text-[8px] px-1.5 py-0.5 rounded ${
          item.status === 'pending' ? 'text-yellow-400 bg-yellow-500/10' :
          item.status === 'running' ? 'text-cyan-400 bg-cyan-500/10' :
          item.status === 'completed' ? 'text-emerald-400 bg-emerald-500/10' :
          'text-red-400 bg-red-500/10'
        }`}>{item.status}</span>
      ),
    },
    {
      key: 'scheduledAt',
      label: 'Scheduled For',
      width: 'w-36',
      render: (item) => (
        <span className="text-slate-400 text-[9px]">
          {item.scheduledAt ? new Date(item.scheduledAt).toLocaleString() : '—'}
        </span>
      ),
    },
    {
      key: 'progress',
      label: 'Progress',
      width: 'w-20',
      align: 'center',
      render: (item) => <span className="text-white">{item.progress || 0}%</span>,
    },
  ];

  return (
    <PageLayout
      title="Schedules"
      description="Manage scheduled jobs and automated tasks."
      stats={stats}
      actions={
        <button
          onClick={() => setShowCreateModal(true)}
          className="px-3 py-1.5 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20"
        >
          + New Schedule
        </button>
      }
    >
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search schedules...' }}
        info={`${filtered.length} schedules`}
      />

      <DataTable
        columns={columns}
        data={filtered}
        loading={isLoading}
        emptyIcon="📅"
        emptyTitle="No schedules"
        emptyDescription="Create a scheduled job to automate recurring tasks."
      />

      {/* Create Modal */}
      <Modal open={showCreateModal} onClose={() => setShowCreateModal(false)} title="Create Schedule">
        <div className="space-y-4 p-4">
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Name *</label>
            <input
              type="text"
              value={newSchedule.name}
              onChange={(e) => setNewSchedule(prev => ({ ...prev, name: e.target.value }))}
              placeholder="e.g. Daily Backup"
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600"
            />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Type</label>
            <select
              value={newSchedule.type}
              onChange={(e) => setNewSchedule(prev => ({ ...prev, type: e.target.value }))}
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none"
            >
              <option value="maintenance">Maintenance</option>
              <option value="backup">Backup</option>
              <option value="firmware_update">Firmware Update</option>
              <option value="security_scan">Security Scan</option>
              <option value="diagnostics">Diagnostics</option>
            </select>
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Scheduled At</label>
            <input
              type="datetime-local"
              value={newSchedule.scheduledAt}
              onChange={(e) => setNewSchedule(prev => ({ ...prev, scheduledAt: e.target.value }))}
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none"
            />
          </div>
          <div className="flex gap-2 pt-2">
            <button
              onClick={() => {
                if (!newSchedule.name) { notify.error('Name required'); return; }
                createSchedule.mutate({
                  name: newSchedule.name,
                  type: newSchedule.type,
                  scheduledAt: newSchedule.scheduledAt || undefined,
                });
              }}
              disabled={createSchedule.isPending}
              className="flex-1 py-2 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20 disabled:opacity-50"
            >
              {createSchedule.isPending ? 'Creating...' : 'Create'}
            </button>
            <button onClick={() => setShowCreateModal(false)} className="flex-1 py-2 rounded-md text-[10px] font-medium bg-[#1e293b]/50 border border-[#1e293b] text-slate-300">
              Cancel
            </button>
          </div>
        </div>
      </Modal>
    </PageLayout>
  );
}

import { useState } from 'react';
import { useDeviceStats, useAlerts, useJobStats, useTelemetryAggregated } from '../hooks/useApi';
import { exportToCSV, exportToJSON } from '../lib/export';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';

export function Reports() {
  const [activeReport, setActiveReport] = useState<string>('fleet');

  const { data: deviceStats } = useDeviceStats();
  const { data: alertsData } = useAlerts();
  const { data: jobStats } = useJobStats();
  const { data: telemetryAgg } = useTelemetryAggregated();

  const alerts = Array.isArray(alertsData) ? alertsData : [];

  const reportTypes = [
    { id: 'fleet', icon: '📊', label: 'Fleet Overview', description: 'Device status and health summary' },
    { id: 'alerts', icon: '🔔', label: 'Alert Report', description: 'Alert history and statistics' },
    { id: 'performance', icon: '⚡', label: 'Performance', description: 'Resource usage and trends' },
    { id: 'jobs', icon: '📋', label: 'Job Report', description: 'Job execution history' },
  ];

  const handleExportCSV = () => {
    const data = getReportData();
    if (data.length > 0) {
      exportToCSV(data, `report-${activeReport}-${Date.now()}`);
      notify.success('Report exported as CSV');
    } else {
      notify.error('No data to export');
    }
  };

  const handleExportJSON = () => {
    const data = getReportData();
    if (data.length > 0) {
      exportToJSON(data, `report-${activeReport}-${Date.now()}`);
      notify.success('Report exported as JSON');
    } else {
      notify.error('No data to export');
    }
  };

  const getReportData = () => {
    switch (activeReport) {
      case 'alerts':
        return alerts.map((a: any) => ({
          title: a.title,
          severity: a.severity,
          status: a.status,
          source: a.source,
          createdAt: a.createdAt,
        }));
      case 'fleet':
        return [{ ...deviceStats }];
      default:
        return [];
    }
  };

  return (
    <PageLayout
      title="Reports"
      description="Generate and export reports from your fleet data."
      actions={
        <div className="flex items-center gap-2">
          <button onClick={handleExportCSV} className="px-3 py-1.5 rounded-md text-[10px] font-medium bg-[#1e293b]/50 border border-[#1e293b] text-slate-300 hover:bg-[#1e293b]">
            📥 Export CSV
          </button>
          <button onClick={handleExportJSON} className="px-3 py-1.5 rounded-md text-[10px] font-medium bg-[#1e293b]/50 border border-[#1e293b] text-slate-300 hover:bg-[#1e293b]">
            📥 Export JSON
          </button>
        </div>
      }
    >
      <div className="flex-1 flex overflow-hidden">
        {/* Left: Report types */}
        <div className="w-56 border-r border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
          <div className="p-3 space-y-1">
            <p className="text-[9px] text-slate-500 font-medium uppercase mb-2">Report Types</p>
            {reportTypes.map((report) => (
              <button
                key={report.id}
                onClick={() => setActiveReport(report.id)}
                className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-left transition-colors ${
                  activeReport === report.id
                    ? 'bg-[#1e293b] border border-[#334155] text-white'
                    : 'text-slate-400 hover:text-white hover:bg-[#1e293b]/50 border border-transparent'
                }`}
              >
                <span className="text-sm">{report.icon}</span>
                <div>
                  <p className="text-[9px] font-medium">{report.label}</p>
                  <p className="text-[7px] text-slate-500">{report.description}</p>
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Right: Report content */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {activeReport === 'fleet' && (
            <>
              <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
                <h3 className="text-[11px] font-semibold text-white mb-3">Fleet Status Summary</h3>
                <div className="grid grid-cols-4 gap-3">
                  {[
                    { label: 'Total Devices', value: deviceStats?.total || 0, color: 'text-white' },
                    { label: 'Online', value: deviceStats?.online || 0, color: 'text-emerald-400' },
                    { label: 'Offline', value: deviceStats?.offline || 0, color: 'text-red-400' },
                    { label: 'Error', value: deviceStats?.error || 0, color: 'text-orange-400' },
                  ].map((item) => (
                    <div key={item.label} className="rounded-lg border border-[#1e293b] bg-[#0a0e1a] p-3 text-center">
                      <p className="text-[8px] text-slate-500">{item.label}</p>
                      <p className={`text-xl font-bold ${item.color}`}>{item.value}</p>
                    </div>
                  ))}
                </div>
              </div>
              {telemetryAgg && (
                <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
                  <h3 className="text-[11px] font-semibold text-white mb-3">Resource Usage (Fleet Average)</h3>
                  <div className="grid grid-cols-3 gap-4">
                    {[
                      { label: 'CPU Usage', value: `${telemetryAgg.cpu?.toFixed(1)}%`, pct: telemetryAgg.cpu },
                      { label: 'Memory Usage', value: `${telemetryAgg.memory?.toFixed(1)}%`, pct: telemetryAgg.memory },
                      { label: 'Disk Usage', value: `${telemetryAgg.disk?.toFixed(1)}%`, pct: telemetryAgg.disk },
                    ].map((item) => (
                      <div key={item.label}>
                        <div className="flex items-center justify-between mb-1">
                          <span className="text-[9px] text-slate-400">{item.label}</span>
                          <span className="text-[9px] text-white font-medium">{item.value}</span>
                        </div>
                        <div className="h-2 rounded-full bg-[#1e293b]">
                          <div
                            className={`h-full rounded-full ${(item.pct || 0) > 80 ? 'bg-red-400' : (item.pct || 0) > 60 ? 'bg-yellow-400' : 'bg-cyan-400'}`}
                            style={{ width: `${Math.min(item.pct || 0, 100)}%` }}
                          />
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </>
          )}

          {activeReport === 'alerts' && (
            <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
              <h3 className="text-[11px] font-semibold text-white mb-3">Alert Summary ({alerts.length} total)</h3>
              <div className="grid grid-cols-4 gap-3 mb-4">
                {[
                  { label: 'Active', value: alerts.filter((a: any) => a.status === 'active').length, color: 'text-yellow-400' },
                  { label: 'Acknowledged', value: alerts.filter((a: any) => a.status === 'acknowledged').length, color: 'text-blue-400' },
                  { label: 'Resolved', value: alerts.filter((a: any) => a.status === 'resolved').length, color: 'text-emerald-400' },
                  { label: 'Critical', value: alerts.filter((a: any) => a.severity === 'critical').length, color: 'text-red-400' },
                ].map((item) => (
                  <div key={item.label} className="rounded-lg border border-[#1e293b] bg-[#0a0e1a] p-3 text-center">
                    <p className="text-[8px] text-slate-500">{item.label}</p>
                    <p className={`text-xl font-bold ${item.color}`}>{item.value}</p>
                  </div>
                ))}
              </div>
              {/* Alert list */}
              <div className="space-y-1">
                {alerts.slice(0, 10).map((alert: any) => (
                  <div key={alert.id} className="flex items-center gap-2 px-2 py-1.5 rounded border border-[#1e293b]/30 bg-[#0a0e1a]/50">
                    <span className={`w-2 h-2 rounded-full ${
                      alert.severity === 'critical' ? 'bg-red-400' : alert.severity === 'warning' ? 'bg-yellow-400' : 'bg-blue-400'
                    }`} />
                    <span className="text-[9px] text-white flex-1">{alert.title}</span>
                    <span className={`text-[8px] px-1.5 py-0.5 rounded ${
                      alert.status === 'active' ? 'text-yellow-400 bg-yellow-500/10' :
                      alert.status === 'resolved' ? 'text-emerald-400 bg-emerald-500/10' :
                      'text-blue-400 bg-blue-500/10'
                    }`}>{alert.status}</span>
                    <span className="text-[8px] text-slate-500">{new Date(alert.createdAt).toLocaleDateString()}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeReport === 'performance' && telemetryAgg && (
            <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
              <h3 className="text-[11px] font-semibold text-white mb-3">Performance Metrics</h3>
              <div className="space-y-3">
                {[
                  { label: 'Average CPU', value: telemetryAgg.cpu?.toFixed(1) + '%' },
                  { label: 'Average Memory', value: telemetryAgg.memory?.toFixed(1) + '%' },
                  { label: 'Average Disk', value: telemetryAgg.disk?.toFixed(1) + '%' },
                  { label: 'Average Temperature', value: telemetryAgg.temperature?.toFixed(1) + '°C' },
                  { label: 'Network In', value: telemetryAgg.networkIn?.toFixed(0) + ' KB/s' },
                  { label: 'Network Out', value: telemetryAgg.networkOut?.toFixed(0) + ' KB/s' },
                ].map((item) => (
                  <div key={item.label} className="flex items-center justify-between py-2 border-b border-[#1e293b]/30">
                    <span className="text-[10px] text-slate-400">{item.label}</span>
                    <span className="text-[10px] text-white font-medium">{item.value}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeReport === 'jobs' && (
            <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
              <h3 className="text-[11px] font-semibold text-white mb-3">Job Statistics</h3>
              <div className="grid grid-cols-5 gap-3">
                {[
                  { label: 'Total', value: jobStats?.total || 0, color: 'text-white' },
                  { label: 'Pending', value: jobStats?.pending || 0, color: 'text-yellow-400' },
                  { label: 'Running', value: jobStats?.running || 0, color: 'text-cyan-400' },
                  { label: 'Completed', value: jobStats?.completed || 0, color: 'text-emerald-400' },
                  { label: 'Failed', value: jobStats?.failed || 0, color: 'text-red-400' },
                ].map((item) => (
                  <div key={item.label} className="rounded-lg border border-[#1e293b] bg-[#0a0e1a] p-3 text-center">
                    <p className="text-[8px] text-slate-500">{item.label}</p>
                    <p className={`text-xl font-bold ${item.color}`}>{item.value}</p>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </PageLayout>
  );
}

import { useState } from 'react';
import { useUsers, useUserStats } from '../hooks/useApi';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { DataTable, Column } from '../components/ui/DataTable';

export function Users() {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterRole, setFilterRole] = useState('all');
  const [selectedUser, setSelectedUser] = useState<any>(null);

  const { data: usersData, isLoading } = useUsers();
  const { data: userStats } = useUserStats();

  const users = Array.isArray(usersData) ? usersData : [];

  const filtered = users.filter((u: any) => {
    if (filterRole !== 'all' && u.role !== filterRole) return false;
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      return u.email?.toLowerCase().includes(q) || u.displayName?.toLowerCase().includes(q) || u.username?.toLowerCase().includes(q);
    }
    return true;
  });

  const stats = [
    { label: 'Total Users', value: String(userStats?.total || users.length) },
    { label: 'Active', value: String(userStats?.active || 0), color: 'text-emerald-400' },
    { label: 'Admins', value: String(userStats?.admins || 0) },
    { label: 'Operators', value: String(userStats?.operators || 0) },
  ];

  const columns: Column<any>[] = [
    {
      key: 'displayName',
      label: 'Name',
      render: (user) => (
        <div>
          <p className="text-white font-medium">{user.displayName}</p>
          <p className="text-[8px] text-slate-500">@{user.username}</p>
        </div>
      ),
    },
    {
      key: 'email',
      label: 'Email',
      render: (user) => <span className="text-slate-400">{user.email}</span>,
    },
    {
      key: 'role',
      label: 'Role',
      width: 'w-28',
      align: 'center',
      render: (user) => (
        <span className={`text-[8px] px-1.5 py-0.5 rounded ${getRoleColor(user.role)}`}>
          {user.role}
        </span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      width: 'w-20',
      align: 'center',
      render: (user) => (
        <span className={`text-[8px] px-1.5 py-0.5 rounded ${
          user.status === 'active' ? 'text-emerald-400 bg-emerald-500/10' :
          user.status === 'suspended' ? 'text-red-400 bg-red-500/10' :
          'text-slate-400 bg-slate-500/10'
        }`}>{user.status}</span>
      ),
    },
    {
      key: 'lastLogin',
      label: 'Last Login',
      width: 'w-32',
      render: (user) => (
        <span className="text-slate-500 text-[9px]">
          {user.lastLogin ? new Date(user.lastLogin).toLocaleString() : 'Never'}
        </span>
      ),
    },
  ];

  return (
    <PageLayout title="Users" description="Manage platform users and access." stats={stats}>
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search users...' }}
        filters={[
          {
            key: 'role',
            value: filterRole,
            onChange: setFilterRole,
            options: [
              { value: 'all', label: 'All Roles' },
              { value: 'super_admin', label: 'Super Admin' },
              { value: 'admin', label: 'Admin' },
              { value: 'operator', label: 'Operator' },
              { value: 'viewer', label: 'Viewer' },
            ],
          },
        ]}
        info={`${filtered.length} users`}
      />

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1">
          <DataTable
            columns={columns}
            data={filtered}
            loading={isLoading}
            emptyIcon="👤"
            emptyTitle="No users found"
            onRowClick={setSelectedUser}
            selectedId={selectedUser?.id}
          />
        </div>

        {selectedUser && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedUser.displayName}</span>
                <button onClick={() => setSelectedUser(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
              <p className="text-[9px] text-slate-500">@{selectedUser.username}</p>
            </div>
            <div className="px-4 py-3 space-y-2">
              <DetailRow label="Email" value={selectedUser.email} />
              <DetailRow label="Role" value={selectedUser.role} />
              <DetailRow label="Status" value={selectedUser.status} />
              <DetailRow label="Last Login" value={selectedUser.lastLogin ? new Date(selectedUser.lastLogin).toLocaleString() : 'Never'} />
              <DetailRow label="Created" value={new Date(selectedUser.createdAt).toLocaleDateString()} />
            </div>
          </aside>
        )}
      </div>
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white">{value}</span>
    </div>
  );
}

function getRoleColor(role: string): string {
  switch (role) {
    case 'super_admin': return 'text-red-400 bg-red-500/10';
    case 'admin': return 'text-purple-400 bg-purple-500/10';
    case 'operator': return 'text-cyan-400 bg-cyan-500/10';
    case 'viewer': return 'text-slate-400 bg-slate-500/10';
    default: return 'text-slate-400 bg-slate-500/10';
  }
}

import { useState } from 'react';
import { useTenants, useTenantStats } from '../hooks/useApi';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { DataTable, Column } from '../components/ui/DataTable';

