      label: 'Plan',
      width: 'w-24',
      align: 'center',
      render: (t) => (
        <span className={`text-[8px] px-1.5 py-0.5 rounded ${
          t.plan === 'enterprise' ? 'text-purple-400 bg-purple-500/10' :
          t.plan === 'pro' ? 'text-cyan-400 bg-cyan-500/10' :
          'text-slate-400 bg-slate-500/10'
        }`}>{t.plan}</span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      width: 'w-20',
      align: 'center',
      render: (t) => (
        <span className={`text-[8px] px-1.5 py-0.5 rounded ${
          t.status === 'active' ? 'text-emerald-400 bg-emerald-500/10' :
          t.status === 'trial' ? 'text-yellow-400 bg-yellow-500/10' :
          'text-red-400 bg-red-500/10'
        }`}>{t.status}</span>
      ),
    },
    {
      key: 'maxDevices',
      label: 'Max Devices',
      width: 'w-24',
      align: 'center',
      render: (t) => <span className="text-white">{t.maxDevices}</span>,
    },
    {
      key: 'maxUsers',
      label: 'Max Users',
      width: 'w-20',
      align: 'center',
      render: (t) => <span className="text-white">{t.maxUsers}</span>,
    },
  ];

  return (
    <PageLayout title="Tenants" description="Multi-tenant management." stats={stats}>
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search tenants...' }}
        info={`${filtered.length} tenants`}
      />

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1">
          <DataTable
            columns={columns}
            data={filtered}
            loading={isLoading}
            emptyIcon="🏢"
            emptyTitle="No tenants"
            onRowClick={setSelectedTenant}
            selectedId={selectedTenant?.id}
          />
        </div>

        {selectedTenant && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedTenant.name}</span>
                <button onClick={() => setSelectedTenant(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
            </div>
            <div className="px-4 py-3 space-y-2">
              <DetailRow label="ID" value={selectedTenant.id?.slice(0, 8) + '...'} />
              <DetailRow label="Slug" value={selectedTenant.slug} />
              <DetailRow label="Domain" value={selectedTenant.domain || '—'} />
              <DetailRow label="Plan" value={selectedTenant.plan} />
              <DetailRow label="Status" value={selectedTenant.status} />
              <DetailRow label="Max Devices" value={String(selectedTenant.maxDevices)} />
              <DetailRow label="Max Users" value={String(selectedTenant.maxUsers)} />
              <DetailRow label="Created" value={new Date(selectedTenant.createdAt).toLocaleDateString()} />
            </div>
          </aside>
        )}
      </div>
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white font-mono">{value}</span>
    </div>
  );
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../lib/api';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { Modal } from '../components/ui/Modal';
import { ConfirmDialog } from '../components/ui/ConfirmDialog';
import { TableSkeleton } from '../components/ui/LoadingState';
import { EmptyState } from '../components/ui/EmptyState';

export function RolesPermissions() {
  const [selectedRole, setSelectedRole] = useState<any>(null);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<any>(null);
  const [newRole, setNewRole] = useState({ name: '', description: '', permissions: '' });

  const queryClient = useQueryClient();

  const { data: rolesData, isLoading } = useQuery({
    queryKey: ['admin', 'roles'],
    queryFn: () => api.adminGetRoles(),
  });

  const roles = Array.isArray(rolesData) ? rolesData : [];

  const createRole = useMutation({
    mutationFn: (data: any) => api.adminCreateRole(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin', 'roles'] });
      notify.success('Role created');
      setShowCreateModal(false);
      setNewRole({ name: '', description: '', permissions: '' });
    },
    onError: (err: any) => notify.error(err.message || 'Failed to create role'),
  });

  const deleteRole = useMutation({
    mutationFn: (id: string) => api.adminDeleteRole(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin', 'roles'] });
      notify.success('Role deleted');
      setDeleteTarget(null);
      if (selectedRole?.id === deleteTarget?.id) setSelectedRole(null);
    },
    onError: (err: any) => notify.error(err.message || 'Failed to delete role'),
  });

  const handleCreate = () => {
    if (!newRole.name.trim()) { notify.error('Role name required'); return; }
    const permissions = newRole.permissions.split(',').map(p => p.trim()).filter(Boolean);
    createRole.mutate({ name: newRole.name, description: newRole.description, permissions });
  };

  return (
    <PageLayout
      title="Roles & Permissions"
      description="Manage access control roles and their permissions."
      stats={[{ label: 'Total Roles', value: String(roles.length) }]}
      actions={
        <button
          onClick={() => setShowCreateModal(true)}
          className="px-3 py-1.5 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20"
        >
          + Create Role
        </button>
      }
    >
      <div className="flex-1 flex overflow-hidden">
        {/* Roles list */}
        <div className="flex-1 overflow-y-auto">
          {isLoading ? (
            <TableSkeleton rows={4} />
          ) : roles.length === 0 ? (
            <EmptyState icon="🔐" title="No roles" description="Create roles to manage access control." />
          ) : (
            <div className="p-4 space-y-2">
              {roles.map((role: any) => (
                <div
                  key={role.id}
                  onClick={() => setSelectedRole(role)}
                  className={`flex items-center gap-3 px-4 py-3 rounded-lg border cursor-pointer transition-colors ${
                    selectedRole?.id === role.id
                      ? 'bg-cyan-500/5 border-cyan-500/20'
                      : 'border-[#1e293b] hover:bg-[#1e293b]/30'
                  }`}
                >
                  <div className="w-8 h-8 rounded-lg bg-[#1e293b] flex items-center justify-center text-sm">
                    {role.isSystem ? '🔒' : '🔑'}
                  </div>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <p className="text-[10px] font-medium text-white">{role.name}</p>
                      {role.isSystem && (
                        <span className="text-[7px] px-1 py-0.5 rounded bg-slate-500/10 text-slate-400">System</span>
                      )}
                    </div>
                    <p className="text-[8px] text-slate-500">{role.description || 'No description'}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-[9px] text-slate-400">{Array.isArray(role.permissions) ? role.permissions.length : 0} permissions</p>
                  </div>
                  {!role.isSystem && (
                    <button
                      onClick={(e) => { e.stopPropagation(); setDeleteTarget(role); }}
                      className="text-slate-500 hover:text-red-400 text-[9px] px-1"
                    >
                      🗑️
                    </button>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Detail panel */}
        {selectedRole && (
          <aside className="w-80 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedRole.name}</span>
                <button onClick={() => setSelectedRole(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
              <p className="text-[9px] text-slate-500 mt-1">{selectedRole.description}</p>
            </div>
            <div className="px-4 py-3">
              <h4 className="text-[10px] font-semibold text-slate-500 uppercase mb-2">Permissions</h4>
              <div className="space-y-1">
                {Array.isArray(selectedRole.permissions) && selectedRole.permissions.map((perm: string, i: number) => (
                  <div key={i} className="flex items-center gap-2 px-2 py-1.5 rounded bg-[#111827] border border-[#1e293b]/50">
                    <span className="text-[9px] text-emerald-400">✓</span>
                    <span className="text-[9px] text-slate-300 font-mono">{perm}</span>
                  </div>
                ))}
                {(!selectedRole.permissions || selectedRole.permissions.length === 0) && (
                  <p className="text-[9px] text-slate-500">No permissions assigned</p>
                )}
              </div>
            </div>
          </aside>
        )}
      </div>

      {/* Create Modal */}
      <Modal open={showCreateModal} onClose={() => setShowCreateModal(false)} title="Create Role">
        <div className="space-y-4 p-4">
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Role Name *</label>
            <input
              type="text"
              value={newRole.name}
              onChange={(e) => setNewRole(prev => ({ ...prev, name: e.target.value }))}
              placeholder="e.g. Device Manager"
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600"
            />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Description</label>
            <input
              type="text"
              value={newRole.description}
              onChange={(e) => setNewRole(prev => ({ ...prev, description: e.target.value }))}
              placeholder="Role description"
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600"
            />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Permissions (comma-separated)</label>
            <input
              type="text"
              value={newRole.permissions}
              onChange={(e) => setNewRole(prev => ({ ...prev, permissions: e.target.value }))}
              placeholder="devices:read, devices:update, alerts:read"
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600"
            />
          </div>
          <div className="flex gap-2 pt-2">
            <button onClick={handleCreate} disabled={createRole.isPending} className="flex-1 py-2 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20 disabled:opacity-50">
              {createRole.isPending ? 'Creating...' : 'Create Role'}
            </button>
            <button onClick={() => setShowCreateModal(false)} className="flex-1 py-2 rounded-md text-[10px] font-medium bg-[#1e293b]/50 border border-[#1e293b] text-slate-300">
              Cancel
            </button>
          </div>
        </div>
      </Modal>

      <ConfirmDialog
        open={!!deleteTarget}
        onClose={() => setDeleteTarget(null)}
        onConfirm={() => deleteTarget && deleteRole.mutate(deleteTarget.id)}
        title="Delete Role"
        message={`Delete role "${deleteTarget?.name}"? This cannot be undone.`}
        confirmLabel="Delete"
        loading={deleteRole.isPending}
      />
    </PageLayout>
  );
}

import { useState } from 'react';
import { useDevices } from '../hooks/useApi';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { EmptyState } from '../components/ui/EmptyState';
import { Modal } from '../components/ui/Modal';

interface Template {
  id: string;
  name: string;
  description: string;
  type: string;
  commands: string[];
  createdAt: string;
}

export function Templates() {
  const [searchQuery, setSearchQuery] = useState('');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [templates, setTemplates] = useState<Template[]>([
    { id: '1', name: 'Health Check', description: 'Run health diagnostics on device', type: 'diagnostics', commands: ['uptime', 'df -h', 'free -m'], createdAt: new Date().toISOString() },
    { id: '2', name: 'Security Audit', description: 'Check security compliance', type: 'security', commands: ['ufw status', 'fail2ban-client status'], createdAt: new Date().toISOString() },
    { id: '3', name: 'Log Rotation', description: 'Rotate and compress logs', type: 'maintenance', commands: ['logrotate -f /etc/logrotate.conf'], createdAt: new Date().toISOString() },
  ]);
  const [newTemplate, setNewTemplate] = useState({ name: '', description: '', type: 'custom', commands: '' });
  const [selectedTemplate, setSelectedTemplate] = useState<Template | null>(null);

  const { data: devicesResponse } = useDevices({ limit: 5 });
  const devices = devicesResponse?.data || [];

  const filtered = templates.filter(t =>
    !searchQuery || t.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleCreate = () => {
    if (!newTemplate.name.trim()) { notify.error('Template name required'); return; }
    const template: Template = {
      id: String(Date.now()),
      name: newTemplate.name,
      description: newTemplate.description,
      type: newTemplate.type,
      commands: newTemplate.commands.split('\n').filter(Boolean),
      createdAt: new Date().toISOString(),
    };
    setTemplates(prev => [...prev, template]);
    notify.success('Template created');
    setShowCreateModal(false);
    setNewTemplate({ name: '', description: '', type: 'custom', commands: '' });
  };

  const handleDelete = (id: string) => {
    setTemplates(prev => prev.filter(t => t.id !== id));
    if (selectedTemplate?.id === id) setSelectedTemplate(null);
    notify.success('Template deleted');
  };

  return (
    <PageLayout
      title="Templates"
      description="Command templates for batch device operations."
      stats={[
        { label: 'Total Templates', value: String(templates.length) },
        { label: 'Available Devices', value: String(devices.length) },
      ]}
      actions={
        <button onClick={() => setShowCreateModal(true)} className="px-3 py-1.5 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20">
          + New Template
        </button>
      }
    >
      <FilterBar search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search templates...' }} info={`${filtered.length} templates`} />

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1 overflow-y-auto p-4">
          {filtered.length === 0 ? (
            <EmptyState icon="📝" title="No templates" description="Create command templates for quick device operations." />
          ) : (
            <div className="grid grid-cols-2 gap-3">
              {filtered.map((template) => (
                <div
                  key={template.id}
                  onClick={() => setSelectedTemplate(template)}
                  className={`rounded-lg border p-4 cursor-pointer transition-colors ${
                    selectedTemplate?.id === template.id ? 'border-cyan-500/30 bg-cyan-500/5' : 'border-[#1e293b] bg-[#111827]/60 hover:bg-[#1e293b]/30'
                  }`}
                >
                  <div className="flex items-center justify-between mb-2">
                    <h4 className="text-[10px] font-medium text-white">{template.name}</h4>
                    <span className="text-[8px] px-1.5 py-0.5 rounded bg-[#1e293b] text-slate-400">{template.type}</span>
                  </div>
                  <p className="text-[8px] text-slate-500 mb-2">{template.description}</p>
                  <div className="space-y-0.5">
                    {template.commands.slice(0, 3).map((cmd, i) => (
                      <p key={i} className="text-[8px] text-slate-400 font-mono bg-[#0a0e1a] px-2 py-0.5 rounded">$ {cmd}</p>
                    ))}
                    {template.commands.length > 3 && (
                      <p className="text-[7px] text-slate-500">+{template.commands.length - 3} more commands</p>
                    )}
                  </div>
                  <div className="flex items-center justify-between mt-3">
                    <span className="text-[7px] text-slate-600">{new Date(template.createdAt).toLocaleDateString()}</span>
                    <button
                      onClick={(e) => { e.stopPropagation(); handleDelete(template.id); }}
                      className="text-[8px] text-slate-500 hover:text-red-400"
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {selectedTemplate && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedTemplate.name}</span>
                <button onClick={() => setSelectedTemplate(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
              <p className="text-[9px] text-slate-500 mt-1">{selectedTemplate.description}</p>
            </div>
            <div className="px-4 py-3">
              <h4 className="text-[10px] font-semibold text-slate-500 uppercase mb-2">Commands</h4>
              <div className="space-y-1">
                {selectedTemplate.commands.map((cmd, i) => (
                  <div key={i} className="px-2 py-1.5 rounded bg-[#0a0e1a] border border-[#1e293b]/50">
                    <span className="text-[9px] text-cyan-400 font-mono">$ {cmd}</span>
                  </div>
                ))}
              </div>
            </div>
          </aside>
        )}
      </div>

      <Modal open={showCreateModal} onClose={() => setShowCreateModal(false)} title="Create Template">
        <div className="space-y-4 p-4">
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Name *</label>
            <input type="text" value={newTemplate.name} onChange={(e) => setNewTemplate(p => ({ ...p, name: e.target.value }))} placeholder="Template name" className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600" />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Description</label>
            <input type="text" value={newTemplate.description} onChange={(e) => setNewTemplate(p => ({ ...p, description: e.target.value }))} placeholder="What does this template do?" className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600" />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Type</label>
            <select value={newTemplate.type} onChange={(e) => setNewTemplate(p => ({ ...p, type: e.target.value }))} className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none">
              <option value="custom">Custom</option>
              <option value="diagnostics">Diagnostics</option>
              <option value="maintenance">Maintenance</option>
              <option value="security">Security</option>
              <option value="deployment">Deployment</option>
            </select>
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Commands (one per line)</label>
            <textarea value={newTemplate.commands} onChange={(e) => setNewTemplate(p => ({ ...p, commands: e.target.value }))} placeholder="uptime&#10;df -h&#10;free -m" rows={4} className="w-full px-3 py-2 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600 font-mono resize-none" />
          </div>
          <div className="flex gap-2">
            <button onClick={handleCreate} className="flex-1 py-2 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20">Create</button>
            <button onClick={() => setShowCreateModal(false)} className="flex-1 py-2 rounded-md text-[10px] font-medium bg-[#1e293b]/50 border border-[#1e293b] text-slate-300">Cancel</button>
          </div>
        </div>
      </Modal>
    </PageLayout>
  );
}

import { useState } from 'react';
import { useDeviceStats, useGroups } from '../hooks/useApi';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { EmptyState } from '../components/ui/EmptyState';
import { Modal } from '../components/ui/Modal';
import { ConfirmDialog } from '../components/ui/ConfirmDialog';

interface Policy {
  id: string;
  name: string;
  description: string;
  type: 'security' | 'compliance' | 'performance' | 'maintenance';
  status: 'active' | 'inactive' | 'draft';
  rules: string[];
  targetGroups: string[];
  createdAt: string;
}

export function Policies() {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState('all');
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<Policy | null>(null);
  const [selectedPolicy, setSelectedPolicy] = useState<Policy | null>(null);
  const [policies, setPolicies] = useState<Policy[]>([
    { id: '1', name: 'Security Baseline', description: 'Minimum security requirements for all devices', type: 'security', status: 'active', rules: ['Firewall enabled', 'Auto-updates enabled', 'SSH key auth only', 'No root login'], targetGroups: ['All Devices'], createdAt: new Date().toISOString() },
    { id: '2', name: 'Performance Monitoring', description: 'Alert when resources exceed thresholds', type: 'performance', status: 'active', rules: ['CPU > 90% for 5min', 'Memory > 85%', 'Disk > 90%', 'Temperature > 80°C'], targetGroups: ['Production'], createdAt: new Date().toISOString() },
    { id: '3', name: 'Backup Policy', description: 'Automated backup schedule', type: 'maintenance', status: 'active', rules: ['Daily config backup', 'Weekly full backup', 'Retain 30 days'], targetGroups: ['Production', 'Development'], createdAt: new Date().toISOString() },
    { id: '4', name: 'Compliance Check', description: 'Regulatory compliance verification', type: 'compliance', status: 'draft', rules: ['Check encryption at rest', 'Verify access logs', 'Audit user permissions'], targetGroups: ['Production'], createdAt: new Date().toISOString() },
  ]);
  const [newPolicy, setNewPolicy] = useState({ name: '', description: '', type: 'security' as const, rules: '' });

  const { data: deviceStats } = useDeviceStats();
  const { data: groupsData } = useGroups();
  const groups = Array.isArray(groupsData) ? groupsData : [];

  const filtered = policies.filter(p => {
    if (filterType !== 'all' && p.type !== filterType) return false;
    if (searchQuery) return p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return true;
  });

  const handleCreate = () => {
    if (!newPolicy.name.trim()) { notify.error('Policy name required'); return; }
    const policy: Policy = {
      id: String(Date.now()),
      name: newPolicy.name,
      description: newPolicy.description,
      type: newPolicy.type,
      status: 'draft',
      rules: newPolicy.rules.split('\n').filter(Boolean),
      targetGroups: [],
      createdAt: new Date().toISOString(),
    };
    setPolicies(prev => [...prev, policy]);
    notify.success('Policy created');
    setShowCreateModal(false);
    setNewPolicy({ name: '', description: '', type: 'security', rules: '' });
  };

  const handleDelete = () => {
    if (!deleteTarget) return;
    setPolicies(prev => prev.filter(p => p.id !== deleteTarget.id));
    if (selectedPolicy?.id === deleteTarget.id) setSelectedPolicy(null);
    setDeleteTarget(null);
    notify.success('Policy deleted');
  };

  const toggleStatus = (id: string) => {
    setPolicies(prev => prev.map(p =>
      p.id === id ? { ...p, status: p.status === 'active' ? 'inactive' : 'active' } : p
    ));
    notify.success('Policy status updated');
  };

  const typeColors: Record<string, string> = {
    security: 'text-red-400 bg-red-500/10',
    compliance: 'text-purple-400 bg-purple-500/10',
