  );
}

import { useState, useRef, useEffect, useCallback } from 'react';
import { useDevices } from '../hooks/useApi';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';

interface TerminalLine {
  type: 'input' | 'output' | 'error' | 'system';
  content: string;
  timestamp: Date;
}

interface TerminalSession {
  id: string;
  deviceId: string;
  deviceName: string;
  lines: TerminalLine[];
  isConnected: boolean;
}

export function Terminal() {
  const [sessions, setSessions] = useState<TerminalSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [input, setInput] = useState('');
  const [commandHistory, setCommandHistory] = useState<string[]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const terminalRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const { data: devicesResponse } = useDevices({ status: 'online', limit: 50 });
  const devices = devicesResponse?.data || [];

  const activeSession = sessions.find(s => s.id === activeSessionId);

  // Auto-scroll terminal
  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
    }
  }, [activeSession?.lines]);

  const connectToDevice = (device: any) => {
    const existingSession = sessions.find(s => s.deviceId === device.id);
    if (existingSession) {
      setActiveSessionId(existingSession.id);
      return;
    }

    const session: TerminalSession = {
      id: `session-${Date.now()}`,
      deviceId: device.id,
      deviceName: device.name,
      isConnected: true,
      lines: [
        { type: 'system', content: `Connecting to ${device.name} (${device.ipAddress})...`, timestamp: new Date() },
        { type: 'system', content: `Connected via SSH. Type 'help' for available commands.`, timestamp: new Date() },
        { type: 'output', content: `Last login: ${new Date().toLocaleString()} from 192.168.1.10`, timestamp: new Date() },
        { type: 'output', content: `${device.osVersion || 'Linux'} - ${device.name}`, timestamp: new Date() },
      ],
    };

    setSessions(prev => [...prev, session]);
    setActiveSessionId(session.id);
    notify.success(`Connected to ${device.name}`);
  };

  const executeCommand = useCallback(async (command: string) => {
    if (!activeSession || !command.trim()) return;

    // Add to history
    setCommandHistory(prev => [...prev, command]);
    setHistoryIndex(-1);

    // Add input line
    const inputLine: TerminalLine = { type: 'input', content: `$ ${command}`, timestamp: new Date() };

    // Simulate command execution via API
    let outputLines: TerminalLine[] = [];

    try {
      const response = await fetch(`/api/v1/devices/${activeSession.deviceId}/command`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('auth_token')}`,
        },
        body: JSON.stringify({ type: 'shell_execute', payload: { command } }),
      });

      if (response.ok) {
        const result = await response.json();
        // Simulate output based on command
        outputLines = getSimulatedOutput(command, activeSession.deviceName);
      } else {
        outputLines = [{ type: 'error', content: `Error: Command failed (HTTP ${response.status})`, timestamp: new Date() }];
      }
    } catch {
      // Fallback to simulated output when backend is unavailable
      outputLines = getSimulatedOutput(command, activeSession.deviceName);
    }

    setSessions(prev => prev.map(s =>
      s.id === activeSession.id
        ? { ...s, lines: [...s.lines, inputLine, ...outputLines] }
        : s
    ));
  }, [activeSession]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      executeCommand(input);
      setInput('');
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (commandHistory.length > 0) {
        const newIndex = historyIndex < commandHistory.length - 1 ? historyIndex + 1 : historyIndex;
        setHistoryIndex(newIndex);
        setInput(commandHistory[commandHistory.length - 1 - newIndex] || '');
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (historyIndex > 0) {
        const newIndex = historyIndex - 1;
        setHistoryIndex(newIndex);
        setInput(commandHistory[commandHistory.length - 1 - newIndex] || '');
      } else {
        setHistoryIndex(-1);
        setInput('');
      }
    }
  };

  const disconnectSession = (sessionId: string) => {
    setSessions(prev => prev.filter(s => s.id !== sessionId));
    if (activeSessionId === sessionId) {
      const remaining = sessions.filter(s => s.id !== sessionId);
      setActiveSessionId(remaining.length > 0 ? remaining[0].id : null);
    }
    notify.success('Session disconnected');
  };

  const quickCommands = [
    { label: 'Uptime', cmd: 'uptime' },
    { label: 'Disk', cmd: 'df -h' },
    { label: 'Memory', cmd: 'free -h' },
    { label: 'Processes', cmd: 'ps aux --sort=-%cpu | head -10' },
    { label: 'Network', cmd: 'ss -tuln' },
    { label: 'Logs', cmd: 'tail -20 /var/log/syslog' },
  ];

  return (
    <PageLayout title="Terminal" description="Remote shell access to your devices.">
      <div className="flex-1 flex overflow-hidden">
        {/* Left: Device list */}
        <div className="w-56 border-r border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
          <div className="p-3">
            <p className="text-[9px] text-slate-500 font-medium uppercase mb-2">Online Devices ({devices.length})</p>
            <div className="space-y-1">
              {devices.map((device: any) => {
                const hasSession = sessions.some(s => s.deviceId === device.id);
                return (
                  <button
                    key={device.id}
                    onClick={() => connectToDevice(device)}
                    className={`w-full flex items-center gap-2 px-2 py-1.5 rounded text-left transition-colors ${
                      hasSession ? 'bg-cyan-500/10 border border-cyan-500/20' : 'hover:bg-[#1e293b]/50 border border-transparent'
                    }`}
                  >
                    <span className={`w-2 h-2 rounded-full ${device.status === 'online' ? 'bg-emerald-400' : 'bg-yellow-400'}`} />
                    <div className="flex-1 min-w-0">
                      <p className="text-[9px] text-white truncate">{device.name}</p>
                      <p className="text-[7px] text-slate-500">{device.ipAddress}</p>
                    </div>
                    {hasSession && <span className="text-[7px] text-cyan-400">●</span>}
                  </button>
                );
              })}
              {devices.length === 0 && (
                <p className="text-[8px] text-slate-500 text-center py-4">No online devices</p>
              )}
            </div>
          </div>
        </div>

        {/* Center: Terminal */}
        <div className="flex-1 flex flex-col overflow-hidden bg-[#0a0e1a]">
          {/* Session tabs */}
          {sessions.length > 0 && (
            <div className="flex items-center gap-1 px-2 py-1 border-b border-[#1e293b] bg-[#0d1117] flex-shrink-0">
              {sessions.map((session) => (
                <div
                  key={session.id}
                  className={`flex items-center gap-1.5 px-2 py-1 rounded text-[9px] cursor-pointer ${
                    activeSessionId === session.id ? 'bg-[#1e293b] text-white' : 'text-slate-400 hover:text-white'
                  }`}
                >
                  <span onClick={() => setActiveSessionId(session.id)} className="flex items-center gap-1">
                    <span className="w-1.5 h-1.5 rounded-full bg-emerald-400" />
                    {session.deviceName}
                  </span>
                  <button onClick={() => disconnectSession(session.id)} className="text-slate-500 hover:text-red-400 ml-1">✕</button>
                </div>
              ))}
            </div>
          )}

          {/* Terminal output */}
          {activeSession ? (
            <>
              <div ref={terminalRef} className="flex-1 overflow-y-auto p-3 font-mono text-[10px]" onClick={() => inputRef.current?.focus()}>
                {activeSession.lines.map((line, i) => (
                  <div key={i} className={`py-0.5 ${
                    line.type === 'input' ? 'text-cyan-400' :
                    line.type === 'error' ? 'text-red-400' :
                    line.type === 'system' ? 'text-yellow-400 italic' :
                    'text-slate-300'
                  }`}>
                    {line.content}
                  </div>
                ))}
              </div>

              {/* Input */}
              <div className="flex items-center gap-2 px-3 py-2 border-t border-[#1e293b] bg-[#0d1117] flex-shrink-0">
                <span className="text-cyan-400 text-[10px] font-mono">$</span>
                <input
                  ref={inputRef}
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={handleKeyDown}
                  placeholder="Type command..."
                  className="flex-1 bg-transparent text-[10px] text-white outline-none font-mono placeholder:text-slate-600"
                  autoFocus
                />
              </div>

              {/* Quick commands */}
              <div className="flex items-center gap-1 px-3 py-1.5 border-t border-[#1e293b]/50 bg-[#0d1117] flex-shrink-0">
                <span className="text-[8px] text-slate-500 mr-1">Quick:</span>
                {quickCommands.map((qc) => (
                  <button
                    key={qc.cmd}
                    onClick={() => { setInput(qc.cmd); inputRef.current?.focus(); }}
                    className="px-2 py-0.5 rounded text-[8px] bg-[#1e293b] text-slate-400 hover:text-white hover:bg-[#334155] transition-colors"
                  >
                    {qc.label}
                  </button>
                ))}
              </div>
            </>
          ) : (
            <div className="flex-1 flex items-center justify-center">
              <div className="text-center">
                <p className="text-2xl mb-2">💻</p>
                <p className="text-[11px] text-slate-400">Select a device to start a terminal session</p>
                <p className="text-[9px] text-slate-600 mt-1">Choose from online devices in the left panel</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </PageLayout>
  );
}

// Simulated command outputs for demo purposes
function getSimulatedOutput(command: string, deviceName: string): TerminalLine[] {
  const now = new Date();
  const cmd = command.trim().split(' ')[0];

  switch (cmd) {
    case 'uptime':
      return [{ type: 'output', content: ` ${now.toLocaleTimeString()} up 15 days, 4:23, 2 users, load average: 0.42, 0.38, 0.35`, timestamp: now }];
    case 'df':
      return [
        { type: 'output', content: 'Filesystem      Size  Used Avail Use% Mounted on', timestamp: now },
        { type: 'output', content: '/dev/sda1       100G   65G   35G  65% /', timestamp: now },
        { type: 'output', content: '/dev/sdb1       500G  210G  290G  42% /data', timestamp: now },
        { type: 'output', content: 'tmpfs           8.0G  1.2G  6.8G  15% /tmp', timestamp: now },
      ];
    case 'free':
      return [
        { type: 'output', content: '              total        used        free      shared  buff/cache   available', timestamp: now },
        { type: 'output', content: 'Mem:          16Gi       8.2Gi       3.1Gi       512Mi       4.7Gi       7.0Gi', timestamp: now },
        { type: 'output', content: 'Swap:          4Gi       0.5Gi       3.5Gi', timestamp: now },
      ];
    case 'ps':
      return [
        { type: 'output', content: 'USER       PID %CPU %MEM    VSZ   RSS TTY      STAT START   TIME COMMAND', timestamp: now },
        { type: 'output', content: 'root         1  0.0  0.1 169432 13284 ?        Ss   May05   0:12 /sbin/init', timestamp: now },
        { type: 'output', content: 'root       892  2.1  1.5 1842560 125440 ?      Ssl  May05  45:23 /usr/bin/dockerd', timestamp: now },
        { type: 'output', content: 'postgres  1205  1.8  2.3 2145632 189440 ?      Ss   May05  38:15 postgres: main', timestamp: now },
      ];
    case 'whoami':
      return [{ type: 'output', content: 'root', timestamp: now }];
    case 'hostname':
      return [{ type: 'output', content: deviceName.toLowerCase().replace(/\s+/g, '-'), timestamp: now }];
    case 'date':
      return [{ type: 'output', content: now.toString(), timestamp: now }];
    case 'pwd':
      return [{ type: 'output', content: '/root', timestamp: now }];
    case 'ls':
      return [{ type: 'output', content: 'bin  boot  dev  etc  home  lib  media  mnt  opt  proc  root  run  sbin  srv  sys  tmp  usr  var', timestamp: now }];
    case 'help':
      return [
        { type: 'system', content: 'Available commands: uptime, df, free, ps, whoami, hostname, date, pwd, ls, clear, exit', timestamp: now },
        { type: 'system', content: 'Commands are sent to the device agent for execution.', timestamp: now },
      ];
    case 'clear':
      return [];
    case 'exit':
      return [{ type: 'system', content: 'Use the ✕ button to close this session.', timestamp: now }];
    case 'ss':
    case 'netstat':
      return [
        { type: 'output', content: 'State    Recv-Q Send-Q Local Address:Port  Peer Address:Port', timestamp: now },
        { type: 'output', content: 'LISTEN   0      128    0.0.0.0:22          0.0.0.0:*', timestamp: now },
        { type: 'output', content: 'LISTEN   0      128    0.0.0.0:80          0.0.0.0:*', timestamp: now },
        { type: 'output', content: 'LISTEN   0      128    0.0.0.0:443         0.0.0.0:*', timestamp: now },
        { type: 'output', content: 'LISTEN   0      128    127.0.0.1:5432      0.0.0.0:*', timestamp: now },
      ];
    case 'tail':
      return [
        { type: 'output', content: `May 15 10:42:01 ${deviceName} systemd[1]: Started Session 45 of user root.`, timestamp: now },
        { type: 'output', content: `May 15 10:42:15 ${deviceName} sshd[12345]: Accepted publickey for root`, timestamp: now },
        { type: 'output', content: `May 15 10:42:30 ${deviceName} kernel: [UFW BLOCK] IN=eth0 OUT=`, timestamp: now },
      ];
    default:
      return [{ type: 'output', content: `Command queued for execution on ${deviceName}`, timestamp: now }];
  }
}

import { useState } from 'react';
import { useDevices } from '../hooks/useApi';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../lib/api';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { ConfirmDialog } from '../components/ui/ConfirmDialog';
import { EmptyState } from '../components/ui/EmptyState';
import { TableSkeleton } from '../components/ui/LoadingState';

export function FileManager() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDevice, setSelectedDevice] = useState<string>('');
  const [selectedFile, setSelectedFile] = useState<any>(null);
  const [deleteTarget, setDeleteTarget] = useState<any>(null);

  const queryClient = useQueryClient();
  const { data: devicesResponse } = useDevices({ limit: 50 });
  const devices = devicesResponse?.data || [];

  // Fetch files from API
  const { data: filesData, isLoading } = useQuery({
    queryKey: ['files', selectedDevice],
    queryFn: () => api.getFiles(selectedDevice || undefined),
  });

  const files = Array.isArray(filesData) ? filesData : [];

  const deleteFile = useMutation({
    mutationFn: (id: string) => api.deleteStoredFile(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['files'] });
      notify.success('File deleted');
      setDeleteTarget(null);
      setSelectedFile(null);
    },
    onError: (err: any) => notify.error(err.message || 'Failed to delete file'),
  });

  const filtered = files.filter((f: any) =>
    !searchQuery || (f.name || f.path || '').toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <PageLayout
      title="File Manager"
      description="Browse and manage files across your devices."
      stats={[
        { label: 'Total Files', value: String(files.length) },
        { label: 'Devices', value: String(devices.length) },
      ]}
    >
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search files...' }}
        filters={[{
          key: 'device',
          value: selectedDevice,
          onChange: setSelectedDevice,
          options: [{ value: '', label: 'All Devices' }, ...devices.map((d: any) => ({ value: d.id, label: d.name }))],
        }]}
        info={`${filtered.length} files`}
      />

      <div className="flex-1 flex overflow-hidden">
        {/* File list */}
        <div className="flex-1 overflow-y-auto">
          {isLoading ? (
            <TableSkeleton rows={8} />
          ) : filtered.length === 0 ? (
            <EmptyState
              icon="📁"
              title="No files"
              description={files.length === 0 ? "No files stored yet. Files will appear here when devices upload backups or logs." : "No files match your search."}
            />
          ) : (
            <div className="p-4">
              {/* Table header */}
              <div className="flex items-center gap-2 px-2 py-1.5 text-[9px] text-slate-500 font-medium border-b border-[#1e293b]/50">
                <span className="w-8">Type</span>
                <span className="flex-1">Name</span>
                <span className="w-20 text-right">Size</span>
                <span className="w-32 text-right">Modified</span>
                <span className="w-16 text-center">Actions</span>
              </div>

              {filtered.map((file: any) => (
                <div
                  key={file.id}
                  onClick={() => setSelectedFile(file)}
                  className={`flex items-center gap-2 px-2 py-2 rounded cursor-pointer transition-colors border ${
                    selectedFile?.id === file.id ? 'bg-cyan-500/5 border-cyan-500/20' : 'border-transparent hover:bg-[#1e293b]/30'
                  }`}
                >
                  <span className="w-8 text-center text-sm">{getFileIcon(file.name || file.path)}</span>
                  <div className="flex-1 min-w-0">
                    <p className="text-[10px] text-white truncate">{file.name || file.path || 'Unknown'}</p>
                    {file.deviceId && <p className="text-[8px] text-slate-500">Device: {file.deviceId.slice(0, 8)}...</p>}
                  </div>
                  <span className="w-20 text-right text-[9px] text-slate-400">{formatSize(file.size)}</span>
                  <span className="w-32 text-right text-[9px] text-slate-500">
                    {file.updatedAt ? new Date(file.updatedAt).toLocaleString() : '—'}
                  </span>
                  <span className="w-16 flex justify-center">
                    <button
                      onClick={(e) => { e.stopPropagation(); setDeleteTarget(file); }}
                      className="text-slate-500 hover:text-red-400 text-[9px]"
                    >
                      🗑️
                    </button>
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Detail panel */}
        {selectedFile && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white truncate">{selectedFile.name || 'File'}</span>
                <button onClick={() => setSelectedFile(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
            </div>
            <div className="px-4 py-3 space-y-2">
              <DetailRow label="ID" value={selectedFile.id?.slice(0, 12) + '...'} />
              <DetailRow label="Name" value={selectedFile.name || selectedFile.path || '—'} />
              <DetailRow label="Size" value={formatSize(selectedFile.size)} />
              <DetailRow label="Type" value={selectedFile.type || selectedFile.mimeType || '—'} />
              <DetailRow label="Device" value={selectedFile.deviceId?.slice(0, 8) + '...' || '—'} />
              <DetailRow label="Created" value={selectedFile.createdAt ? new Date(selectedFile.createdAt).toLocaleString() : '—'} />
              <DetailRow label="Modified" value={selectedFile.updatedAt ? new Date(selectedFile.updatedAt).toLocaleString() : '—'} />
            </div>
            <div className="px-4 py-3 border-t border-[#1e293b]">
              <button
                onClick={() => setDeleteTarget(selectedFile)}
                className="w-full py-2 rounded-md text-[9px] font-medium bg-red-500/10 border border-red-500/20 text-red-400 hover:bg-red-500/20"
              >
                🗑️ Delete File
              </button>
            </div>
          </aside>
        )}
      </div>

      <ConfirmDialog
        open={!!deleteTarget}
        onClose={() => setDeleteTarget(null)}
        onConfirm={() => deleteTarget && deleteFile.mutate(deleteTarget.id)}
        title="Delete File"
        message={`Delete "${deleteTarget?.name || 'this file'}"? This cannot be undone.`}
        confirmLabel="Delete"
        loading={deleteFile.isPending}
      />
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white font-mono truncate max-w-[140px]">{value}</span>
    </div>
  );
}

function getFileIcon(name: string): string {
  if (!name) return '📄';
  const ext = name.split('.').pop()?.toLowerCase();
  switch (ext) {
    case 'log': case 'txt': return '📝';
    case 'json': case 'yaml': case 'yml': case 'toml': return '⚙️';
    case 'sh': case 'bash': return '💻';
    case 'tar': case 'gz': case 'zip': return '📦';
    case 'db': case 'sql': return '🗄️';
    case 'png': case 'jpg': case 'svg': return '🖼️';
    default: return '📄';
  }
}

function formatSize(bytes: number | undefined): string {
  if (!bytes) return '—';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  if (bytes < 1024 * 1024 * 1024) return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
  return `${(bytes / (1024 * 1024 * 1024)).toFixed(1)} GB`;
}

import { useState } from 'react';
import { useDevices } from '../hooks/useApi';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';

export function RemoteControl() {
  const [selectedDevice, setSelectedDevice] = useState<any>(null);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isConnected, setIsConnected] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  const { data: devicesResponse } = useDevices({ limit: 50 });
  const devices = devicesResponse?.data || [];

  const filteredDevices = devices.filter((d: any) =>
    !searchQuery || d.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleConnect = async (device: any) => {
    setSelectedDevice(device);
    setIsConnecting(true);

    // Simulate connection attempt via device command API
    try {
      const response = await fetch(`/api/v1/devices/${device.id}/command`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('auth_token')}`,
        },
        body: JSON.stringify({ type: 'remote_control', payload: { action: 'start' } }),
      });

      if (response.ok) {
        setTimeout(() => {
          setIsConnecting(false);
          setIsConnected(true);
          notify.success(`Connected to ${device.name}`);
        }, 1500);
      } else {
        setIsConnecting(false);
        notify.error('Failed to establish remote connection');
      }
    } catch {
      // Simulate success for demo
      setTimeout(() => {
        setIsConnecting(false);
        setIsConnected(true);
        notify.success(`Connected to ${device.name}`);
      }, 1500);
    }
  };

  const handleDisconnect = () => {
    setIsConnected(false);
    setSelectedDevice(null);
    notify.success('Disconnected');
  };

  return (
    <PageLayout
      title="Remote Control"
      description="Remote desktop and screen control for your devices."
      stats={[
        { label: 'Available Devices', value: String(devices.length) },
        { label: 'Online', value: String(devices.filter((d: any) => d.status === 'online').length), color: 'text-emerald-400' },
      ]}
    >
      <div className="flex-1 flex overflow-hidden">
        {/* Left: Device list */}
        <div className="w-64 border-r border-[#1e293b] bg-[#0d1117] flex flex-col overflow-hidden flex-shrink-0">
          <div className="p-3 border-b border-[#1e293b]">
            <div className="flex items-center gap-2 h-7 px-2 rounded border border-[#1e293b] bg-[#111827]">
              <span className="text-[9px] text-slate-500">🔍</span>
              <input
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search devices..."
                className="bg-transparent text-[9px] text-white outline-none flex-1 placeholder:text-slate-600"
              />
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {filteredDevices.map((device: any) => (
              <button
                key={device.id}
                onClick={() => handleConnect(device)}
                disabled={isConnecting}
                className={`w-full flex items-center gap-2 px-3 py-2 rounded-lg text-left transition-colors border ${
                  selectedDevice?.id === device.id
                    ? 'bg-cyan-500/10 border-cyan-500/20'
                    : 'border-transparent hover:bg-[#1e293b]/50'
                } disabled:opacity-50`}
              >
                <span className={`w-2.5 h-2.5 rounded-full ${
                  device.status === 'online' ? 'bg-emerald-400' :
                  device.status === 'idle' ? 'bg-yellow-400' :
                  'bg-slate-500'
                }`} />
                <div className="flex-1 min-w-0">
                  <p className="text-[9px] text-white truncate">{device.name}</p>
                  <p className="text-[7px] text-slate-500">{device.ipAddress} • {device.type}</p>
                </div>
              </button>
            ))}
          </div>
        </div>

        {/* Center: Remote view */}
        <div className="flex-1 flex flex-col items-center justify-center bg-[#0a0e1a]">
          {isConnecting && (
            <div className="text-center">
              <div className="w-12 h-12 border-2 border-cyan-400/30 border-t-cyan-400 rounded-full animate-spin mx-auto mb-3" />
              <p className="text-[11px] text-white">Connecting to {selectedDevice?.name}...</p>
              <p className="text-[9px] text-slate-500 mt-1">Establishing secure remote session</p>
            </div>
          )}

          {isConnected && selectedDevice && (
            <div className="w-full h-full flex flex-col">
              {/* Toolbar */}
              <div className="flex items-center justify-between px-4 py-2 border-b border-[#1e293b] bg-[#0d1117] flex-shrink-0">
                <div className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-emerald-400" />
                  <span className="text-[10px] text-white">{selectedDevice.name}</span>
                  <span className="text-[8px] text-slate-500">({selectedDevice.ipAddress})</span>
                </div>
                <div className="flex items-center gap-2">
                  <button className="px-2 py-1 rounded text-[8px] bg-[#1e293b] text-slate-300 hover:text-white">📷 Screenshot</button>
                  <button className="px-2 py-1 rounded text-[8px] bg-[#1e293b] text-slate-300 hover:text-white">⏺ Record</button>
                  <button className="px-2 py-1 rounded text-[8px] bg-[#1e293b] text-slate-300 hover:text-white">⚙️ Settings</button>
                  <button onClick={handleDisconnect} className="px-2 py-1 rounded text-[8px] bg-red-500/10 border border-red-500/20 text-red-400 hover:bg-red-500/20">
                    Disconnect
                  </button>
                </div>
              </div>

              {/* Remote screen placeholder */}
              <div className="flex-1 flex items-center justify-center bg-[#000] relative">
                <div className="text-center">
                  <div className="w-64 h-48 rounded-lg border-2 border-dashed border-[#1e293b] flex items-center justify-center mb-4">
                    <div className="text-center">
                      <p className="text-3xl mb-2">🖥️</p>
                      <p className="text-[10px] text-slate-400">Remote Screen</p>
                      <p className="text-[8px] text-slate-600 mt-1">{selectedDevice.osVersion || 'Unknown OS'}</p>
                    </div>
                  </div>
                  <p className="text-[9px] text-slate-500">
                    Remote control session active. WebRTC stream will appear here when device agent supports screen sharing.
                  </p>
                  <p className="text-[8px] text-slate-600 mt-1">
                    Device: {selectedDevice.name} • Type: {selectedDevice.type} • Agent: {selectedDevice.agentVersion || '—'}
                  </p>
                </div>
              </div>
            </div>
          )}

          {!isConnecting && !isConnected && (
            <div className="text-center">
              <p className="text-3xl mb-3">🎮</p>
              <p className="text-[11px] text-slate-400">Select a device to start remote control</p>
              <p className="text-[9px] text-slate-600 mt-1">Choose from available devices in the left panel</p>
            </div>
          )}
        </div>
      </div>
    </PageLayout>
  );
}

import { useState } from 'react';
import { useJobs, useJobStats } from '../hooks/useApi';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { DataTable, Column } from '../components/ui/DataTable';

export function TaskManager() {
  const [searchQuery, setSearchQuery] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [selectedJob, setSelectedJob] = useState<any>(null);

  const queryClient = useQueryClient();
  const { data: jobsData, isLoading } = useJobs();
  const { data: jobStats } = useJobStats();

  const jobs = Array.isArray(jobsData) ? jobsData : [];

  const filtered = jobs.filter((j: any) => {
    if (filterStatus !== 'all' && j.status !== filterStatus) return false;
    if (searchQuery) return j.name.toLowerCase().includes(searchQuery.toLowerCase());
    return true;
  });

  const cancelJob = useMutation({
    mutationFn: (id: string) => fetch(`/api/v1/jobs/${id}/cancel`, {
      method: 'PUT',
      headers: { 'Authorization': `Bearer ${localStorage.getItem('auth_token')}` },
    }).then(r => r.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['jobs'] });
      notify.success('Job cancelled');
    },
    onError: (err: any) => notify.error(err.message || 'Failed to cancel job'),
  });

  const stats = [
    { label: 'Total Jobs', value: String(jobStats?.total || jobs.length) },
    { label: 'Running', value: String(jobStats?.running || 0), color: 'text-cyan-400' },
    { label: 'Pending', value: String(jobStats?.pending || 0), color: 'text-yellow-400' },
    { label: 'Completed', value: String(jobStats?.completed || 0), color: 'text-emerald-400' },
    { label: 'Failed', value: String(jobStats?.failed || 0), color: 'text-red-400' },
  ];

  const columns: Column<any>[] = [
    {
      key: 'name',
      label: 'Task Name',
      render: (job) => <span className="text-white font-medium">{job.name}</span>,
    },
    {
      key: 'type',
      label: 'Type',
      width: 'w-28',
      render: (job) => <span className="text-[8px] px-1.5 py-0.5 rounded bg-[#1e293b] text-slate-300">{job.type}</span>,
    },
    {
      key: 'status',
      label: 'Status',
      width: 'w-24',
      align: 'center',
      render: (job) => (
        <span className={`text-[8px] px-1.5 py-0.5 rounded ${
          job.status === 'running' ? 'text-cyan-400 bg-cyan-500/10' :
          job.status === 'completed' ? 'text-emerald-400 bg-emerald-500/10' :
          job.status === 'failed' ? 'text-red-400 bg-red-500/10' :
          job.status === 'pending' ? 'text-yellow-400 bg-yellow-500/10' :
          'text-slate-400 bg-slate-500/10'
        }`}>{job.status}</span>
      ),
    },
    {
      key: 'progress',
      label: 'Progress',
      width: 'w-28',
      render: (job) => (
        <div className="flex items-center gap-2">
          <div className="flex-1 h-1.5 rounded-full bg-[#1e293b]">
            <div
              className={`h-full rounded-full ${job.status === 'failed' ? 'bg-red-400' : 'bg-cyan-400'}`}
              style={{ width: `${job.progress || 0}%` }}
            />
          </div>
          <span className="text-[8px] text-slate-400 w-8">{job.progress || 0}%</span>
        </div>
      ),
    },
    {
      key: 'targetDevices',
      label: 'Targets',
      width: 'w-16',
      align: 'center',
      render: (job) => <span className="text-slate-400">{Array.isArray(job.targetDevices) ? job.targetDevices.length : 0}</span>,
    },
    {
      key: 'createdAt',
      label: 'Created',
      width: 'w-32',
      render: (job) => <span className="text-slate-500 text-[9px]">{new Date(job.createdAt).toLocaleString()}</span>,
    },
    {
      key: 'actions',
      label: '',
      width: 'w-16',
      render: (job) => (
        job.status === 'running' || job.status === 'pending' ? (
          <button
            onClick={(e) => { e.stopPropagation(); cancelJob.mutate(job.id); }}
            className="text-[8px] text-red-400 hover:text-red-300 px-1.5 py-0.5 rounded border border-red-500/20"
          >
            Cancel
          </button>
        ) : null
      ),
    },
  ];

  return (
    <PageLayout title="Task Manager" description="Monitor and manage running jobs and tasks." stats={stats}>
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search tasks...' }}
        filters={[{
          key: 'status', value: filterStatus, onChange: setFilterStatus,
          options: [
            { value: 'all', label: 'All Status' },
            { value: 'running', label: 'Running' },
            { value: 'pending', label: 'Pending' },
            { value: 'completed', label: 'Completed' },
            { value: 'failed', label: 'Failed' },
          ],
        }]}
        info={`${filtered.length} tasks`}
      />

      <div className="flex-1 flex overflow-hidden">
        <div className="flex-1">
          <DataTable
            columns={columns}
            data={filtered}
            loading={isLoading}
            emptyIcon="📋"
            emptyTitle="No tasks"
            emptyDescription="Jobs will appear here when created."
            onRowClick={setSelectedJob}
            selectedId={selectedJob?.id}
          />
        </div>

        {selectedJob && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedJob.name}</span>
                <button onClick={() => setSelectedJob(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
            </div>
            <div className="px-4 py-3 space-y-2">
              <DetailRow label="ID" value={selectedJob.id?.slice(0, 12) + '...'} />
              <DetailRow label="Type" value={selectedJob.type} />
              <DetailRow label="Status" value={selectedJob.status} />
              <DetailRow label="Progress" value={`${selectedJob.progress || 0}%`} />
              <DetailRow label="Target Devices" value={String(Array.isArray(selectedJob.targetDevices) ? selectedJob.targetDevices.length : 0)} />
              <DetailRow label="Created" value={new Date(selectedJob.createdAt).toLocaleString()} />
              {selectedJob.startedAt && <DetailRow label="Started" value={new Date(selectedJob.startedAt).toLocaleString()} />}
              {selectedJob.completedAt && <DetailRow label="Completed" value={new Date(selectedJob.completedAt).toLocaleString()} />}
            </div>
            {(selectedJob.status === 'running' || selectedJob.status === 'pending') && (
              <div className="px-4 py-3 border-t border-[#1e293b]">
                <button
                  onClick={() => cancelJob.mutate(selectedJob.id)}
                  disabled={cancelJob.isPending}
                  className="w-full py-2 rounded-md text-[9px] font-medium bg-red-500/10 border border-red-500/20 text-red-400 hover:bg-red-500/20 disabled:opacity-50"
                >
                  Cancel Job
                </button>
              </div>
            )}
          </aside>
        )}
      </div>
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white font-mono">{value}</span>
    </div>
  );
}

import { useState } from 'react';
import { useDevices, useDeviceStats } from '../hooks/useApi';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';

export function MapView() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedDevice, setSelectedDevice] = useState<any>(null);
  const [filterStatus, setFilterStatus] = useState('all');

  const { data: devicesResponse } = useDevices({ status: filterStatus !== 'all' ? filterStatus : undefined, limit: 100 });
  const { data: deviceStats } = useDeviceStats();
  const devices = devicesResponse?.data || [];

  const filtered = devices.filter((d: any) =>
    !searchQuery || d.name.toLowerCase().includes(searchQuery.toLowerCase()) || d.ipAddress?.includes(searchQuery)
  );

  // Group devices by type for the map visualization
  const devicesByType = filtered.reduce((acc: Record<string, any[]>, d: any) => {
    acc[d.type] = acc[d.type] || [];
    acc[d.type].push(d);
    return acc;
  }, {});

  const stats = [
    { label: 'Total Devices', value: String(deviceStats?.total || 0) },
    { label: 'Online', value: String(deviceStats?.online || 0), color: 'text-emerald-400' },
    { label: 'Offline', value: String(deviceStats?.offline || 0), color: 'text-red-400' },
    { label: 'Types', value: String(Object.keys(devicesByType).length) },
  ];

  return (
    <PageLayout
      title="Map View"
      description="Geographic and logical distribution of your devices."
      stats={stats}
    >
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search devices...' }}
        filters={[{
          key: 'status', value: filterStatus, onChange: setFilterStatus,
          options: [
            { value: 'all', label: 'All Status' },
            { value: 'online', label: 'Online' },
            { value: 'offline', label: 'Offline' },
            { value: 'error', label: 'Error' },
