            <h3 className="text-[10px] font-semibold text-white mb-3">Device Distribution by Type</h3>
            <div className="grid grid-cols-5 gap-3">
              {Object.entries(devicesByType).map(([type, devs]) => {
                const online = (devs as any[]).filter(d => d.status === 'online').length;
                return (
                  <div key={type} className="rounded-lg border border-[#1e293b] bg-[#0a0e1a] p-3 text-center">
