          </div>

          {/* Network topology visualization */}
          <div className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
            <h3 className="text-[10px] font-semibold text-white mb-3">Network Map</h3>
            <div className="relative h-64 rounded bg-[#0a0e1a] border border-[#1e293b]/30 overflow-hidden">
