              <div className="absolute inset-0 p-4">
                <div className="grid grid-cols-6 gap-3 h-full">
                  {filtered.slice(0, 18).map((device: any, i: number) => (
                    <button
                      key={device.id}
                      onClick={() => setSelectedDevice(device)}
                      className={`flex flex-col items-center justify-center rounded-lg border transition-all hover:scale-105 ${
                        selectedDevice?.id === device.id
                          ? 'border-cyan-500/50 bg-cyan-500/10'
                          : 'border-[#1e293b] bg-[#111827]/80 hover:border-[#334155]'
                      }`}
                    >
                      <span className={`w-3 h-3 rounded-full mb-1 ${
                        device.status === 'online' ? 'bg-emerald-400' :
                        device.status === 'error' ? 'bg-red-400' :
                        device.status === 'busy' ? 'bg-orange-400' :
                        'bg-slate-500'
                      }`} />
                      <p className="text-[7px] text-slate-300 truncate w-full text-center px-1">{device.name.split(' ')[0]}</p>
                      <p className="text-[6px] text-slate-500">{device.ipAddress}</p>
                    </button>
                  ))}
                </div>
              </div>
            </div>
            {filtered.length > 18 && (
              <p className="text-[8px] text-slate-500 mt-2">Showing 18 of {filtered.length} devices</p>
            )}
          </div>
        </div>

        {/* Right: Device detail */}
        {selectedDevice && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedDevice.name}</span>
                <button onClick={() => setSelectedDevice(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
              <div className="flex items-center gap-2 mt-1">
                <span className={`w-2 h-2 rounded-full ${selectedDevice.status === 'online' ? 'bg-emerald-400' : 'bg-slate-500'}`} />
                <span className="text-[9px] text-slate-400 capitalize">{selectedDevice.status}</span>
              </div>
            </div>
            <div className="px-4 py-3 space-y-2">
              <DetailRow label="IP Address" value={selectedDevice.ipAddress || '—'} />
              <DetailRow label="Type" value={selectedDevice.type} />
              <DetailRow label="OS" value={selectedDevice.osVersion || '—'} />
              <DetailRow label="Agent" value={selectedDevice.agentVersion || '—'} />
              <DetailRow label="Last Seen" value={selectedDevice.lastSeen ? new Date(selectedDevice.lastSeen).toLocaleString() : '—'} />
              <DetailRow label="Created" value={new Date(selectedDevice.createdAt).toLocaleDateString()} />
            </div>
          </aside>
        )}
      </div>
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white">{value}</span>
    </div>
  );
}

function getTypeIcon(type: string): string {
  switch (type) {
    case 'linux': return '🐧';
    case 'windows': return '🪟';
    case 'macos': return '🍎';
    case 'android': return '📱';
    case 'iot': return '📡';
    case 'raspberry_pi': return '🍓';
    case 'docker_agent': return '🐳';
    case 'vm_agent': return '💻';
    case 'kubernetes_node': return '☸️';
    case 'browser_worker': return '🌐';
    default: return '📟';
  }
}

import { useState } from 'react';
import { useDevices, useDeviceStats, useGroups } from '../hooks/useApi';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';

export function Topology() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedNode, setSelectedNode] = useState<any>(null);
  const [viewMode, setViewMode] = useState<'type' | 'status' | 'group'>('type');

  const { data: devicesResponse } = useDevices({ limit: 100 });
  const { data: deviceStats } = useDeviceStats();
  const { data: groupsData } = useGroups();

  const devices = devicesResponse?.data || [];
  const groups = Array.isArray(groupsData) ? groupsData : [];

  const filtered = devices.filter((d: any) =>
    !searchQuery || d.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Group devices based on view mode
  const groupedDevices = (() => {
    switch (viewMode) {
      case 'type':
        return filtered.reduce((acc: Record<string, any[]>, d: any) => {
          acc[d.type] = acc[d.type] || [];
          acc[d.type].push(d);
          return acc;
        }, {});
      case 'status':
        return filtered.reduce((acc: Record<string, any[]>, d: any) => {
          acc[d.status] = acc[d.status] || [];
          acc[d.status].push(d);
          return acc;
        }, {});
      default:
        return { 'All Devices': filtered };
    }
  })();

  const stats = [
    { label: 'Total Nodes', value: String(deviceStats?.total || 0) },
    { label: 'Online', value: String(deviceStats?.online || 0), color: 'text-emerald-400' },
    { label: 'Groups', value: String(groups.length) },
    { label: 'Types', value: String(Object.keys(groupedDevices).length) },
  ];

  return (
    <PageLayout
      title="Network Topology"
      description="Visualize your device network topology and connections."
      stats={stats}
      actions={
        <div className="flex items-center gap-1">
          {(['type', 'status', 'group'] as const).map((mode) => (
            <button
              key={mode}
              onClick={() => setViewMode(mode)}
              className={`px-2 py-1 rounded text-[9px] ${
                viewMode === mode ? 'bg-[#1e293b] text-white border border-[#334155]' : 'text-slate-400 hover:text-white'
              }`}
            >
              By {mode}
            </button>
          ))}
        </div>
      }
    >
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search nodes...' }}
        info={`${filtered.length} nodes`}
      />

      <div className="flex-1 flex overflow-hidden">
        {/* Topology visualization */}
        <div className="flex-1 overflow-y-auto p-4">
          <div className="space-y-4">
            {/* Central hub */}
            <div className="flex justify-center mb-4">
              <div className="rounded-lg border-2 border-cyan-500/30 bg-cyan-500/5 px-6 py-3 text-center">
                <p className="text-sm">🌐</p>
                <p className="text-[10px] text-white font-medium">Orchestrator</p>
                <p className="text-[8px] text-slate-500">{filtered.length} connected</p>
              </div>
            </div>

            {/* Device groups */}
            {Object.entries(groupedDevices).map(([group, devs]) => (
              <div key={group} className="rounded-lg border border-[#1e293b] bg-[#111827]/60 p-4">
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <span className="text-sm">{getGroupIcon(group)}</span>
                    <h3 className="text-[10px] font-semibold text-white capitalize">{group.replace('_', ' ')}</h3>
                    <span className="text-[8px] text-slate-500">({(devs as any[]).length} devices)</span>
                  </div>
                  <div className="flex items-center gap-1">
                    <span className="w-2 h-2 rounded-full bg-emerald-400" />
                    <span className="text-[8px] text-slate-400">
                      {(devs as any[]).filter(d => d.status === 'online').length} online
                    </span>
                  </div>
                </div>

                <div className="grid grid-cols-6 gap-2">
                  {(devs as any[]).map((device: any) => (
                    <button
                      key={device.id}
                      onClick={() => setSelectedNode(device)}
                      className={`flex flex-col items-center p-2 rounded-lg border transition-all ${
                        selectedNode?.id === device.id
                          ? 'border-cyan-500/50 bg-cyan-500/10'
                          : 'border-[#1e293b] hover:border-[#334155] hover:bg-[#1e293b]/30'
                      }`}
                    >
                      <span className={`w-3 h-3 rounded-full mb-1 ${
                        device.status === 'online' ? 'bg-emerald-400' :
                        device.status === 'error' ? 'bg-red-400 animate-pulse' :
                        device.status === 'busy' ? 'bg-orange-400' :
                        device.status === 'idle' ? 'bg-yellow-400' :
                        'bg-slate-500'
                      }`} />
                      <p className="text-[8px] text-slate-300 truncate w-full text-center">{device.name.split(' ')[0]}</p>
                      <p className="text-[7px] text-slate-500">{device.ipAddress}</p>
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Detail panel */}
        {selectedNode && (
          <aside className="w-72 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedNode.name}</span>
                <button onClick={() => setSelectedNode(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
              <div className="flex items-center gap-2 mt-1">
                <span className={`w-2 h-2 rounded-full ${selectedNode.status === 'online' ? 'bg-emerald-400' : 'bg-slate-500'}`} />
                <span className="text-[9px] text-slate-400 capitalize">{selectedNode.status}</span>
              </div>
            </div>
            <div className="px-4 py-3 space-y-2">
              <DetailRow label="IP Address" value={selectedNode.ipAddress || '—'} />
              <DetailRow label="Type" value={selectedNode.type} />
              <DetailRow label="OS" value={selectedNode.osVersion || '—'} />
              <DetailRow label="Agent Version" value={selectedNode.agentVersion || '—'} />
              <DetailRow label="Last Seen" value={selectedNode.lastSeen ? new Date(selectedNode.lastSeen).toLocaleString() : '—'} />
              <DetailRow label="Last Heartbeat" value={selectedNode.lastHeartbeat ? new Date(selectedNode.lastHeartbeat).toLocaleString() : '—'} />
            </div>
          </aside>
        )}
      </div>
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white">{value}</span>
    </div>
  );
}

function getGroupIcon(group: string): string {
  switch (group) {
    case 'linux': return '🐧';
    case 'windows': return '🪟';
    case 'macos': return '🍎';
    case 'android': return '📱';
    case 'iot': return '📡';
    case 'raspberry_pi': return '🍓';
    case 'docker_agent': return '🐳';
    case 'vm_agent': return '💻';
    case 'kubernetes_node': return '☸️';
    case 'browser_worker': return '🌐';
    case 'online': return '🟢';
    case 'offline': return '🔴';
    case 'error': return '⚠️';
    case 'busy': return '🟠';
    case 'idle': return '🟡';
    case 'maintenance': return '🔧';
    default: return '📟';
  }
}

import { useState } from 'react';
import { useDevices, useGroups } from '../hooks/useApi';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { FilterBar } from '../components/ui/FilterBar';
import { Modal } from '../components/ui/Modal';
import { ConfirmDialog } from '../components/ui/ConfirmDialog';
import { EmptyState } from '../components/ui/EmptyState';

interface Workflow {
  id: string;
  name: string;
  description: string;
  status: 'active' | 'inactive' | 'draft';
  trigger: { type: string; config: string };
  actions: { type: string; command: string }[];
  targetGroups: string[];
  lastRun?: string;
  runCount: number;
  createdAt: string;
}

export function Automation() {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedWorkflow, setSelectedWorkflow] = useState<Workflow | null>(null);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<Workflow | null>(null);
  const [workflows, setWorkflows] = useState<Workflow[]>([
    {
      id: '1', name: 'Daily Health Check', description: 'Run health diagnostics on all production devices every day at 2 AM',
      status: 'active', trigger: { type: 'schedule', config: '0 2 * * *' },
      actions: [{ type: 'command', command: 'health_check.sh' }, { type: 'notify', command: 'email:admin@audira.io' }],
      targetGroups: ['Production'], lastRun: new Date(Date.now() - 120000).toISOString(), runCount: 45, createdAt: new Date(Date.now() - 86400000 * 30).toISOString(),
    },
    {
      id: '2', name: 'Auto Reboot on Failure', description: 'Automatically reboot devices that enter error state',
      status: 'active', trigger: { type: 'event', config: 'device.status === error' },
      actions: [{ type: 'command', command: 'reboot' }, { type: 'alert', command: 'create:warning' }],
      targetGroups: ['All'], lastRun: new Date(Date.now() - 7200000).toISOString(), runCount: 12, createdAt: new Date(Date.now() - 86400000 * 15).toISOString(),
    },
    {
      id: '3', name: 'Backup Configurations', description: 'Backup device configurations every night',
      status: 'active', trigger: { type: 'schedule', config: '0 3 * * *' },
      actions: [{ type: 'command', command: 'backup_config.sh' }, { type: 'command', command: 'upload_to_s3.sh' }],
      targetGroups: ['Production', 'Development'], lastRun: new Date(Date.now() - 3600000).toISOString(), runCount: 90, createdAt: new Date(Date.now() - 86400000 * 60).toISOString(),
    },
    {
      id: '4', name: 'High CPU Alert', description: 'Alert when CPU usage exceeds 90% for 5 minutes',
      status: 'active', trigger: { type: 'threshold', config: 'cpu > 90% for 5m' },
      actions: [{ type: 'alert', command: 'create:critical' }, { type: 'notify', command: 'slack:#alerts' }],
      targetGroups: ['All'], lastRun: new Date(Date.now() - 900000).toISOString(), runCount: 8, createdAt: new Date(Date.now() - 86400000 * 20).toISOString(),
    },
    {
      id: '5', name: 'Log Rotation', description: 'Rotate and compress logs weekly',
      status: 'inactive', trigger: { type: 'schedule', config: '0 4 * * 0' },
      actions: [{ type: 'command', command: 'logrotate -f /etc/logrotate.conf' }],
      targetGroups: ['Production'], lastRun: new Date(Date.now() - 86400000 * 7).toISOString(), runCount: 15, createdAt: new Date(Date.now() - 86400000 * 90).toISOString(),
    },
  ]);

  const [newWorkflow, setNewWorkflow] = useState({
    name: '', description: '', triggerType: 'schedule', triggerConfig: '', actions: '',
  });

  const { data: devicesResponse } = useDevices({ limit: 5 });
  const { data: groupsData } = useGroups();
  const groups = Array.isArray(groupsData) ? groupsData : [];

  const filtered = workflows.filter(w =>
    !searchQuery || w.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleCreate = () => {
    if (!newWorkflow.name.trim()) { notify.error('Workflow name required'); return; }
    const workflow: Workflow = {
      id: String(Date.now()),
      name: newWorkflow.name,
      description: newWorkflow.description,
      status: 'draft',
      trigger: { type: newWorkflow.triggerType, config: newWorkflow.triggerConfig },
      actions: newWorkflow.actions.split('\n').filter(Boolean).map(a => ({ type: 'command', command: a })),
      targetGroups: [],
      runCount: 0,
      createdAt: new Date().toISOString(),
    };
    setWorkflows(prev => [...prev, workflow]);
    notify.success('Workflow created');
    setShowCreateModal(false);
    setNewWorkflow({ name: '', description: '', triggerType: 'schedule', triggerConfig: '', actions: '' });
  };

  const handleDelete = () => {
    if (!deleteTarget) return;
    setWorkflows(prev => prev.filter(w => w.id !== deleteTarget.id));
    if (selectedWorkflow?.id === deleteTarget.id) setSelectedWorkflow(null);
    setDeleteTarget(null);
    notify.success('Workflow deleted');
  };

  const toggleStatus = (id: string) => {
    setWorkflows(prev => prev.map(w =>
      w.id === id ? { ...w, status: w.status === 'active' ? 'inactive' : 'active' } : w
    ));
    notify.success('Workflow status updated');
  };

  const runWorkflow = (workflow: Workflow) => {
    setWorkflows(prev => prev.map(w =>
      w.id === workflow.id ? { ...w, lastRun: new Date().toISOString(), runCount: w.runCount + 1 } : w
    ));
    notify.success(`Running "${workflow.name}"...`);
  };

  const stats = [
    { label: 'Total Workflows', value: String(workflows.length) },
    { label: 'Active', value: String(workflows.filter(w => w.status === 'active').length), color: 'text-emerald-400' },
    { label: 'Inactive', value: String(workflows.filter(w => w.status === 'inactive').length) },
    { label: 'Total Runs', value: String(workflows.reduce((sum, w) => sum + w.runCount, 0)) },
  ];

  const triggerIcons: Record<string, string> = {
    schedule: '⏰',
    event: '⚡',
    threshold: '📊',
    manual: '👆',
  };

  return (
    <PageLayout
      title="Automation"
      description="Create and manage automated workflows for your device fleet."
      stats={stats}
      actions={
        <button onClick={() => setShowCreateModal(true)} className="px-3 py-1.5 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20">
          + New Workflow
        </button>
      }
    >
      <FilterBar
        search={{ value: searchQuery, onChange: setSearchQuery, placeholder: 'Search workflows...' }}
        info={`${filtered.length} workflows`}
      />

      <div className="flex-1 flex overflow-hidden">
        {/* Workflow list */}
        <div className="flex-1 overflow-y-auto p-4">
          {filtered.length === 0 ? (
            <EmptyState icon="⚡" title="No workflows" description="Create automated workflows to manage your devices." />
          ) : (
            <div className="space-y-2">
              {filtered.map((workflow) => (
                <div
                  key={workflow.id}
                  onClick={() => setSelectedWorkflow(workflow)}
                  className={`rounded-lg border p-4 cursor-pointer transition-colors ${
                    selectedWorkflow?.id === workflow.id
                      ? 'border-cyan-500/20 bg-cyan-500/5'
                      : 'border-[#1e293b] bg-[#111827]/60 hover:bg-[#1e293b]/30'
                  }`}
                >
                  <div className="flex items-center justify-between mb-2">
                    <div className="flex items-center gap-2">
                      <span className="text-sm">{triggerIcons[workflow.trigger.type] || '⚙️'}</span>
                      <h4 className="text-[10px] font-medium text-white">{workflow.name}</h4>
                      <span className={`text-[7px] px-1.5 py-0.5 rounded ${
                        workflow.status === 'active' ? 'text-emerald-400 bg-emerald-500/10' :
                        workflow.status === 'draft' ? 'text-yellow-400 bg-yellow-500/10' :
                        'text-slate-400 bg-slate-500/10'
                      }`}>{workflow.status}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <button
                        onClick={(e) => { e.stopPropagation(); runWorkflow(workflow); }}
                        className="text-[8px] px-2 py-0.5 rounded border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/10"
                        title="Run now"
                      >
                        ▶ Run
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); toggleStatus(workflow.id); }}
                        className="text-[8px] px-2 py-0.5 rounded border border-[#1e293b] text-slate-400 hover:text-white"
                      >
                        {workflow.status === 'active' ? 'Disable' : 'Enable'}
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); setDeleteTarget(workflow); }}
                        className="text-slate-500 hover:text-red-400 text-[9px]"
                      >
                        🗑️
                      </button>
                    </div>
                  </div>
                  <p className="text-[8px] text-slate-500 mb-2">{workflow.description}</p>
                  <div className="flex items-center gap-4 text-[8px]">
                    <span className="text-slate-500">Trigger: <span className="text-slate-300">{workflow.trigger.config}</span></span>
                    <span className="text-slate-500">Actions: <span className="text-slate-300">{workflow.actions.length}</span></span>
                    <span className="text-slate-500">Runs: <span className="text-slate-300">{workflow.runCount}</span></span>
                    {workflow.lastRun && (
                      <span className="text-slate-500">Last: <span className="text-slate-300">{getTimeAgo(workflow.lastRun)}</span></span>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Detail panel */}
        {selectedWorkflow && (
          <aside className="w-80 border-l border-[#1e293b] bg-[#0d1117] overflow-y-auto flex-shrink-0">
            <div className="px-4 py-3 border-b border-[#1e293b]">
              <div className="flex items-center justify-between">
                <span className="text-[11px] font-semibold text-white">{selectedWorkflow.name}</span>
                <button onClick={() => setSelectedWorkflow(null)} className="text-slate-500 hover:text-white text-xs">✕</button>
              </div>
              <p className="text-[9px] text-slate-500 mt-1">{selectedWorkflow.description}</p>
            </div>

            <div className="px-4 py-3 border-b border-[#1e293b]">
              <h4 className="text-[10px] font-semibold text-slate-500 uppercase mb-2">Trigger</h4>
              <div className="flex items-center gap-2 px-3 py-2 rounded bg-[#111827] border border-[#1e293b]/50">
                <span className="text-sm">{triggerIcons[selectedWorkflow.trigger.type]}</span>
                <div>
                  <p className="text-[9px] text-white capitalize">{selectedWorkflow.trigger.type}</p>
                  <p className="text-[8px] text-slate-400 font-mono">{selectedWorkflow.trigger.config}</p>
                </div>
              </div>
            </div>

            <div className="px-4 py-3 border-b border-[#1e293b]">
              <h4 className="text-[10px] font-semibold text-slate-500 uppercase mb-2">Actions ({selectedWorkflow.actions.length})</h4>
              <div className="space-y-1.5">
                {selectedWorkflow.actions.map((action, i) => (
                  <div key={i} className="flex items-center gap-2 px-3 py-2 rounded bg-[#111827] border border-[#1e293b]/50">
                    <span className="text-[9px] text-cyan-400 font-bold">{i + 1}</span>
                    <div>
                      <p className="text-[8px] text-slate-500 capitalize">{action.type}</p>
                      <p className="text-[9px] text-white font-mono">{action.command}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="px-4 py-3 border-b border-[#1e293b]">
              <h4 className="text-[10px] font-semibold text-slate-500 uppercase mb-2">Statistics</h4>
              <div className="space-y-1.5">
                <DetailRow label="Status" value={selectedWorkflow.status} />
                <DetailRow label="Total Runs" value={String(selectedWorkflow.runCount)} />
                <DetailRow label="Last Run" value={selectedWorkflow.lastRun ? getTimeAgo(selectedWorkflow.lastRun) : 'Never'} />
                <DetailRow label="Created" value={new Date(selectedWorkflow.createdAt).toLocaleDateString()} />
                <DetailRow label="Target Groups" value={selectedWorkflow.targetGroups.join(', ') || 'None'} />
              </div>
            </div>

            <div className="px-4 py-3 space-y-2">
              <button
                onClick={() => runWorkflow(selectedWorkflow)}
                className="w-full py-2 rounded-md text-[9px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20"
              >
                ▶ Run Now
              </button>
              <button
                onClick={() => setDeleteTarget(selectedWorkflow)}
                className="w-full py-2 rounded-md text-[9px] font-medium bg-red-500/10 border border-red-500/20 text-red-400 hover:bg-red-500/20"
              >
                🗑️ Delete Workflow
              </button>
            </div>
          </aside>
        )}
      </div>

      {/* Create Modal */}
      <Modal open={showCreateModal} onClose={() => setShowCreateModal(false)} title="Create Workflow">
        <div className="space-y-4 p-4">
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Name *</label>
            <input type="text" value={newWorkflow.name} onChange={(e) => setNewWorkflow(p => ({ ...p, name: e.target.value }))} placeholder="e.g. Daily Health Check" className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600" />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Description</label>
            <input type="text" value={newWorkflow.description} onChange={(e) => setNewWorkflow(p => ({ ...p, description: e.target.value }))} placeholder="What does this workflow do?" className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600" />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Trigger Type</label>
            <select value={newWorkflow.triggerType} onChange={(e) => setNewWorkflow(p => ({ ...p, triggerType: e.target.value }))} className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none">
              <option value="schedule">Schedule (Cron)</option>
              <option value="event">Event-based</option>
              <option value="threshold">Threshold</option>
              <option value="manual">Manual</option>
            </select>
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Trigger Config</label>
            <input type="text" value={newWorkflow.triggerConfig} onChange={(e) => setNewWorkflow(p => ({ ...p, triggerConfig: e.target.value }))} placeholder="e.g. 0 2 * * * (cron) or cpu > 90%" className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600 font-mono" />
          </div>
          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Actions (one per line)</label>
            <textarea value={newWorkflow.actions} onChange={(e) => setNewWorkflow(p => ({ ...p, actions: e.target.value }))} placeholder="health_check.sh&#10;notify:admin@company.com" rows={3} className="w-full px-3 py-2 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600 font-mono resize-none" />
          </div>
          <div className="flex gap-2">
            <button onClick={handleCreate} className="flex-1 py-2 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20">Create</button>
            <button onClick={() => setShowCreateModal(false)} className="flex-1 py-2 rounded-md text-[10px] font-medium bg-[#1e293b]/50 border border-[#1e293b] text-slate-300">Cancel</button>
          </div>
        </div>
      </Modal>

      <ConfirmDialog open={!!deleteTarget} onClose={() => setDeleteTarget(null)} onConfirm={handleDelete} title="Delete Workflow" message={`Delete "${deleteTarget?.name}"? This cannot be undone.`} confirmLabel="Delete" />
    </PageLayout>
  );
}

function DetailRow({ label, value }: { label: string; value: string }) {
  return (
    <div className="flex items-center justify-between">
      <span className="text-[9px] text-slate-500">{label}</span>
      <span className="text-[9px] text-white">{value}</span>
    </div>
  );
}

function getTimeAgo(dateStr: string): string {
  const diff = Date.now() - new Date(dateStr).getTime();
  const minutes = Math.floor(diff / 60000);
  if (minutes < 1) return 'Just now';
  if (minutes < 60) return `${minutes}m ago`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  return `${days}d ago`;
}

