    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE device_type AS ENUM ('android', 'linux', 'windows', 'macos', 'iot', 'raspberry_pi', 'browser_worker', 'docker_agent', 'vm_agent', 'kubernetes_node');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE alert_severity AS ENUM ('info', 'warning', 'error', 'critical');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE alert_status AS ENUM ('active', 'acknowledged', 'resolved');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE job_status AS ENUM ('pending', 'running', 'completed', 'failed', 'cancelled');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE user_role AS ENUM ('super_admin', 'tenant_owner', 'admin', 'operator', 'viewer');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE user_status AS ENUM ('active', 'inactive', 'suspended');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE tenant_plan AS ENUM ('free', 'pro', 'enterprise');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

    DO $$ BEGIN
      CREATE TYPE tenant_status AS ENUM ('active', 'suspended', 'trial', 'cancelled');
    EXCEPTION WHEN duplicate_object THEN null; END $$;

