import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import { Server, Socket } from 'socket.io';

@WebSocketGateway({
  cors: {
    origin: '*',
  },
  namespace: '/realtime',
})
export class RealtimeGateway implements OnGatewayConnection, OnGatewayDisconnect {
  @WebSocketServer()
  server!: Server;

  private connectedClients = new Map<string, { userId: string; tenantId: string; rooms: Set<string> }>();

  handleConnection(client: Socket) {
    console.log(`Client connected: ${client.id}`);
    this.connectedClients.set(client.id, {
      userId: 'unknown',
      tenantId: 'unknown',
      rooms: new Set(),
    });
  }

  handleDisconnect(client: Socket) {
    console.log(`Client disconnected: ${client.id}`);
    this.connectedClients.delete(client.id);
  }

  @SubscribeMessage('authenticate')
  handleAuthenticate(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { token: string; tenantId: string },
  ) {
    // TODO: Validate JWT token
    const clientData = this.connectedClients.get(client.id);
    if (clientData) {
      clientData.tenantId = data.tenantId;
      client.join(`tenant:${data.tenantId}`);
    }
    return { event: 'authenticated', data: { success: true } };
  }

  @SubscribeMessage('subscribe:device')
  handleSubscribeDevice(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { deviceId: string },
  ) {
    const room = `device:${data.deviceId}`;
    client.join(room);
    const clientData = this.connectedClients.get(client.id);
    if (clientData) clientData.rooms.add(room);
    return { event: 'subscribed', data: { channel: room } };
  }

  @SubscribeMessage('subscribe:fleet')
  handleSubscribeFleet(@ConnectedSocket() client: Socket) {
    const clientData = this.connectedClients.get(client.id);
    if (clientData) {
      const room = `fleet:${clientData.tenantId}`;
      client.join(room);
      clientData.rooms.add(room);
      return { event: 'subscribed', data: { channel: room } };
    }
    return { event: 'error', data: { message: 'Not authenticated' } };
  }

  @SubscribeMessage('subscribe:alerts')
  handleSubscribeAlerts(@ConnectedSocket() client: Socket) {
    const clientData = this.connectedClients.get(client.id);
    if (clientData) {
      const room = `alerts:${clientData.tenantId}`;
      client.join(room);
      return { event: 'subscribed', data: { channel: room } };
    }
    return { event: 'error', data: { message: 'Not authenticated' } };
  }

  @SubscribeMessage('unsubscribe')
  handleUnsubscribe(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { channel: string },
  ) {
    client.leave(data.channel);
    const clientData = this.connectedClients.get(client.id);
    if (clientData) clientData.rooms.delete(data.channel);
    return { event: 'unsubscribed', data: { channel: data.channel } };
  }

  // Methods to emit events from services
  emitDeviceUpdate(deviceId: string, data: any) {
    this.server.to(`device:${deviceId}`).emit('device:update', data);
  }

  emitFleetEvent(tenantId: string, data: any) {
    this.server.to(`fleet:${tenantId}`).emit('fleet:event', data);
  }

  emitAlert(tenantId: string, alert: any) {
    this.server.to(`alerts:${tenantId}`).emit('alert:new', alert);
  }

  emitCommandResult(deviceId: string, result: any) {
    this.server.to(`device:${deviceId}`).emit('command:result', result);
  }

  emitTelemetry(deviceId: string, metrics: any) {
    this.server.to(`device:${deviceId}`).emit('telemetry:update', metrics);
  }

  getConnectedClientsCount(): number {
    return this.connectedClients.size;
  }
}

