import { Injectable } from '@nestjs/common';
import { PrismaService } from '../../prisma.service';

@Injectable()
export class CommandService {
  constructor(private prisma: PrismaService) {}

  // Alerts
  async getAlerts(tenantId?: string) {
    return this.prisma.alert.findMany({
      where: tenantId ? { tenantId } : undefined,
      include: { device: true },
      orderBy: { createdAt: 'desc' },
      take: 50,
    });
  }

  async getAlertStats(tenantId?: string) {
    const where = tenantId ? { tenantId } : undefined;
    const [total, critical, warning, info, unacknowledged, acknowledged, resolved] = await Promise.all([
      this.prisma.alert.count({ where }),
      this.prisma.alert.count({ where: { ...where, severity: 'critical' } }),
      this.prisma.alert.count({ where: { ...where, severity: 'warning' } }),
      this.prisma.alert.count({ where: { ...where, severity: 'info' } }),
      this.prisma.alert.count({ where: { ...where, status: 'unacknowledged' } }),
      this.prisma.alert.count({ where: { ...where, status: 'acknowledged' } }),
      this.prisma.alert.count({ where: { ...where, status: 'resolved' } }),
    ]);
    return { total, critical, warning, info, unacknowledged, acknowledged, resolved };
  }

  async acknowledgeAlert(id: string) {
    return this.prisma.alert.update({ where: { id }, data: { status: 'acknowledged' } });
  }

  async resolveAlert(id: string) {
    return this.prisma.alert.update({ where: { id }, data: { status: 'resolved' } });
  }

  // Jobs
  async getJobs(tenantId?: string) {
    return this.prisma.job.findMany({
      where: tenantId ? { tenantId } : undefined,
      orderBy: { createdAt: 'desc' },
      take: 50,
    });
  }

  async getJobStats(tenantId?: string) {
    const where = tenantId ? { tenantId } : undefined;
    const [total, running, completed, failed, cancelled] = await Promise.all([
      this.prisma.job.count({ where }),
      this.prisma.job.count({ where: { ...where, status: 'running' } }),
      this.prisma.job.count({ where: { ...where, status: 'completed' } }),
      this.prisma.job.count({ where: { ...where, status: 'failed' } }),
      this.prisma.job.count({ where: { ...where, status: 'cancelled' } }),
    ]);
    const successRate = total > 0 ? ((completed / total) * 100).toFixed(1) : '0';
    return { total, running, completed, failed, cancelled, successRate };
  }

  // Users
  async getUsers(tenantId?: string) {
    return this.prisma.user.findMany({
      where: tenantId ? { tenantId } : undefined,
      include: { tenant: true },
      orderBy: { createdAt: 'desc' },
    });
  }

  async getUserStats(tenantId?: string) {
    const where = tenantId ? { tenantId } : undefined;
    const [total, active, inactive, locked] = await Promise.all([
      this.prisma.user.count({ where }),
      this.prisma.user.count({ where: { ...where, status: 'active' } }),
      this.prisma.user.count({ where: { ...where, status: 'inactive' } }),
      this.prisma.user.count({ where: { ...where, status: 'locked' } }),
    ]);
    return { total, active, inactive, locked };
  }

  // Audit Logs
  async getAuditLogs(tenantId?: string) {
    return this.prisma.auditLog.findMany({
      where: tenantId ? { tenantId } : undefined,
      include: { user: true },
      orderBy: { createdAt: 'desc' },
      take: 50,
    });
  }

  async getAuditLogStats(tenantId?: string) {
    const where = tenantId ? { tenantId } : undefined;
    const [total, success, failed] = await Promise.all([
      this.prisma.auditLog.count({ where }),
      this.prisma.auditLog.count({ where: { ...where, status: 'success' } }),
      this.prisma.auditLog.count({ where: { ...where, status: 'failed' } }),
    ]);
    return { total, success, failed };
  }

  // Groups
  async getGroups(tenantId?: string) {
    return this.prisma.deviceGroup.findMany({
      where: tenantId ? { tenantId } : undefined,
      include: { devices: true, children: true },
      orderBy: { createdAt: 'desc' },
    });
  }
}

import { FastifyInstance } from 'fastify';
import { db } from '../db/connection';
import { devices } from '../db/schema';
import { eq, and, ilike, sql, count } from 'drizzle-orm';

export async function devicesRoutes(app: FastifyInstance) {
  // List devices with filtering & pagination
  app.get('/', { preHandler: [app.authenticate] }, async (request) => {
    const { search, status, type, page = '1', limit = '25' } = request.query as any;
    const { tenantId } = request.user;
    const pageNum = parseInt(page);
    const limitNum = parseInt(limit);
    const offset = (pageNum - 1) * limitNum;

    const conditions: any[] = [eq(devices.tenantId, tenantId)];
    if (status && status !== 'all') conditions.push(eq(devices.status, status));
    if (type && type !== 'all') conditions.push(eq(devices.type, type));
    if (search) conditions.push(ilike(devices.name, `%${search}%`));

    const where = conditions.length > 1 ? and(...conditions) : conditions[0];

    const [data, [{ total: totalCount }]] = await Promise.all([
      db.select().from(devices).where(where).limit(limitNum).offset(offset).orderBy(devices.createdAt),
      db.select({ total: count() }).from(devices).where(where),
    ]);

    const total = Number(totalCount);
    return {
      success: true,
      data,
      total,
      page: pageNum,
      pageSize: limitNum,
      totalPages: Math.ceil(total / limitNum),
    };
  });

  // Device stats
  app.get('/stats', { preHandler: [app.authenticate] }, async (request) => {
    const { tenantId } = request.user;

    const result = await db.select({
      status: devices.status,
      count: count(),
    }).from(devices).where(eq(devices.tenantId, tenantId)).groupBy(devices.status);

    const stats: Record<string, number> = { total: 0, online: 0, offline: 0, idle: 0, busy: 0, error: 0, maintenance: 0 };
    for (const row of result) {
      stats[row.status] = Number(row.count);
      stats.total += Number(row.count);
    }

    return { success: true, ...stats };
  });

  // Get single device
  app.get('/:id', { preHandler: [app.authenticate] }, async (request, reply) => {
    const { id } = request.params as { id: string };
    const { tenantId } = request.user;

    const [device] = await db.select().from(devices)
      .where(and(eq(devices.id, id), eq(devices.tenantId, tenantId)))
      .limit(1);

    if (!device) return reply.status(404).send({ success: false, error: 'Device not found' });
    return { success: true, data: device };
  });

  // Create device
  app.post('/', { preHandler: [app.authenticate] }, async (request) => {
    const { tenantId } = request.user;
    const body = request.body as any;

    const [device] = await db.insert(devices).values({
      tenantId,
      name: body.name,
      type: body.type || 'linux',
      status: body.status || 'offline',
      ipAddress: body.ipAddress,
      osVersion: body.osVersion,
      agentVersion: body.agentVersion || '2.1.0',
      tags: body.tags || [],
      metadata: body.metadata || {},
    }).returning();

    return { success: true, data: device };
  });

  // Update device
  app.put('/:id', { preHandler: [app.authenticate] }, async (request, reply) => {
    const { id } = request.params as { id: string };
    const { tenantId } = request.user;
    const body = request.body as any;

    const [device] = await db.update(devices)
      .set({ ...body, updatedAt: new Date() })
      .where(and(eq(devices.id, id), eq(devices.tenantId, tenantId)))
      .returning();

    if (!device) return reply.status(404).send({ success: false, error: 'Device not found' });
    return { success: true, data: device };
  });

  // Delete device
  app.delete('/:id', { preHandler: [app.authenticate] }, async (request, reply) => {
    const { id } = request.params as { id: string };
    const { tenantId } = request.user;

    const [device] = await db.delete(devices)
      .where(and(eq(devices.id, id), eq(devices.tenantId, tenantId)))
      .returning();

    if (!device) return reply.status(404).send({ success: false, error: 'Device not found' });
    return { success: true, message: 'Device deleted' };
  });
}

import Fastify from 'fastify';
import cors from '@fastify/cors';
import { registerAuth } from './lib/auth';
import { logger } from './lib/logger';

// Routes
import { authRoutes } from './routes/auth.routes';
import { dashboardRoutes } from './routes/dashboard.routes';
import { devicesRoutes } from './routes/devices.routes';
import { alertsRoutes } from './routes/alerts.routes';
