import { io, Socket } from 'socket.io-client';

let socket: Socket | null = null;

export function connectSocket(token: string) {
  if (socket?.connected) return socket;

  socket = io('http://localhost:3388/realtime', {
    auth: { token },
    transports: ['websocket'],
    reconnection: true,
    reconnectionAttempts: 5,
    reconnectionDelay: 2000,
  });

  socket.on('connect', () => {
    console.log('[WS] Connected to realtime server');
    socket?.emit('authenticate', { token, tenantId: 'default' });
  });

  socket.on('disconnect', (reason) => {
    console.log('[WS] Disconnected:', reason);
  });

  socket.on('connect_error', (err) => {
    console.warn('[WS] Connection error:', err.message);
  });

  return socket;
}

export function disconnectSocket() {
  if (socket) {
    socket.disconnect();
    socket = null;
  }
}

export function getSocket(): Socket | null {
  return socket;
}

// Subscribe to device updates
export function subscribeToDevice(deviceId: string) {
  socket?.emit('subscribe:device', { deviceId });
}

export function subscribeToFleet() {
  socket?.emit('subscribe:fleet');
}

export function subscribeToAlerts() {
  socket?.emit('subscribe:alerts');
}

import { useEffect, useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { connectSocket, disconnectSocket, getSocket, subscribeToFleet, subscribeToAlerts } from '../lib/socket';
import { useAuthStore } from '../stores/authStore';
import { useNotificationStore } from '../stores/notificationStore';

export function useRealtime() {
  const { user, isAuthenticated } = useAuthStore();
  const queryClient = useQueryClient();
  const { addNotification } = useNotificationStore();
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    if (!isAuthenticated) {
      disconnectSocket();
      setConnected(false);
      return;
    }

    const token = localStorage.getItem('auth_token');
    if (!token) return;

    const socket = connectSocket(token);

    socket.on('connect', () => {
      setConnected(true);
      subscribeToFleet();
      subscribeToAlerts();
    });

    socket.on('disconnect', () => setConnected(false));

    // Real-time event handlers
    socket.on('device:update', (data: any) => {
      queryClient.invalidateQueries({ queryKey: ['devices'] });
      queryClient.invalidateQueries({ queryKey: ['dashboard', 'stats'] });
    });

    socket.on('fleet:event', () => {
      queryClient.invalidateQueries({ queryKey: ['devices'] });
    });

    socket.on('alert:new', (alert: any) => {
      queryClient.invalidateQueries({ queryKey: ['alerts'] });
      queryClient.invalidateQueries({ queryKey: ['dashboard', 'stats'] });

      // Push to notification store
      addNotification({
        title: `${alert.severity?.toUpperCase() || 'Alert'}: ${alert.source || 'System'}`,
        message: alert.message || 'New alert received',
        type: alert.severity === 'critical' ? 'critical' : alert.severity === 'warning' ? 'warning' : 'info',
        link: '/alerts',
      });
    });

    socket.on('command:result', () => {
      queryClient.invalidateQueries({ queryKey: ['jobs'] });
    });

    return () => {
      disconnectSocket();
      setConnected(false);
    };
  }, [isAuthenticated, queryClient, addNotification]);

  return { connected };
}

