/**
 * WebSocket client for real-time orchestrator communication.
 * Connects to the API Gateway WebSocket endpoint.
 */

let socket: WebSocket | null = null;
let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
const listeners = new Map<string, Set<(data: any) => void>>();

const WS_URL = `ws://${window.location.hostname}:3388/ws`;

export function connectSocket(token: string): WebSocket {
  if (socket && socket.readyState === WebSocket.OPEN) return socket;

  socket = new WebSocket(WS_URL);

  socket.onopen = () => {
    console.log('[WS] Connected to orchestrator');
    // Authenticate as dashboard
    send({ type: 'auth', token, tenantId: 'default' });
    send({ type: 'subscribe', channel: 'all' });
    emit('connect', {});
  };

  socket.onmessage = (event) => {
    try {
      const msg = JSON.parse(event.data);
      // Route to appropriate listeners
      if (msg.type) {
        emit(msg.type, msg);
      }
    } catch {}
  };

  socket.onclose = () => {
    console.log('[WS] Disconnected');
    emit('disconnect', {});
    // Auto-reconnect
    if (!reconnectTimer) {
      reconnectTimer = setTimeout(() => {
        reconnectTimer = null;
        connectSocket(token);
      }, 3000);
    }
  };

  socket.onerror = () => {
    // Errors handled by onclose
  };

  return socket;
}

export function disconnectSocket() {
  if (reconnectTimer) {
    clearTimeout(reconnectTimer);
    reconnectTimer = null;
  }
  if (socket) {
    socket.close();
    socket = null;
  }
}

export function getSocket(): WebSocket | null {
  return socket;
}

function send(msg: any) {
  if (socket && socket.readyState === WebSocket.OPEN) {
    socket.send(JSON.stringify(msg));
  }
}

// Event system
function emit(event: string, data: any) {
  const handlers = listeners.get(event);
  if (handlers) {
    for (const handler of handlers) {
      handler(data);
    }
  }
}

export function onSocketEvent(event: string, handler: (data: any) => void) {
  if (!listeners.has(event)) {
    listeners.set(event, new Set());
  }
  listeners.get(event)!.add(handler);
  return () => {
    listeners.get(event)?.delete(handler);
  };
}

// Convenience subscriptions
export function subscribeToDevice(deviceId: string) {
  send({ type: 'subscribe', channel: `device:${deviceId}` });
}

export function subscribeToFleet() {
  send({ type: 'subscribe', channel: 'fleet' });
}

export function subscribeToAlerts() {
  send({ type: 'subscribe', channel: 'alerts' });
}

import { useEffect, useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { connectSocket, disconnectSocket, onSocketEvent } from '../lib/socket';
import { useAuthStore } from '../stores/authStore';
import { useNotificationStore } from '../stores/notificationStore';

export function useRealtime() {
  const { isAuthenticated } = useAuthStore();
  const queryClient = useQueryClient();
  const { addNotification } = useNotificationStore();
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    if (!isAuthenticated) {
      disconnectSocket();
      setConnected(false);
      return;
    }

    const token = localStorage.getItem('auth_token');
    if (!token) return;

    connectSocket(token);

    const unsubs = [
      onSocketEvent('connect', () => setConnected(true)),
      onSocketEvent('disconnect', () => setConnected(false)),

      // Device status changes
      onSocketEvent('device:status', () => {
        queryClient.invalidateQueries({ queryKey: ['devices'] });
        queryClient.invalidateQueries({ queryKey: ['dashboard', 'stats'] });
      }),

      // Telemetry updates
      onSocketEvent('telemetry:update', () => {
        queryClient.invalidateQueries({ queryKey: ['telemetry'] });
      }),

      // New alerts
      onSocketEvent('alert:new', (data: any) => {
        queryClient.invalidateQueries({ queryKey: ['alerts'] });
        queryClient.invalidateQueries({ queryKey: ['dashboard', 'stats'] });
        addNotification({
          title: `Alert: ${data.alert?.title || 'New alert'}`,
          message: data.alert?.message || '',
          type: data.alert?.severity === 'critical' ? 'critical' : data.alert?.severity === 'warning' ? 'warning' : 'info',
          link: '/alerts',
        });
      }),

      // Command results
      onSocketEvent('command:result', () => {
        queryClient.invalidateQueries({ queryKey: ['jobs'] });
      }),

      // Job progress
      onSocketEvent('job:progress', () => {
        queryClient.invalidateQueries({ queryKey: ['jobs'] });
      }),

      onSocketEvent('job:completed', (data: any) => {
        queryClient.invalidateQueries({ queryKey: ['jobs'] });
        addNotification({
          title: `Job completed`,
          message: `Job ${data.jobId} finished (${data.status})`,
          type: data.status === 'completed' ? 'info' : 'warning',
          link: '/jobs',
        });
      }),
    ];

    return () => {
      unsubs.forEach(unsub => unsub());
      disconnectSocket();
      setConnected(false);
    };
  }, [isAuthenticated, queryClient, addNotification]);

  return { connected };
}

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import path from 'path';

