/**
 * Redis Client
 * Used for: session cache, rate limiting, orchestrator state persistence, pub/sub
 */

import Redis from 'ioredis';
import { logger } from './logger';

const REDIS_URL = process.env.REDIS_URL || 'redis://localhost:6380';

export const redis = new Redis(REDIS_URL, {
  maxRetriesPerRequest: 3,
  retryStrategy(times) {
    if (times > 5) return null; // stop retrying
    return Math.min(times * 200, 2000);
  },
  lazyConnect: true,
});

let connected = false;

export async function connectRedis(): Promise<boolean> {
  try {
    await redis.connect();
    connected = true;
    logger.info('🔴 Redis connected');
    return true;
  } catch (err: any) {
    logger.warn({ err: err.message }, 'Redis connection failed — running without cache');
    connected = false;
    return false;
  }
}

export function isRedisConnected(): boolean {
  return connected && redis.status === 'ready';
}

// ─── Cache Helpers ────────────────────────────────────────────────────────────

export async function cacheGet<T>(key: string): Promise<T | null> {
  if (!isRedisConnected()) return null;
  try {
    const data = await redis.get(key);
    return data ? JSON.parse(data) : null;
  } catch {
    return null;
  }
}

export async function cacheSet(key: string, value: any, ttlSeconds = 60): Promise<void> {
  if (!isRedisConnected()) return;
  try {
    await redis.set(key, JSON.stringify(value), 'EX', ttlSeconds);
  } catch {}
}

export async function cacheDel(key: string): Promise<void> {
  if (!isRedisConnected()) return;
  try {
    await redis.del(key);
  } catch {}
}

// ─── Rate Limiting ────────────────────────────────────────────────────────────

export async function checkRateLimit(key: string, maxRequests: number, windowSeconds: number): Promise<{ allowed: boolean; remaining: number; resetIn: number }> {
  if (!isRedisConnected()) {
    return { allowed: true, remaining: maxRequests, resetIn: 0 };
  }

  const redisKey = `ratelimit:${key}`;
  const now = Date.now();
  const windowMs = windowSeconds * 1000;

  try {
    // Sliding window using sorted set
    const pipeline = redis.pipeline();
    pipeline.zremrangebyscore(redisKey, 0, now - windowMs);
    pipeline.zadd(redisKey, now.toString(), `${now}-${Math.random()}`);
    pipeline.zcard(redisKey);
    pipeline.expire(redisKey, windowSeconds);
    const results = await pipeline.exec();

    const count = (results?.[2]?.[1] as number) || 0;
    const allowed = count <= maxRequests;
    const remaining = Math.max(0, maxRequests - count);
    const resetIn = windowSeconds;

    return { allowed, remaining, resetIn };
  } catch {
    return { allowed: true, remaining: maxRequests, resetIn: 0 };
  }
}

// ─── Session/Device State ─────────────────────────────────────────────────────

export async function setDeviceOnline(deviceId: string, tenantId: string, ttl = 60): Promise<void> {
  if (!isRedisConnected()) return;
  await redis.set(`device:online:${deviceId}`, tenantId, 'EX', ttl);
}

export async function setDeviceOffline(deviceId: string): Promise<void> {
  if (!isRedisConnected()) return;
  await redis.del(`device:online:${deviceId}`);
}

export async function getOnlineDeviceIds(): Promise<string[]> {
  if (!isRedisConnected()) return [];
  try {
    const keys = await redis.keys('device:online:*');
    return keys.map(k => k.replace('device:online:', ''));
  } catch {
    return [];
  }
}

// ─── Command Queue Persistence ────────────────────────────────────────────────

export async function persistCommand(deviceId: string, command: any): Promise<void> {
  if (!isRedisConnected()) return;
  await redis.rpush(`cmdqueue:${deviceId}`, JSON.stringify(command));
  await redis.expire(`cmdqueue:${deviceId}`, 86400); // 24h TTL
}

export async function getPersistedCommands(deviceId: string): Promise<any[]> {
  if (!isRedisConnected()) return [];
  try {
    const items = await redis.lrange(`cmdqueue:${deviceId}`, 0, -1);
    await redis.del(`cmdqueue:${deviceId}`);
    return items.map(i => JSON.parse(i));
  } catch {
    return [];
  }
}

/**
 * Rate Limiting Middleware
 * Uses Redis sliding window for distributed rate limiting.
 * Falls back to in-memory when Redis is unavailable.
 */

import { FastifyRequest, FastifyReply } from 'fastify';
import { checkRateLimit, isRedisConnected } from './redis';

// In-memory fallback for when Redis is down
const memoryStore = new Map<string, { count: number; resetAt: number }>();

interface RateLimitConfig {
  max: number;        // max requests
  window: number;     // window in seconds
  keyGenerator?: (request: FastifyRequest) => string;
}

const DEFAULT_CONFIG: RateLimitConfig = {
  max: 100,
  window: 60, // 100 requests per minute
};

// Specific limits per route pattern
const ROUTE_LIMITS: Record<string, RateLimitConfig> = {
  '/api/v1/auth/login': { max: 10, window: 60 },       // 10 login attempts/min
  '/api/v1/auth/register': { max: 5, window: 300 },    // 5 registrations/5min
  '/api/v1/telemetry/ingest': { max: 600, window: 60 }, // 600 telemetry/min (10/sec)
  '/api/v1/orchestrator/bulk': { max: 20, window: 60 }, // 20 bulk ops/min
};

export function createRateLimitHook(config?: Partial<RateLimitConfig>) {
  const cfg = { ...DEFAULT_CONFIG, ...config };

  return async (request: FastifyRequest, reply: FastifyReply) => {
    const key = getKey(request, cfg);
    const routeConfig = getRouteConfig(request.url) || cfg;

    let result: { allowed: boolean; remaining: number; resetIn: number };

    if (isRedisConnected()) {
      result = await checkRateLimit(key, routeConfig.max, routeConfig.window);
    } else {
      result = checkMemoryRateLimit(key, routeConfig.max, routeConfig.window);
    }

    // Set rate limit headers
    reply.header('X-RateLimit-Limit', routeConfig.max);
    reply.header('X-RateLimit-Remaining', result.remaining);
    reply.header('X-RateLimit-Reset', result.resetIn);

    if (!result.allowed) {
      reply.status(429).send({
        success: false,
        error: 'Too many requests. Please slow down.',
        retryAfter: result.resetIn,
      });
    }
  };
}

function getKey(request: FastifyRequest, config: RateLimitConfig): string {
  if (config.keyGenerator) return config.keyGenerator(request);

  // Use user ID if authenticated, otherwise IP
  const user = (request as any).user;
  if (user?.userId) return `user:${user.userId}`;

  const ip = request.ip || request.headers['x-forwarded-for'] || 'unknown';
  return `ip:${ip}`;
}

function getRouteConfig(url: string): RateLimitConfig | null {
  for (const [pattern, config] of Object.entries(ROUTE_LIMITS)) {
    if (url.startsWith(pattern)) return config;
  }
  return null;
}

// In-memory fallback
function checkMemoryRateLimit(key: string, max: number, windowSeconds: number): { allowed: boolean; remaining: number; resetIn: number } {
  const now = Date.now();
  const entry = memoryStore.get(key);

  if (!entry || now > entry.resetAt) {
    memoryStore.set(key, { count: 1, resetAt: now + windowSeconds * 1000 });
    return { allowed: true, remaining: max - 1, resetIn: windowSeconds };
  }

  entry.count++;
  const allowed = entry.count <= max;
  const remaining = Math.max(0, max - entry.count);
  const resetIn = Math.ceil((entry.resetAt - now) / 1000);

  return { allowed, remaining, resetIn };
}

// Cleanup memory store periodically
setInterval(() => {
  const now = Date.now();
  for (const [key, entry] of memoryStore) {
    if (now > entry.resetAt) memoryStore.delete(key);
  }
}, 60000);

/**
 * Role-Based Access Control (RBAC)
 * Enforces permissions based on user role from JWT.
 * 
 * Roles hierarchy: super_admin > tenant_owner > admin > operator > viewer
 */

import { FastifyRequest, FastifyReply } from 'fastify';

export type Role = 'super_admin' | 'tenant_owner' | 'admin' | 'operator' | 'viewer';

// Role hierarchy (higher index = more permissions)
const ROLE_HIERARCHY: Role[] = ['viewer', 'operator', 'admin', 'tenant_owner', 'super_admin'];

// Permission definitions per role
const ROLE_PERMISSIONS: Record<Role, string[]> = {
  viewer: [
    'devices:read', 'alerts:read', 'jobs:read', 'telemetry:read',
    'groups:read', 'users:read', 'audit-logs:read', 'dashboard:read',
  ],
  operator: [
    'devices:read', 'devices:update', 'devices:execute',
    'alerts:read', 'alerts:acknowledge',
    'jobs:read', 'jobs:create',
    'telemetry:read',
    'groups:read',
    'users:read',
    'audit-logs:read',
    'dashboard:read',
    'orchestrator:command', 'orchestrator:read',
  ],
  admin: [
    'devices:*', 'alerts:*', 'jobs:*', 'telemetry:*',
    'groups:*', 'users:read', 'users:update',
    'audit-logs:read',
    'dashboard:*',
    'orchestrator:*',
    'settings:read', 'settings:update',
  ],
  tenant_owner: [
    '*:*', // all permissions within tenant
  ],
  super_admin: [
    '*', // global admin
  ],
};

/**
 * Check if a role has a specific permission
 */
export function hasPermission(role: Role, permission: string): boolean {
  const permissions = ROLE_PERMISSIONS[role] || [];

  // Super admin and tenant owner have wildcard
  if (permissions.includes('*') || permissions.includes('*:*')) return true;

  // Check exact match
  if (permissions.includes(permission)) return true;

  // Check wildcard match (e.g., 'devices:*' matches 'devices:read')
  const [resource] = permission.split(':');
  if (permissions.includes(`${resource}:*`)) return true;

  return false;
}

/**
 * Check if roleA is at least as privileged as roleB
 */
export function isRoleAtLeast(roleA: Role, roleB: Role): boolean {
  return ROLE_HIERARCHY.indexOf(roleA) >= ROLE_HIERARCHY.indexOf(roleB);
}

/**
 * Fastify preHandler: require minimum role
 */
export function requireRole(...allowedRoles: Role[]) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    const user = request.user;
    if (!user) {
      return reply.status(401).send({ success: false, error: 'Unauthorized' });
    }

    const userRole = user.role as Role;

    // Super admin always passes
    if (userRole === 'super_admin') return;

    // Check if user's role is in allowed list
    if (allowedRoles.includes(userRole)) return;

    // Check hierarchy — if user's role is higher than any allowed role
    const minRequired = allowedRoles.reduce((min, role) => {
      const idx = ROLE_HIERARCHY.indexOf(role);
      return idx < ROLE_HIERARCHY.indexOf(min) ? role : min;
    }, allowedRoles[0]);

    if (isRoleAtLeast(userRole, minRequired)) return;

    return reply.status(403).send({
      success: false,
      error: 'Forbidden: insufficient permissions',
      required: allowedRoles,
      current: userRole,
    });
  };
}

/**
 * Fastify preHandler: require specific permission
 */
export function requirePermission(permission: string) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    const user = request.user;
    if (!user) {
      return reply.status(401).send({ success: false, error: 'Unauthorized' });
    }

    const userRole = user.role as Role;

    if (!hasPermission(userRole, permission)) {
      return reply.status(403).send({
        success: false,
        error: `Forbidden: missing permission '${permission}'`,
        current: userRole,
      });
    }
  };
}

/**
 * Shorthand preHandlers
 */
export const adminOnly = requireRole('admin', 'tenant_owner', 'super_admin');
export const operatorUp = requireRole('operator', 'admin', 'tenant_owner', 'super_admin');
export const viewerUp = requireRole('viewer', 'operator', 'admin', 'tenant_owner', 'super_admin');

/**
 * Input Validation Schemas (Zod)
 * Validates all incoming request bodies before processing.
 */

import { z } from 'zod';
import { FastifyRequest, FastifyReply } from 'fastify';

// ─── Auth Schemas ─────────────────────────────────────────────────────────────

export const loginSchema = z.object({
