  type: z.enum(['android', 'linux', 'windows', 'macos', 'iot', 'raspberry_pi', 'browser_worker', 'docker_agent', 'vm_agent', 'kubernetes_node']).optional(),
  ipAddress: z.string().ip().optional().or(z.literal('')),
  osVersion: z.string().max(100).optional(),
  status: z.enum(['online', 'offline', 'idle', 'busy', 'error', 'maintenance', 'updating', 'provisioning', 'decommissioned']).optional(),
  tags: z.array(z.string()).optional(),
  metadata: z.record(z.unknown()).optional(),
}).refine(data => Object.keys(data).length > 0, 'At least one field must be provided');

// ─── Command Schemas ──────────────────────────────────────────────────────────

export const commandSchema = z.object({
  type: z.enum(['shell_execute', 'reboot', 'shutdown', 'update_config', 'file_transfer', 'diagnostics', 'ota_update']),
  payload: z.record(z.unknown()).optional().default({}),
  timeout: z.number().min(1000).max(300000).optional().default(30000),
});

export const bulkCommandSchema = z.object({
  deviceIds: z.array(z.string().uuid()).min(1).max(100),
  type: z.enum(['shell_execute', 'reboot', 'shutdown', 'update_config', 'file_transfer', 'diagnostics', 'ota_update']),
  payload: z.record(z.unknown()).optional().default({}),
});

// ─── Job Schemas ──────────────────────────────────────────────────────────────

export const createJobSchema = z.object({
  name: z.string().min(1).max(255),
  type: z.string().min(1).max(100),
  targetDevices: z.array(z.string().uuid()).optional().default([]),
  payload: z.record(z.unknown()).optional().default({}),
  scheduledAt: z.string().datetime().optional(),
});

// ─── Alert Schemas ────────────────────────────────────────────────────────────

export const createAlertSchema = z.object({
  deviceId: z.string().uuid().optional(),
  title: z.string().min(1).max(500),
  message: z.string().max(2000).optional(),
  severity: z.enum(['info', 'warning', 'error', 'critical']),
  source: z.string().max(100).optional(),
});

// ─── Group Schemas ────────────────────────────────────────────────────────────

export const createGroupSchema = z.object({
  name: z.string().min(1).max(255),
  description: z.string().max(1000).optional(),
  color: z.string().regex(/^#[0-9a-fA-F]{6}$/, 'Color must be hex format (#RRGGBB)').optional(),
  parentId: z.string().uuid().optional(),
});

// ─── Admin Schemas ────────────────────────────────────────────────────────────

export const createUserSchema = z.object({
  email: z.string().email(),
  username: z.string().min(3).max(50).optional(),
  password: z.string().min(8),
  displayName: z.string().min(2).max(100),
  role: z.enum(['super_admin', 'tenant_owner', 'admin', 'operator', 'viewer']).optional().default('viewer'),
});

export const updateUserSchema = z.object({
  displayName: z.string().min(2).max(100).optional(),
  role: z.enum(['super_admin', 'tenant_owner', 'admin', 'operator', 'viewer']).optional(),
  status: z.enum(['active', 'inactive', 'suspended']).optional(),
}).refine(data => Object.keys(data).length > 0, 'At least one field must be provided');

export const createRoleSchema = z.object({
  name: z.string().min(1).max(100),
  description: z.string().max(500).optional(),
  permissions: z.array(z.string()).min(1),
});

export const updateSettingsSchema = z.object({
  settings: z.array(z.object({
    key: z.string().min(1).max(255),
    value: z.string().max(5000),
  })).min(1),
});

// ─── Shadow State Schema ──────────────────────────────────────────────────────

export const shadowUpdateSchema = z.object({
  desired: z.record(z.unknown()),
});

// ─── Validation Middleware Factory ────────────────────────────────────────────

/**
 * Creates a Fastify preHandler that validates request.body against a Zod schema.
 * Returns 400 with detailed error messages on validation failure.
 */
export function validate(schema: z.ZodSchema) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      const parsed = schema.parse(request.body);
      // Replace body with parsed (cleaned) data
      (request as any).body = parsed;
    } catch (err) {
      if (err instanceof z.ZodError) {
        return reply.status(400).send({
          success: false,
          error: 'Validation failed',
          details: err.errors.map(e => ({
            field: e.path.join('.'),
            message: e.message,
          })),
        });
      }
      return reply.status(400).send({ success: false, error: 'Invalid request body' });
    }
  };
}

/**
 * Authentication & Security
 * JWT verification, security headers, RBAC decorators
 */

import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import jwt from '@fastify/jwt';
import { logger } from './logger';

export async function registerAuth(app: FastifyInstance) {
  // JWT secret — MUST be set via env in production
  const secret = process.env.JWT_SECRET;
  if (!secret || secret === 'your-super-secret-jwt-key-change-in-production') {
    logger.warn('⚠️  Using default JWT secret — set JWT_SECRET env var for production!');
  }

  await app.register(jwt, {
    secret: secret || 'audira-dev-secret-change-in-production',
    sign: { expiresIn: process.env.JWT_EXPIRATION ? `${process.env.JWT_EXPIRATION}s` : '24h' },
  });

  // ─── Security Headers ───────────────────────────────────────────────────

  app.addHook('onSend', async (request, reply) => {
    reply.header('X-Content-Type-Options', 'nosniff');
    reply.header('X-Frame-Options', 'DENY');
    reply.header('X-XSS-Protection', '1; mode=block');
    reply.header('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
    reply.header('Cache-Control', 'no-store');
    // Remove server header
    reply.removeHeader('x-powered-by');
  });

  // ─── Request Logging ────────────────────────────────────────────────────

  app.addHook('onResponse', async (request, reply) => {
    const duration = reply.elapsedTime;
    const level = reply.statusCode >= 500 ? 'error' : reply.statusCode >= 400 ? 'warn' : 'info';
    logger[level]({
      method: request.method,
      url: request.url,
      status: reply.statusCode,
      duration: `${duration.toFixed(0)}ms`,
      ip: request.ip,
      userId: (request as any).user?.userId,
    }, `${request.method} ${request.url} ${reply.statusCode}`);
  });

  // ─── Authentication Decorator ───────────────────────────────────────────

  app.decorate('authenticate', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();
    } catch (err) {
      reply.status(401).send({ success: false, error: 'Unauthorized: invalid or expired token' });
    }
  });
}

// Type augmentation
declare module 'fastify' {
  interface FastifyInstance {
    authenticate: (request: FastifyRequest, reply: FastifyReply) => Promise<void>;
  }
}

declare module '@fastify/jwt' {
  interface FastifyJWT {
    payload: { userId: string; tenantId: string; role: string; email: string };
    user: { userId: string; tenantId: string; role: string; email: string };
  }
}

import Fastify from 'fastify';
import cors from '@fastify/cors';
import { registerAuth } from './lib/auth';
import { logger } from './lib/logger';
import { setupWebSocket } from './lib/websocket';
import { connectRedis, isRedisConnected } from './lib/redis';
import { createRateLimitHook } from './lib/rateLimit';

// Routes
import { authRoutes } from './routes/auth.routes';
import { dashboardRoutes } from './routes/dashboard.routes';
import { devicesRoutes } from './routes/devices.routes';
import { alertsRoutes } from './routes/alerts.routes';
import { jobsRoutes } from './routes/jobs.routes';
import { telemetryRoutes } from './routes/telemetry.routes';
import { usersRoutes } from './routes/users.routes';
import { tenantsRoutes } from './routes/tenants.routes';
import { auditLogsRoutes } from './routes/audit-logs.routes';
import { groupsRoutes } from './routes/groups.routes';
import { adminRoutes } from './routes/admin.routes';
import { aiRoutes } from './routes/ai.routes';
import { healthRoutes } from './routes/health.routes';
import { orchestratorRoutes } from './routes/orchestrator.routes';

const app = Fastify({ logger: false });

async function start() {
  // ─── Redis ──────────────────────────────────────────────────────────────
  await connectRedis();

  // ─── CORS ───────────────────────────────────────────────────────────────
  await app.register(cors, {
    origin: (process.env.CORS_ORIGINS || 'http://localhost:5173,http://localhost:3387,http://localhost:3000,http://localhost:1420').split(','),
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
  });

  // ─── Auth (JWT + Security Headers + Request Logging) ────────────────────
  await registerAuth(app);

  // ─── Global Rate Limiting ───────────────────────────────────────────────
  app.addHook('onRequest', createRateLimitHook({ max: 200, window: 60 }));

  // ─── Routes ─────────────────────────────────────────────────────────────
  await app.register(authRoutes, { prefix: '/api/v1/auth' });
  await app.register(dashboardRoutes, { prefix: '/api/v1/dashboard' });
  await app.register(devicesRoutes, { prefix: '/api/v1/devices' });
  await app.register(alertsRoutes, { prefix: '/api/v1/alerts' });
  await app.register(jobsRoutes, { prefix: '/api/v1/jobs' });
  await app.register(telemetryRoutes, { prefix: '/api/v1/telemetry' });
  await app.register(usersRoutes, { prefix: '/api/v1/users' });
  await app.register(tenantsRoutes, { prefix: '/api/v1/tenants' });
  await app.register(auditLogsRoutes, { prefix: '/api/v1/audit-logs' });
  await app.register(groupsRoutes, { prefix: '/api/v1/groups' });
  await app.register(adminRoutes, { prefix: '/api/v1/admin' });
  await app.register(aiRoutes, { prefix: '/api/v1/ai' });
  await app.register(healthRoutes, { prefix: '/api/v1/health' });
  await app.register(orchestratorRoutes, { prefix: '/api/v1/orchestrator' });

  // ─── Global Error Handler ───────────────────────────────────────────────
  app.setErrorHandler((error, request, reply) => {
    logger.error({ err: error, url: request.url, method: request.method }, 'Request error');

    // Don't leak internal errors in production
    const isProd = process.env.NODE_ENV === 'production';
    const statusCode = error.statusCode || 500;
    const message = statusCode >= 500 && isProd ? 'Internal server error' : error.message;

    reply.status(statusCode).send({
      success: false,
      error: message,
      ...(isProd ? {} : { stack: error.stack }),
    });
  });

  // ─── 404 Handler ────────────────────────────────────────────────────────
  app.setNotFoundHandler((request, reply) => {
    reply.status(404).send({
      success: false,
      error: `Route ${request.method} ${request.url} not found`,
    });
  });

  // ─── Start Server ──────────────────────────────────────────────────────
  const port = parseInt(process.env.API_PORT || '3388');
  const host = '0.0.0.0';

  await app.listen({ port, host });

  // Setup WebSocket after HTTP server is listening
  setupWebSocket(app);

  logger.info(`🚀 API Gateway running on http://localhost:${port}`);
  logger.info(`   Health:       http://localhost:${port}/api/v1/health`);
  logger.info(`   Auth:         POST http://localhost:${port}/api/v1/auth/login`);
  logger.info(`   WebSocket:    ws://localhost:${port}/ws`);
  logger.info(`   Orchestrator: http://localhost:${port}/api/v1/orchestrator/status`);
  logger.info(`   Redis:        ${isRedisConnected() ? '✅ connected' : '⚠️  not connected (fallback mode)'}`);
  logger.info(`   Rate Limit:   200 req/min global`);
}

start().catch((err) => {
  logger.error(err, 'Failed to start API Gateway');
  process.exit(1);
});

export { app };

