export async function healthRoutes(app: FastifyInstance) {
  app.get('/', async () => {
    let dbStatus = 'unknown';
    try {
      await pool.query('SELECT 1');
      dbStatus = 'connected';
    } catch {
      dbStatus = 'disconnected';
    }

    const wsStats = getWsStats();
    const orchStats = orchestrator.getStats();

    return {
      status: 'ok',
      service: 'api-gateway',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
      version: '2.1.0',
      dependencies: {
        database: dbStatus,
        redis: isRedisConnected() ? 'connected' : 'disconnected',
      },
      orchestrator: {
        connectedDevices: orchStats.connectedDevices,
        activeCommands: orchStats.activeCommands,
        pendingCommands: orchStats.pendingCommands,
      },
      websocket: wsStats,
      memory: {
        rss: `${(process.memoryUsage().rss / 1024 / 1024).toFixed(1)}MB`,
        heap: `${(process.memoryUsage().heapUsed / 1024 / 1024).toFixed(1)}MB`,
      },
    };
  });
}

