/**
 * Database Migration Runner
 * Runs SQL migration files in order, tracks applied migrations.
 * Usage: node migrate.mjs
 */

import pg from 'pg';
import { readdir, readFile } from 'fs/promises';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const MIGRATIONS_DIR = join(__dirname, 'drizzle');
const DB_URL = process.env.DATABASE_URL || 'postgresql://orchestrator:orchestrator_secret@localhost:5433/orchestrator';

const pool = new pg.Pool({ connectionString: DB_URL });

async function migrate() {
  console.log('🔄 Running database migrations...');
  console.log(`   Database: ${DB_URL.replace(/:[^:@]+@/, ':***@')}`);
  console.log(`   Migrations: ${MIGRATIONS_DIR}\n`);

  // Ensure migrations table exists
  await pool.query(`
    CREATE TABLE IF NOT EXISTS _migrations (
      id SERIAL PRIMARY KEY,
      name VARCHAR(255) NOT NULL UNIQUE,
      applied_at TIMESTAMP NOT NULL DEFAULT NOW()
    );
  `);

  // Get applied migrations
  const { rows: applied } = await pool.query('SELECT name FROM _migrations ORDER BY id');
  const appliedSet = new Set(applied.map(r => r.name));

  // Get migration files
  const files = (await readdir(MIGRATIONS_DIR))
    .filter(f => f.endsWith('.sql'))
    .sort();

  let newMigrations = 0;

  for (const file of files) {
    const name = file.replace('.sql', '');
    if (appliedSet.has(name)) {
      console.log(`   ✓ ${name} (already applied)`);
      continue;
    }

    console.log(`   → Applying: ${name}...`);
    const sql = await readFile(join(MIGRATIONS_DIR, file), 'utf-8');

    try {
      await pool.query('BEGIN');
      await pool.query(sql);
      await pool.query('COMMIT');
      console.log(`   ✅ ${name} applied`);
      newMigrations++;
    } catch (err) {
      await pool.query('ROLLBACK');
      console.error(`   ❌ ${name} FAILED:`, err.message);
      process.exit(1);
    }
  }

  console.log(`\n✅ Migrations complete! (${newMigrations} new, ${files.length} total)`);
  await pool.end();
}

migrate().catch(err => {
  console.error('Migration failed:', err);
  process.exit(1);
});

/**
 * Application Metrics
 * Collects and exposes metrics in Prometheus format.
 * Endpoint: GET /metrics
 */

import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { orchestrator } from './orchestrator';
import { getWsStats } from './websocket';
import { isRedisConnected } from './redis';
import { pool } from '../db/connection';

// ─── Metric Counters ──────────────────────────────────────────────────────────

const metrics = {
  httpRequestsTotal: new Map<string, number>(),
  httpRequestDuration: new Map<string, number[]>(),
  httpErrors: 0,
  wsConnectionsTotal: 0,
  wsMessagesReceived: 0,
  commandsDispatched: 0,
  commandsCompleted: 0,
  commandsFailed: 0,
  commandsTimedOut: 0,
  heartbeatsProcessed: 0,
  alertsGenerated: 0,
  jobsExecuted: 0,
  telemetryRecordsIngested: 0,
  startTime: Date.now(),
};

// ─── Metric Collection Hooks ──────────────────────────────────────────────────

export function setupMetrics(app: FastifyInstance) {
  // Track HTTP requests
  app.addHook('onResponse', async (request: FastifyRequest, reply: FastifyReply) => {
    const key = `${request.method}:${reply.statusCode}`;
    metrics.httpRequestsTotal.set(key, (metrics.httpRequestsTotal.get(key) || 0) + 1);

    // Track duration
    const duration = reply.elapsedTime;
    const durationKey = request.method;
    if (!metrics.httpRequestDuration.has(durationKey)) {
      metrics.httpRequestDuration.set(durationKey, []);
    }
    const durations = metrics.httpRequestDuration.get(durationKey)!;
    durations.push(duration);
    // Keep only last 1000 samples
    if (durations.length > 1000) durations.shift();

    if (reply.statusCode >= 500) metrics.httpErrors++;
  });

  // Track orchestrator events
  orchestrator.on('command:dispatch', () => metrics.commandsDispatched++);
  orchestrator.on('command:result', (cmd: any) => {
    if (cmd.status === 'completed') metrics.commandsCompleted++;
    else metrics.commandsFailed++;
  });
  orchestrator.on('command:timeout', () => metrics.commandsTimedOut++);
  orchestrator.on('telemetry:received', () => {
    metrics.heartbeatsProcessed++;
    metrics.telemetryRecordsIngested++;
  });
  orchestrator.on('alert:created', () => metrics.alertsGenerated++);
  orchestrator.on('job:completed', () => metrics.jobsExecuted++);

  // Metrics endpoint (Prometheus format)
  app.get('/metrics', async (request, reply) => {
    reply.header('Content-Type', 'text/plain; charset=utf-8');

    const wsStats = getWsStats();
    const orchStats = orchestrator.getStats();
    const uptime = (Date.now() - metrics.startTime) / 1000;
    const mem = process.memoryUsage();

    let output = '';
    const line = (name: string, value: number, help?: string, type?: string) => {
      if (help) output += `# HELP ${name} ${help}\n`;
      if (type) output += `# TYPE ${name} ${type}\n`;
      output += `${name} ${value}\n`;
    };

    // Process metrics
    line('process_uptime_seconds', uptime, 'Process uptime in seconds', 'gauge');
    line('process_memory_rss_bytes', mem.rss, 'Process RSS memory', 'gauge');
    line('process_memory_heap_used_bytes', mem.heapUsed, 'Process heap used', 'gauge');
    line('process_memory_heap_total_bytes', mem.heapTotal, 'Process heap total', 'gauge');

    // HTTP metrics
    let totalRequests = 0;
    for (const [key, count] of metrics.httpRequestsTotal) {
      const [method, status] = key.split(':');
      output += `http_requests_total{method="${method}",status="${status}"} ${count}\n`;
      totalRequests += count;
    }
    line('http_requests_total_all', totalRequests, 'Total HTTP requests', 'counter');
    line('http_errors_total', metrics.httpErrors, 'Total HTTP 5xx errors', 'counter');

    // Request duration percentiles
    for (const [method, durations] of metrics.httpRequestDuration) {
      if (durations.length === 0) continue;
      const sorted = [...durations].sort((a, b) => a - b);
      const p50 = sorted[Math.floor(sorted.length * 0.5)] || 0;
      const p95 = sorted[Math.floor(sorted.length * 0.95)] || 0;
      const p99 = sorted[Math.floor(sorted.length * 0.99)] || 0;
      output += `http_request_duration_ms{method="${method}",quantile="0.5"} ${p50.toFixed(1)}\n`;
      output += `http_request_duration_ms{method="${method}",quantile="0.95"} ${p95.toFixed(1)}\n`;
      output += `http_request_duration_ms{method="${method}",quantile="0.99"} ${p99.toFixed(1)}\n`;
    }

    // WebSocket metrics
    line('ws_connections_total', wsStats.total, 'Total WebSocket connections', 'gauge');
    line('ws_connections_dashboard', wsStats.dashboards, 'Dashboard WS connections', 'gauge');
    line('ws_connections_agents', wsStats.agents, 'Device agent WS connections', 'gauge');

    // Orchestrator metrics
    line('orchestrator_devices_connected', orchStats.connectedDevices, 'Connected devices', 'gauge');
    line('orchestrator_commands_active', orchStats.activeCommands, 'Active commands', 'gauge');
    line('orchestrator_telemetry_buffer', orchStats.telemetryBufferSize, 'Telemetry buffer size', 'gauge');
    line('orchestrator_commands_dispatched_total', metrics.commandsDispatched, 'Total commands dispatched', 'counter');
    line('orchestrator_commands_completed_total', metrics.commandsCompleted, 'Total commands completed', 'counter');
    line('orchestrator_commands_failed_total', metrics.commandsFailed, 'Total commands failed', 'counter');
    line('orchestrator_commands_timeout_total', metrics.commandsTimedOut, 'Total commands timed out', 'counter');
    line('orchestrator_heartbeats_total', metrics.heartbeatsProcessed, 'Total heartbeats processed', 'counter');
    line('orchestrator_alerts_generated_total', metrics.alertsGenerated, 'Total alerts generated', 'counter');
    line('orchestrator_jobs_executed_total', metrics.jobsExecuted, 'Total jobs executed', 'counter');
    line('orchestrator_telemetry_ingested_total', metrics.telemetryRecordsIngested, 'Total telemetry records', 'counter');

    // Dependencies
    line('dependency_redis_connected', isRedisConnected() ? 1 : 0, 'Redis connection status', 'gauge');

    // DB pool
    try {
      line('dependency_db_pool_total', (pool as any).totalCount || 0, 'DB pool total connections', 'gauge');
      line('dependency_db_pool_idle', (pool as any).idleCount || 0, 'DB pool idle connections', 'gauge');
      line('dependency_db_pool_waiting', (pool as any).waitingCount || 0, 'DB pool waiting clients', 'gauge');
    } catch {}

    return output;
  });
}

