// ─── AI Provider Manager ──────────────────────────────────────────────────────

class AIProviderManager {
  private connections = new Map<string, { apiKey: string; endpoint?: string; status: string; lastTested?: string; latency?: number }>();

  constructor() {
    // Load from env on startup
    this.loadFromEnv();
  }

  private loadFromEnv() {
    const envMappings: Record<string, string> = {
      'openai': 'OPENAI_API_KEY',
      'anthropic': 'ANTHROPIC_API_KEY',
      'google-gemini': 'GEMINI_API_KEY',
      'groq': 'GROQ_API_KEY',
      'deepseek': 'DEEPSEEK_API_KEY',
      'mistral': 'MISTRAL_API_KEY',
      'fireworks': 'FIREWORKS_API_KEY',
      'together': 'TOGETHER_API_KEY',
      'cohere': 'COHERE_API_KEY',
      'openrouter': 'OPENROUTER_API_KEY',
      'perplexity': 'PERPLEXITY_API_KEY',
      'cerebras': 'CEREBRAS_API_KEY',
    };

    for (const [providerId, envKey] of Object.entries(envMappings)) {
      const key = process.env[envKey];
      if (key) {
        this.connections.set(providerId, { apiKey: key, status: 'ready' });
        logger.info({ provider: providerId }, 'AI provider loaded from env');
      }
    }
  }

  // ─── Connection Management ──────────────────────────────────────────────

  async connect(providerId: string, apiKey: string, endpoint?: string): Promise<{ success: boolean; latency?: number; error?: string }> {
    const provider = PROVIDER_CATALOG.find(p => p.id === providerId);
    if (!provider) return { success: false, error: 'Provider not found' };

    // Test connection
    const testResult = await this.testConnection(providerId, apiKey, endpoint || provider.baseUrl);

    if (testResult.success) {
      this.connections.set(providerId, {
        apiKey,
        endpoint,
        status: 'connected',
        lastTested: new Date().toISOString(),
        latency: testResult.latency,
      });

      // Persist to Redis
      if (isRedisConnected()) {
        await redis.set(`ai:provider:${providerId}`, JSON.stringify({
          apiKey: this.maskKey(apiKey),
          endpoint,
          status: 'connected',
          lastTested: new Date().toISOString(),
          latency: testResult.latency,
        }), 'EX', 86400 * 30);
      }
    }

    return testResult;
  }

  async disconnect(providerId: string) {
    this.connections.delete(providerId);
    if (isRedisConnected()) {
      await redis.del(`ai:provider:${providerId}`);
    }
  }

  async testConnection(providerId: string, apiKey: string, baseUrl: string): Promise<{ success: boolean; latency?: number; error?: string; model?: string }> {
    const provider = PROVIDER_CATALOG.find(p => p.id === providerId);
    if (!provider) return { success: false, error: 'Provider not found' };

    const start = Date.now();

    try {
      // Use appropriate test method based on provider type
      if (provider.authType === 'bearer' && baseUrl.includes('openai.com') || 
          providerId === 'groq' || providerId === 'deepseek' || providerId === 'fireworks' ||
          providerId === 'together' || providerId === 'openrouter' || providerId === 'mistral' ||
          providerId === 'cerebras' || providerId === 'sambanova' || providerId === 'nvidia-nim') {
        // OpenAI-compatible: list models
        const res = await fetch(`${baseUrl}/models`, {
          headers: { 'Authorization': `Bearer ${apiKey}` },
          signal: AbortSignal.timeout(10000),
        });
        const latency = Date.now() - start;
        if (res.ok) return { success: true, latency };
        const err = await res.text();
        return { success: false, error: `HTTP ${res.status}: ${err.slice(0, 100)}`, latency };
      }

      if (providerId === 'anthropic' || providerId === 'claude-code') {
        // Anthropic: simple message
        const res = await fetch(`${baseUrl}/messages`, {
          method: 'POST',
          headers: {
            'x-api-key': apiKey,
            'anthropic-version': '2023-06-01',
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ model: 'claude-3-5-haiku-20241022', max_tokens: 5, messages: [{ role: 'user', content: 'hi' }] }),
          signal: AbortSignal.timeout(15000),
        });
        const latency = Date.now() - start;
        if (res.ok) return { success: true, latency };
        if (res.status === 401) return { success: false, error: 'Invalid API key', latency };
        return { success: true, latency }; // 4xx might be rate limit but key is valid
      }

      if (providerId === 'google-gemini' || providerId === 'gemini-cli') {
        const res = await fetch(`${baseUrl}/models?key=${apiKey}`, {
          signal: AbortSignal.timeout(10000),
        });
        const latency = Date.now() - start;
        if (res.ok) return { success: true, latency };
        return { success: false, error: `HTTP ${res.status}`, latency };
      }

      if (providerId === 'ollama') {
        const res = await fetch(`${baseUrl.replace('/v1', '')}/api/tags`, {
          signal: AbortSignal.timeout(5000),
        });
        const latency = Date.now() - start;
        if (res.ok) return { success: true, latency };
        return { success: false, error: 'Ollama not running', latency };
      }

      // Generic: try /models endpoint
      const res = await fetch(`${baseUrl}/models`, {
        headers: { 'Authorization': `Bearer ${apiKey}` },
        signal: AbortSignal.timeout(10000),
      });
      const latency = Date.now() - start;
      return { success: res.ok, latency, error: res.ok ? undefined : `HTTP ${res.status}` };

    } catch (err: any) {
      const latency = Date.now() - start;
      if (err.name === 'TimeoutError' || err.name === 'AbortError') {
        return { success: false, error: 'Connection timeout', latency };
      }
      return { success: false, error: err.message || 'Connection failed', latency };
    }
  }

  // ─── Chat Completion ────────────────────────────────────────────────────

  async complete(request: AICompletionRequest): Promise<AICompletionResponse> {
    const connection = this.connections.get(request.provider);
    if (!connection) throw new Error(`Provider '${request.provider}' not connected`);

    const provider = PROVIDER_CATALOG.find(p => p.id === request.provider);
    if (!provider) throw new Error(`Provider '${request.provider}' not found`);

    const baseUrl = connection.endpoint || provider.baseUrl;
    const model = request.model || provider.models[0];
    const start = Date.now();

    try {
      let response: AICompletionResponse;

      if (request.provider === 'anthropic' || request.provider === 'claude-code') {
        response = await this.callAnthropic(connection.apiKey, baseUrl, model, request, start);
      } else if (request.provider === 'google-gemini' || request.provider === 'gemini-cli') {
        response = await this.callGemini(connection.apiKey, baseUrl, model, request, start);
      } else {
        // OpenAI-compatible (most providers)
        response = await this.callOpenAICompatible(connection.apiKey, baseUrl, model, request, start);
      }

      // Track usage
      if (isRedisConnected()) {
        await redis.hincrby('ai:usage:tokens', request.provider, response.usage.totalTokens);
        await redis.hincrby('ai:usage:requests', request.provider, 1);
      }

      return response;
    } catch (err: any) {
      logger.error({ provider: request.provider, err: err.message }, 'AI completion failed');
      throw err;
    }
  }

  private async callOpenAICompatible(apiKey: string, baseUrl: string, model: string, request: AICompletionRequest, start: number): Promise<AICompletionResponse> {
    const res = await fetch(`${baseUrl}/chat/completions`, {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model,
        messages: request.messages,
        temperature: request.temperature ?? 0.7,
        max_tokens: request.maxTokens ?? 2048,
      }),
      signal: AbortSignal.timeout(60000),
    });

    if (!res.ok) {
      const err = await res.text();
      throw new Error(`Provider error (${res.status}): ${err.slice(0, 200)}`);
    }

    const data = await res.json();
    return {
      provider: request.provider,
      model: data.model || model,
      content: data.choices?.[0]?.message?.content || '',
      usage: {
        promptTokens: data.usage?.prompt_tokens || 0,
        completionTokens: data.usage?.completion_tokens || 0,
        totalTokens: data.usage?.total_tokens || 0,
      },
      latency: Date.now() - start,
    };
  }

  private async callAnthropic(apiKey: string, baseUrl: string, model: string, request: AICompletionRequest, start: number): Promise<AICompletionResponse> {
    const systemMsg = request.messages.find(m => m.role === 'system');
    const messages = request.messages.filter(m => m.role !== 'system');

    const res = await fetch(`${baseUrl}/messages`, {
      method: 'POST',
      headers: {
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model,
        max_tokens: request.maxTokens ?? 2048,
        system: systemMsg?.content,
        messages,
        temperature: request.temperature ?? 0.7,
      }),
      signal: AbortSignal.timeout(60000),
    });

    if (!res.ok) {
      const err = await res.text();
      throw new Error(`Anthropic error (${res.status}): ${err.slice(0, 200)}`);
    }

    const data = await res.json();
    return {
      provider: request.provider,
      model: data.model || model,
      content: data.content?.[0]?.text || '',
      usage: {
        promptTokens: data.usage?.input_tokens || 0,
        completionTokens: data.usage?.output_tokens || 0,
        totalTokens: (data.usage?.input_tokens || 0) + (data.usage?.output_tokens || 0),
      },
      latency: Date.now() - start,
    };
  }

  private async callGemini(apiKey: string, baseUrl: string, model: string, request: AICompletionRequest, start: number): Promise<AICompletionResponse> {
    const contents = request.messages.filter(m => m.role !== 'system').map(m => ({
      role: m.role === 'assistant' ? 'model' : 'user',
      parts: [{ text: m.content }],
    }));

    const res = await fetch(`${baseUrl}/models/${model}:generateContent?key=${apiKey}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents,
        generationConfig: { temperature: request.temperature ?? 0.7, maxOutputTokens: request.maxTokens ?? 2048 },
      }),
      signal: AbortSignal.timeout(60000),
    });

    if (!res.ok) {
      const err = await res.text();
      throw new Error(`Gemini error (${res.status}): ${err.slice(0, 200)}`);
    }

    const data = await res.json();
    return {
      provider: request.provider,
      model,
      content: data.candidates?.[0]?.content?.parts?.[0]?.text || '',
      usage: {
        promptTokens: data.usageMetadata?.promptTokenCount || 0,
        completionTokens: data.usageMetadata?.candidatesTokenCount || 0,
        totalTokens: data.usageMetadata?.totalTokenCount || 0,
      },
      latency: Date.now() - start,
    };
  }

  // ─── Provider Listing ───────────────────────────────────────────────────

  getProviders(): (typeof PROVIDER_CATALOG[0] & { status: string; connectionCount: number; lastTested?: string; latency?: number })[] {
    return PROVIDER_CATALOG.map(p => {
      const conn = this.connections.get(p.id);
      return {
        ...p,
        status: conn?.status || 'disconnected',
        connectionCount: conn ? 1 : 0,
        lastTested: conn?.lastTested,
        latency: conn?.latency,
      };
    });
  }

  getConnectedProviders() {
    return this.getProviders().filter(p => p.status === 'connected' || p.status === 'ready');
  }

  isConnected(providerId: string): boolean {
    return this.connections.has(providerId);
  }

  async getUsageStats(): Promise<Record<string, { tokens: number; requests: number }>> {
    if (!isRedisConnected()) return {};
    const tokens = await redis.hgetall('ai:usage:tokens');
    const requests = await redis.hgetall('ai:usage:requests');
    const stats: Record<string, { tokens: number; requests: number }> = {};
    for (const [provider, count] of Object.entries(tokens)) {
      stats[provider] = { tokens: parseInt(count), requests: parseInt(requests[provider] || '0') };
    }
    return stats;
  }

  private maskKey(key: string): string {
    if (key.length <= 8) return '***';
    return key.slice(0, 4) + '...' + key.slice(-4);
  }
}

export const aiProviders = new AIProviderManager();

/**
 * AI Routes — Multi-Provider AI Gateway
 * Manages connections to 30+ AI providers and routes completions.
 */

import { FastifyInstance } from 'fastify';
import { aiProviders, PROVIDER_CATALOG } from '../lib/ai-providers';
import { db } from '../db/connection';
import { devices, alerts, telemetry } from '../db/schema';
import { eq, count, avg, gte, and, desc } from 'drizzle-orm';
import { validate } from '../lib/validation';
import { operatorUp, adminOnly } from '../lib/rbac';
import { z } from 'zod';

// Schemas
const connectSchema = z.object({
  apiKey: z.string().min(1),
  endpoint: z.string().url().optional(),
});

const completionSchema = z.object({
  provider: z.string().min(1),
  model: z.string().optional(),
  messages: z.array(z.object({
    role: z.enum(['system', 'user', 'assistant']),
    content: z.string().min(1),
  })).min(1),
  temperature: z.number().min(0).max(2).optional(),
  maxTokens: z.number().min(1).max(128000).optional(),
});

const querySchema = z.object({
  query: z.string().min(1).max(5000),
  provider: z.string().optional(),
  model: z.string().optional(),
});

export async function aiRoutes(app: FastifyInstance) {

  // ─── Provider Management ────────────────────────────────────────────────

  // List all providers
  app.get('/providers', { preHandler: [app.authenticate] }, async () => {
    const providers = aiProviders.getProviders();
    const byCategory = {
      oauth: providers.filter(p => p.category === 'oauth'),
      free_tier: providers.filter(p => p.category === 'free_tier'),
      api_key: providers.filter(p => p.category === 'api_key'),
    };

    return {
      success: true,
      data: byCategory,
      total: providers.length,
      connected: providers.filter(p => p.status === 'connected' || p.status === 'ready').length,
    };
  });

  // Connect to a provider
  app.post('/providers/:id/connect', { preHandler: [app.authenticate, adminOnly, validate(connectSchema)] }, async (request, reply) => {
    const { id } = request.params as { id: string };
    const { apiKey, endpoint } = request.body as { apiKey: string; endpoint?: string };

    const result = await aiProviders.connect(id, apiKey, endpoint);

    if (result.success) {
      return { success: true, message: `Connected to ${id}`, latency: result.latency };
    } else {
      return reply.status(400).send({ success: false, error: result.error });
    }
  });

  // Disconnect provider
  app.post('/providers/:id/disconnect', { preHandler: [app.authenticate, adminOnly] }, async (request) => {
    const { id } = request.params as { id: string };
    await aiProviders.disconnect(id);
    return { success: true, message: `Disconnected from ${id}` };
  });

  // Test provider connection
  app.post('/providers/:id/test', { preHandler: [app.authenticate, validate(connectSchema)] }, async (request) => {
    const { id } = request.params as { id: string };
    const { apiKey, endpoint } = request.body as { apiKey: string; endpoint?: string };

    const provider = PROVIDER_CATALOG.find(p => p.id === id);
    if (!provider) return { success: false, error: 'Provider not found' };

    const result = await aiProviders.testConnection(id, apiKey, endpoint || provider.baseUrl);
    return { success: result.success, latency: result.latency, error: result.error };
  });

  // Get usage stats
  app.get('/providers/usage', { preHandler: [app.authenticate] }, async () => {
    const usage = await aiProviders.getUsageStats();
    return { success: true, data: usage };
  });

  // ─── AI Completion (Multi-Provider) ─────────────────────────────────────

  // Generic completion — route to any provider
  app.post('/complete', { preHandler: [app.authenticate, operatorUp, validate(completionSchema)] }, async (request, reply) => {
    const body = request.body as z.infer<typeof completionSchema>;

    try {
      const result = await aiProviders.complete(body);
      return { success: true, data: result };
    } catch (err: any) {
      return reply.status(502).send({ success: false, error: err.message });
    }
  });

  // ─── AI Query (Smart — uses connected provider + fleet context) ─────────

  app.post('/query', { preHandler: [app.authenticate, validate(querySchema)] }, async (request, reply) => {
    const { query, provider: preferredProvider, model } = request.body as { query: string; provider?: string; model?: string };
    const { tenantId } = request.user;

    // Get fleet context
    const [deviceCount] = await db.select({ count: count() }).from(devices).where(eq(devices.tenantId, tenantId));
    const [alertCount] = await db.select({ count: count() }).from(alerts).where(eq(alerts.tenantId, tenantId));

    const fiveMinAgo = new Date(Date.now() - 5 * 60 * 1000);
    const [telemetryAvg] = await db.select({
      avgCpu: avg(telemetry.cpuUsage),
      avgMemory: avg(telemetry.memoryUsage),
    }).from(telemetry).where(and(eq(telemetry.tenantId, tenantId), gte(telemetry.timestamp, fiveMinAgo)));

    const systemPrompt = `You are AUDIRA AI Assistant — an intelligent device fleet management assistant.
Current fleet status:
- Total devices: ${deviceCount.count}
- Active alerts: ${alertCount.count}
- Avg CPU: ${parseFloat(String(telemetryAvg?.avgCpu || 0)).toFixed(1)}%
- Avg Memory: ${parseFloat(String(telemetryAvg?.avgMemory || 0)).toFixed(1)}%

Help the user manage their device fleet. Be concise and actionable.`;

    // Try to use a connected provider
    const connectedProviders = aiProviders.getConnectedProviders();
    const targetProvider = preferredProvider || connectedProviders[0]?.id;

    if (targetProvider && aiProviders.isConnected(targetProvider)) {
      try {
        const result = await aiProviders.complete({
          provider: targetProvider,
          model,
          messages: [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: query },
          ],
          temperature: 0.7,
          maxTokens: 1024,
        });

        return {
          success: true,
          response: result.content,
          provider: result.provider,
          model: result.model,
          usage: result.usage,
          latency: result.latency,
          suggestions: generateSuggestions(query),
        };
      } catch (err: any) {
        // Fallback to rule-based if provider fails
        return {
          success: true,
          response: getRuleBasedResponse(query, deviceCount.count, alertCount.count),
          provider: 'rule-based',
          model: 'built-in',
          usage: { promptTokens: 0, completionTokens: 0, totalTokens: 0 },
          latency: 0,
          suggestions: generateSuggestions(query),
          fallback: true,
          fallbackReason: err.message,
        };
      }
    }

    // No provider connected — use rule-based
    return {
      success: true,
      response: getRuleBasedResponse(query, deviceCount.count, alertCount.count),
      provider: 'rule-based',
      model: 'built-in',
      usage: { promptTokens: 0, completionTokens: 0, totalTokens: 0 },
      latency: 0,
      suggestions: generateSuggestions(query),
      hint: connectedProviders.length === 0 ? 'Connect an AI provider for smarter responses. Go to Settings → AI Providers.' : undefined,
    };
  });

  // ─── Legacy endpoints (backward compatible) ─────────────────────────────

  app.get('/recommendations', { preHandler: [app.authenticate] }, async () => {
    return {
      success: true,
      recommendations: [
        { id: '1', priority: 'high', category: 'security', title: 'Update agent on 3 devices', description: 'Devices running agent < 2.1.0 should be updated', affectedDevices: 3 },
        { id: '2', priority: 'medium', category: 'performance', title: 'Disk cleanup on Ubuntu Server', description: 'Disk usage at 87%', affectedDevices: 1 },
        { id: '3', priority: 'low', category: 'maintenance', title: 'Firmware update for IoT Gateway', description: 'New firmware v1.6.0 available', affectedDevices: 1 },
      ],
    };
  });

  app.get('/anomalies', { preHandler: [app.authenticate] }, async () => {
    return {
      success: true,
      anomalies: [
        { id: '1', deviceName: 'Docker Agent Node-01', metric: 'cpu_usage', expected: 45, actual: 92, severity: 'high', detectedAt: new Date(Date.now() - 900000).toISOString() },
      ],
    };
  });

  app.get('/predictions', { preHandler: [app.authenticate] }, async () => {
    return {
      success: true,
      predictions: [
        { id: '1', type: 'disk_full', device: 'Ubuntu Server 22.04', probability: 0.85, estimatedTime: '3 days', recommendation: 'Schedule disk cleanup' },
      ],
    };
  });
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

function getRuleBasedResponse(query: string, deviceCount: any, alertCount: any): string {
  const q = query.toLowerCase();
  if (q.includes('status') || q.includes('overview')) {
    return `Your fleet has ${deviceCount} devices with ${alertCount} alerts. System is operating normally.`;
  }
  if (q.includes('alert') || q.includes('problem')) {
    return `There are ${alertCount} alerts in the system. Check the Alerts page for details.`;
  }
  if (q.includes('recommend') || q.includes('optimize')) {
    return `Recommendations: 1) Update agents on older devices, 2) Monitor disk usage on servers approaching 90%, 3) Review and resolve active alerts.`;
  }
  return `I can help you manage your fleet of ${deviceCount} devices. Connect an AI provider (OpenAI, Anthropic, Groq, etc.) for more intelligent responses.`;
}

function generateSuggestions(query: string): string[] {
  const q = query.toLowerCase();
  if (q.includes('alert')) return ['Show critical alerts', 'Acknowledge all warnings', 'Alert trends this week'];
  if (q.includes('device')) return ['Show offline devices', 'Device health report', 'Update all agents'];
  if (q.includes('performance')) return ['CPU usage trends', 'Memory optimization', 'Network bottlenecks'];
  return ['Fleet overview', 'Active alerts', 'Performance report', 'Recommendations'];
}

import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { api } from '../lib/api';
import { notify } from '../lib/toast';
import { PageLayout } from '../components/ui/PageLayout';
import { Modal } from '../components/ui/Modal';

interface Provider {
  id: string;
  name: string;
  category: string;
  icon: string;
  models: string[];
  features: string[];
  status: string;
  connectionCount: number;
  lastTested?: string;
  latency?: number;
}

export function AIInsights() {
  const [connectTarget, setConnectTarget] = useState<Provider | null>(null);
  const [apiKey, setApiKey] = useState('');
  const [endpoint, setEndpoint] = useState('');
  const [testingId, setTestingId] = useState<string | null>(null);

  const queryClient = useQueryClient();

  const { data: providersData, isLoading } = useQuery({
    queryKey: ['ai', 'providers'],
    queryFn: async () => {
      const res = await fetch('/api/v1/ai/providers', {
        headers: { 'Authorization': `Bearer ${localStorage.getItem('auth_token')}` },
      });
      return res.json();
    },
  });

  const { data: usageData } = useQuery({
    queryKey: ['ai', 'usage'],
    queryFn: async () => {
      const res = await fetch('/api/v1/ai/providers/usage', {
        headers: { 'Authorization': `Bearer ${localStorage.getItem('auth_token')}` },
      });
      return res.json();
    },
  });

  const connectMutation = useMutation({
    mutationFn: async ({ id, apiKey, endpoint }: { id: string; apiKey: string; endpoint?: string }) => {
      const res = await fetch(`/api/v1/ai/providers/${id}/connect`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${localStorage.getItem('auth_token')}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ apiKey, endpoint: endpoint || undefined }),
      });
      return res.json();
    },
    onSuccess: (data) => {
      if (data.success) {
        queryClient.invalidateQueries({ queryKey: ['ai', 'providers'] });
        notify.success(`Connected! Latency: ${data.latency}ms`);
        setConnectTarget(null);
        setApiKey('');
        setEndpoint('');
      } else {
        notify.error(data.error || 'Connection failed');
      }
    },
  });

  const disconnectMutation = useMutation({
    mutationFn: async (id: string) => {
      await fetch(`/api/v1/ai/providers/${id}/disconnect`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${localStorage.getItem('auth_token')}` },
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['ai', 'providers'] });
      notify.success('Disconnected');
    },
  });

  const testMutation = useMutation({
    mutationFn: async ({ id, apiKey }: { id: string; apiKey: string }) => {
      setTestingId(id);
      const res = await fetch(`/api/v1/ai/providers/${id}/test`, {
        method: 'POST',
        headers: { 'Authorization': `Bearer ${localStorage.getItem('auth_token')}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ apiKey }),
      });
      return res.json();
    },
    onSettled: () => setTestingId(null),
    onSuccess: (data) => {
      if (data.success) notify.success(`Connection OK! Latency: ${data.latency}ms`);
      else notify.error(data.error || 'Test failed');
    },
  });

  const providers = providersData?.data || { oauth: [], free_tier: [], api_key: [] };
  const connectedCount = providersData?.connected || 0;
  const usage = usageData?.data || {};

  const stats = [
    { label: 'Total Providers', value: String(providersData?.total || 0) },
    { label: 'Connected', value: String(connectedCount), color: 'text-emerald-400' },
    { label: 'Total Tokens Used', value: formatNumber(Object.values(usage).reduce((sum: number, u: any) => sum + (u?.tokens || 0), 0)) },
    { label: 'Total Requests', value: formatNumber(Object.values(usage).reduce((sum: number, u: any) => sum + (u?.requests || 0), 0)) },
  ];

  const renderProviderCard = (provider: Provider) => {
    const isConnected = provider.status === 'connected' || provider.status === 'ready';
    const providerUsage = usage[provider.id];

    return (
      <div
        key={provider.id}
        className={`rounded-lg border p-3 transition-all ${
          isConnected ? 'border-emerald-500/30 bg-emerald-500/5' : 'border-[#1e293b] bg-[#111827]/60 hover:border-[#334155]'
        }`}
      >
        <div className="flex items-center justify-between mb-2">
          <div className="flex items-center gap-2">
            <span className="text-lg">{provider.icon}</span>
            <div>
              <p className="text-[10px] font-medium text-white">{provider.name}</p>
              <p className="text-[8px] text-slate-500">{provider.models.length} models</p>
            </div>
          </div>
          {isConnected ? (
            <span className="text-[8px] px-1.5 py-0.5 rounded bg-emerald-500/10 text-emerald-400">
              {provider.latency ? `${provider.latency}ms` : 'Connected'}
            </span>
          ) : (
            <span className="text-[8px] text-slate-500">No connections</span>
          )}
        </div>

        {/* Features */}
        <div className="flex flex-wrap gap-1 mb-2">
          {provider.features.slice(0, 4).map(f => (
            <span key={f} className="text-[7px] px-1 py-0.5 rounded bg-[#1e293b] text-slate-400">{f}</span>
          ))}
        </div>

        {/* Usage */}
        {providerUsage && (
          <div className="text-[8px] text-slate-500 mb-2">
            {providerUsage.requests} requests • {formatNumber(providerUsage.tokens)} tokens
          </div>
        )}

        {/* Actions */}
        <div className="flex items-center gap-1.5">
          {isConnected ? (
            <>
              <button
                onClick={() => disconnectMutation.mutate(provider.id)}
                className="flex-1 py-1 rounded text-[8px] bg-red-500/10 border border-red-500/20 text-red-400 hover:bg-red-500/20"
              >
                Disconnect
              </button>
            </>
          ) : (
            <button
              onClick={() => setConnectTarget(provider)}
              className="flex-1 py-1 rounded text-[8px] bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20"
            >
              Connect
            </button>
          )}
        </div>
      </div>
    );
  };

  const renderSection = (title: string, items: Provider[]) => (
    <div className="mb-6">
      <div className="flex items-center justify-between mb-3">
        <h3 className="text-[11px] font-semibold text-white">{title}</h3>
        <span className="text-[9px] text-slate-500">{items.filter(p => p.status === 'connected' || p.status === 'ready').length}/{items.length} connected</span>
      </div>
      <div className="grid grid-cols-4 gap-3">
        {items.map(renderProviderCard)}
      </div>
    </div>
  );

  return (
    <PageLayout
      title="AI Providers"
      description="Connect and manage AI providers for intelligent fleet management."
      stats={stats}
    >
      <div className="flex-1 overflow-y-auto p-4">
        {isLoading ? (
          <div className="flex items-center justify-center h-40">
            <div className="w-8 h-8 border-2 border-cyan-400/30 border-t-cyan-400 rounded-full animate-spin" />
          </div>
        ) : (
          <>
            {providers.oauth?.length > 0 && renderSection('OAuth Providers', providers.oauth)}
            {providers.free_tier?.length > 0 && renderSection('Free Tier Providers', providers.free_tier)}
            {providers.api_key?.length > 0 && renderSection('API Key Providers', providers.api_key)}
          </>
        )}
      </div>

      {/* Connect Modal */}
      <Modal open={!!connectTarget} onClose={() => { setConnectTarget(null); setApiKey(''); setEndpoint(''); }} title={`Connect to ${connectTarget?.name}`}>
        <div className="p-4 space-y-4">
          <div className="flex items-center gap-3 p-3 rounded-lg bg-[#0a0e1a] border border-[#1e293b]">
            <span className="text-2xl">{connectTarget?.icon}</span>
            <div>
              <p className="text-[11px] font-medium text-white">{connectTarget?.name}</p>
              <p className="text-[9px] text-slate-500">{connectTarget?.models.join(', ')}</p>
            </div>
          </div>

          <div>
            <label className="text-[9px] text-slate-400 block mb-1">API Key *</label>
            <input
              type="password"
              value={apiKey}
              onChange={(e) => setApiKey(e.target.value)}
              placeholder="sk-... or your API key"
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600 font-mono"
            />
          </div>

          <div>
            <label className="text-[9px] text-slate-400 block mb-1">Custom Endpoint (optional)</label>
            <input
              type="text"
              value={endpoint}
              onChange={(e) => setEndpoint(e.target.value)}
              placeholder={connectTarget?.baseUrl || 'https://...'}
              className="w-full h-8 px-3 rounded border border-[#1e293b] bg-[#111827] text-[10px] text-white outline-none focus:border-cyan-500/30 placeholder:text-slate-600 font-mono"
            />
          </div>

          <div className="flex gap-2">
            <button
              onClick={() => connectTarget && testMutation.mutate({ id: connectTarget.id, apiKey })}
              disabled={!apiKey || testMutation.isPending}
              className="flex-1 py-2 rounded-md text-[10px] font-medium bg-[#1e293b] border border-[#334155] text-slate-300 hover:text-white disabled:opacity-50"
            >
              {testMutation.isPending ? '⏳ Testing...' : '🔍 Test Connection'}
            </button>
            <button
              onClick={() => connectTarget && connectMutation.mutate({ id: connectTarget.id, apiKey, endpoint })}
              disabled={!apiKey || connectMutation.isPending}
              className="flex-1 py-2 rounded-md text-[10px] font-medium bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 hover:bg-cyan-500/20 disabled:opacity-50"
            >
              {connectMutation.isPending ? '⏳ Connecting...' : '⚡ Connect'}
            </button>
          </div>
        </div>
      </Modal>
    </PageLayout>
  );
}

function formatNumber(n: number): string {
  if (n >= 1000000) return `${(n / 1000000).toFixed(1)}M`;
  if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
  return String(n || 0);
}

